window.HADITH_CACHE["bukhari_13"] = {"6501":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ أَحَدٍ أَغْيَرُ مِنْ اللَّهِ مِنْ أَجْلِ ذَلِكَ حَرَّمَ الْفَوَاحِشَ وَمَا أَحَدٌ أَحَبَّ إِلَيْهِ الْمَدْحُ مِنْ اللَّهِ","id":"Telah menceritakan kepada kami ['Umar bin Hafs bin Ghiyats] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tak ada seorangpun yang lebih cemburu daripada Allah, yang karena sifat cemburu-Nya Allah mengharamkan segala bentuk kejahatan, dan tak seorang pun yang lebih senang dipuji daripada Allah.\""},"6502":{"ar":"حَدَّثَنَا عَبْدَانُ عَنْ أَبِي حَمْزَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَمَّا خَلَقَ اللَّهُ الْخَلْقَ كَتَبَ فِي كِتَابِهِ وَهُوَ يَكْتُبُ عَلَى نَفْسِهِ وَهُوَ وَضْعٌ عِنْدَهُ عَلَى الْعَرْشِ إِنَّ رَحْمَتِي تَغْلِبُ غَضَبِي","id":"Telah menceritakan kepada kami ['Abdan] dari [Abu hamzah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Dikala Allah mencipta manusia, Dia menulis dalam kitab-Nya yang Dia sendirilah yang menulis terhadap diri-Nya, dan itu diletakkan-Nya di sisiNya di atas 'arsy, 'Sesungguhnya rahmat-Ku lebih mendominasi kemurkaan-Ku'.\""},"6503":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ سَمِعْتُ أَبَا صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ تَعَالَى أَنَا عِنْدَ ظَنِّ عَبْدِي بِي وَأَنَا مَعَهُ إِذَا ذَكَرَنِي فَإِنْ ذَكَرَنِي فِي نَفْسِهِ ذَكَرْتُهُ فِي نَفْسِي وَإِنْ ذَكَرَنِي فِي مَلَإٍ ذَكَرْتُهُ فِي مَلَإٍ خَيْرٍ مِنْهُمْ وَإِنْ تَقَرَّبَ إِلَيَّ بِشِبْرٍ تَقَرَّبْتُ إِلَيْهِ ذِرَاعًا وَإِنْ تَقَرَّبَ إِلَيَّ ذِرَاعًا تَقَرَّبْتُ إِلَيْهِ بَاعًا وَإِنْ أَتَانِي يَمْشِي أَتَيْتُهُ هَرْوَلَةً","id":"Telah menceritakan kepada kami ['Amru bin Hafs] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] aku mendengar [Abu Shalih] dari [Abu Hurairah] radliyallahu'anhu berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Aku berada dalam prasangka hamba-Ku, dan Aku selalu bersamanya jika ia mengingat-Ku, jika ia mengingat-Ku dalam dirinya, maka Aku mengingatnya dalam diri-Ku, dan jika ia mengingat-Ku dalam perkumpulan, maka Aku mengingatnya dalam perkumpulan yang lebih baik daripada mereka, jika ia mendekatkan diri kepada-Ku sejengkal, maka Aku mendekatkan diri kepadanya sehasta, dan jika ia mendekatkan diri kepada-Ku sehasta, Aku mendekatkan diri kepadanya sedepa, jika ia mendatangi-Ku dalam keadaan berjalan, maka Aku mendatanginya dalam keadaan berlari.\""},"6504":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرٍو عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ قُلْ هُوَ الْقَادِرُ عَلَى أَنْ يَبْعَثَ عَلَيْكُمْ عَذَابًا مِنْ فَوْقِكُمْ }قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعُوذُ بِوَجْهِكَ فَقَالَ{ أَوْ مِنْ تَحْتِ أَرْجُلِكُمْ }فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعُوذُ بِوَجْهِكَ قَالَ{ أَوْ يَلْبِسَكُمْ شِيَعًا }فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا أَيْسَرُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Hammad bin Zaid] dari ['Amru] dari [Jabir bin Abdullah] berkata, \"Tatkala ayat berikut diturunkan: '(Katakanlah Hai Muhammad, Dia-lah yang Maha berkuasa mengirimkan siksaan untuk kalian dari atas kalian) ' (QS. Al An'am 65), Nabi shallallahu 'alaihi wasallam memanjatkan doa: 'Saya berlindung dengan wajah-Mu, ' lantas Allah berfirman: '(Atau dari bawah kakimu) ' (QS. Al An'am 65), maka nabi memanjatkan doa: 'Saya berlindung dengan wajah-Mu', dan Allah berfirman: '(Atau menjadikan kalian berkelompok-kelompok) ' (QS. Al An'am 65), maka Nabi berkomentar 'Ini lebih sepele.'"},"6505":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ قَالَذُكِرَ الدَّجَّالُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ اللَّهَ لَا يَخْفَى عَلَيْكُمْ إِنَّ اللَّهَ لَيْسَ بِأَعْوَرَ وَأَشَارَ بِيَدِهِ إِلَى عَيْنِهِ وَإِنَّ الْمَسِيحَ الدَّجَّالَ أَعْوَرُ الْعَيْنِ الْيُمْنَى كَأَنَّ عَيْنَهُ عِنَبَةٌ طَافِيَةٌ","id":"Telah menceritakan kepada kami [Musa bin Ismail] telah menceritakan kepada kami [Juwairiyah] dari [Nafi'] dari ['Abdullah] berkata, \"Dajjal disebut-sebut di sisi Nabi shallallahu 'alaihi wasallam, lantas beliau berkomentar\" 'Allah tidak samar bagi kalian, Allah tidak buta sebelah -sambil beliau mendemontrasikan dengan tangannya ke matanya- 'dan bahwasanya al masih addajjal buta sebelah kanan, seolah-olah matanya anggur yang menjorok.\""},"6506":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ أَخْبَرَنَا قَتَادَةُ قَالَ سَمِعْتُ أَنَسًا رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا بَعَثَ اللَّهُ مِنْ نَبِيٍّ إِلَّا أَنْذَرَ قَوْمَهُ الْأَعْوَرَ الْكَذَّابَ إِنَّهُ أَعْوَرُ وَإِنَّ رَبَّكُمْ لَيْسَ بِأَعْوَرَ مَكْتُوبٌ بَيْنَ عَيْنَيْهِ كَافِرٌ","id":"Telah menceritakan kepada kami [Hafs bin Umar] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepada kami [Qatadah] berkata, aku mendengar [Anas] radliyallahu'anhu dari Nabi shallallahu 'alaihi wasallam: \"Tidaklah Allah mengutus seorang nabi pun melainkan telah mengingatkan kaumnya terhadap si buta sebelah dan si pendusta, ingatlah bahwa dajjal adalah buta sebelah, sedang Rabb kalian tidak buta sebelah, tertulis diantara kedua matanya KAFIR.\""},"6507":{"ar":"حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا عَفَّانُ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا مُوسَى هُوَ ابْنُ عُقْبَةَ حَدَّثَنِي مُحَمَّدُ بْنُ يَحْيَى بْنِ حَبَّانَ عَنْ ابْنِ مُحَيْرِيزٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّفِي غَزْوَةِ بَنِي الْمُصْطَلِقِ أَنَّهُمْ أَصَابُوا سَبَايَا فَأَرَادُوا أَنْ يَسْتَمْتِعُوا بِهِنَّ وَلَا يَحْمِلْنَ فَسَأَلُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْعَزْلِ فَقَالَ مَا عَلَيْكُمْ أَنْ لَا تَفْعَلُوا فَإِنَّ اللَّهَ قَدْ كَتَبَ مَنْ هُوَ خَالِقٌ إِلَى يَوْمِ الْقِيَامَةِوَقَالَ مُجَاهِدٌ عَنْ قَزَعَةَ سَمِعْتُ أَبَا سَعِيدٍ فَقَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَتْ نَفْسٌ مَخْلُوقَةٌ إِلَّا اللَّهُ خَالِقُهَا","id":"Telah menceritakan kepada kami [Ishaq] telah menceritakan kepada kami [Affan] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Musa] -yaitu Ibn Uqbah- telah menceritakan kepadaku [Muhammad bin Yahya bin Hibban] dari [Ibn Muhairiz] dari [Abu Sa'id Al Khudzri] saat perang bani Musthaliq, bahwa para sahabat mendapatkan para tawanan wanita, dan mereka ingin menikmatinya (jimak) namun tidak menginginkan para tawanan wanita itu hamil. Maka mereka bertanya kepada nabi tentang 'azl (mengeluarkan sperma di luar kenaluan wanita), maka Nabi bertanya: 'Bukan sebaiknyakah kalian tidak melakukannya, sebab Allah telah menetapkan siapa saja yang hidup hingga hari kiamat tiba? ' Sedang [Mujahid] berkata dari [Qaza'ah] aku mendengar [Abu Sa'id] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: 'Tidaklah manusia yang dicipta melainkan Allah lah yang menciptanya.\""},"6508":{"ar":"حَدَّثَنِي مُعَاذُ بْنُ فَضَالَةَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَجْمَعُ اللَّهُ الْمُؤْمِنِينَ يَوْمَ الْقِيَامَةِ كَذَلِكَ فَيَقُولُونَ لَوْ اسْتَشْفَعْنَا إِلَى رَبِّنَا حَتَّى يُرِيحَنَا مِنْ مَكَانِنَا هَذَا فَيَأْتُونَ آدَمَ فَيَقُولُونَ يَا آدَمُ أَمَا تَرَى النَّاسَ خَلَقَكَ اللَّهُ بِيَدِهِ وَأَسْجَدَ لَكَ مَلَائِكَتَهُ وَعَلَّمَكَ أَسْمَاءَ كُلِّ شَيْءٍ اشْفَعْ لَنَا إِلَى رَبِّنَا حَتَّى يُرِيحَنَا مِنْ مَكَانِنَا هَذَا فَيَقُولُ لَسْتُ هُنَاكَ وَيَذْكُرُ لَهُمْ خَطِيئَتَهُ الَّتِي أَصَابَهَا وَلَكِنْ ائْتُوا نُوحًا فَإِنَّهُ أَوَّلُ رَسُولٍ بَعَثَهُ اللَّهُ إِلَى أَهْلِ الْأَرْضِ فَيَأْتُونَ نُوحًا فَيَقُولُ لَسْتُ هُنَاكُمْ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ وَلَكِنْ ائْتُوا إِبْرَاهِيمَ خَلِيلَ الرَّحْمَنِ فَيَأْتُونَ إِبْرَاهِيمَ فَيَقُولُ لَسْتُ هُنَاكُمْ وَيَذْكُرُ لَهُمْ خَطَايَاهُ الَّتِي أَصَابَهَا وَلَكِنْ ائْتُوا مُوسَى عَبْدًا آتَاهُ اللَّهُ التَّوْرَاةَ وَكَلَّمَهُ تَكْلِيمًا فَيَأْتُونَ مُوسَى فَيَقُولُ لَسْتُ هُنَاكُمْ وَيَذْكُرُ لَهُمْ خَطِيئَتَهُ الَّتِي أَصَابَ وَلَكِنْ ائْتُوا عِيسَى عَبْدَ اللَّهِ وَرَسُولَهُ وَكَلِمَتَهُ وَرُوحَهُ فَيَأْتُونَ عِيسَى فَيَقُولُ لَسْتُ هُنَاكُمْ وَلَكِنْ ائْتُوا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبهِ وَمَا تَأَخَّرَ فَيَأْتُونِي فَأَنْطَلِقُ فَأَسْتَأْذِنُ عَلَى رَبِّي فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُ رَبِّي وَقَعْتُ لَهُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي ثُمَّ يُقَالُ لِي ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَسَلْ تُعْطَهْ وَاشْفَعْ تُشَفَّعْ فَأَحْمَدُ رَبِّي بِمَحَامِدَ عَلَّمَنِيهَا ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَرْجِعُ فَإِذَا رَأَيْتُ رَبِّي وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي ثُمَّ يُقَالُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَسَلْ تُعْطَهْ وَاشْفَعْ تُشَفَّعْ فَأَحْمَدُ رَبِّي بِمَحَامِدَ عَلَّمَنِيهَا رَبِّي ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَرْجِعُ فَإِذَا رَأَيْتُ رَبِّي وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي ثُمَّ يُقَالُ ارْفَعْ مُحَمَّدُ قُلْ يُسْمَعْ وَسَلْ تُعْطَهْ وَاشْفَعْ تُشَفَّعْ فَأَحْمَدُ رَبِّي بِمَحَامِدَ عَلَّمَنِيهَا ثُمَّ أَشْفَعْ فَيَحُدُّ لِي حَدًّا فَأُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَرْجِعُ فَأَقُولُ يَا رَبِّ مَا بَقِيَ فِي النَّارِ إِلَّا مَنْ حَبَسَهُ الْقُرْآنُ وَوَجَبَ عَلَيْهِ الْخُلُودُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْرُجُ مِنْ النَّارِ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَكَانَ فِي قَلْبِهِ مِنْ الْخَيْرِ مَا يَزِنُ شَعِيرَةً ثُمَّ يَخْرُجُ مِنْ النَّارِ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَكَانَ فِي قَلْبِهِ مِنْ الْخَيْرِ مَا يَزِنُ بُرَّةً ثُمَّ يَخْرُجُ مِنْ النَّارِ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَكَانَ فِي قَلْبِهِ مَا يَزِنُ مِنْ الْخَيْرِ ذَرَّةً","id":"Telah menceritakan kepadaku [Mu'adz bin Fadlalah] telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Anas] bahwa nabi shallallahu 'alaihi wasallam bersabda: \"Pada hari kiamat Allah mengumpulkan orang-orang mukmin, lalu mereka berkata, 'Tidak sebaiknyakah kita meminta syafaat kepada Rabb kita sehingga Dia bisa menjadikan kita merasa aman dari tempat kita sekarang ini? ' akhirnya mereka datangi Adam dan mereka sampaikan, 'Wahai Adam, bukankah engkau tahu bahwa Allah menciptamu dengan tangan-Nya dan Ia jadikan para malaikat tunduk sujud kepadamu, dan mengajarimu nama-nama segala sesuatu, maka mintailah syafaat Tuhan kami untuk kami sehingga Dia bisa memberi kenyamanan kami dari tempat kami sekarang ini! ' Adam hanya menjawab, 'Aku tidak berhak di sini.' Dan Adam menceritakan kesalahan yang pernah dilakukannya kepada mereka seraya berkata, 'Coba kalian datangi Nuh sebab ia adalah rasul pertama-tama yang Allah utus ke penduduk bumi.' Mereka pun mendatangi Nuh, namun Nuh menjawab, 'Saya tak berhak menolong kalian di sini', sambil Nuh menceritakan kesalahan yang pernah dilakukannya, 'namun coba datangilah Ibrahim yang ia adalah khalilurrahman (kekasih Allah Arrahman).' Lantas mereka pun mendatangi Ibrahim. Hanya Ibrahim menjawab, 'Maaf, di sini saya tak berhak menolong kalian.' Lantas Ibrahim menyebutkan kesalahan yang pernah dilakukannya seraya ia katakan, 'Coba datangilah Musa, seorang hamba yang Allah telah memberinya Taurat dan Dia mengajaknya bicara.' Mereka pun mendatangi Musa, hanya Musa berkata, 'Maaf, di sini saya tak berhak menolong kalian, ' lalu ia menceritakan kesalahan yang pernah dilakukannya, 'namun datangilah Isa, hamba Allah dan rasul-Nya, kalimah-Nya dan ruh-Nya.' Lantas mereka mendatangi Isa.' Hanya Isa menjawab, 'Maaf, di sini saya tak berhak menolong kalian, namun cobalah kalian datangi Muhammad Shallallahu'alaihiwasallam, seorang hamba yang telah diampuni dosanya baik yang terdahulu maupun yang akan datang.' Lantas orang-orang pun mendatangiku. Aku berusaha mendatangi dan meminta ijin Tuhanku sehingga aku diijinkan. Dan jika kulihat Tuhanku, aku tersungkur sujud. Lantas Allah membiarkanku sekehendak Allah membiarkanku. Tiba-tiba ada suara memanggil-manggil, 'Angkatlah kepalamu hai Muhammad, katakanlah, perkataanmu didengar, mintalah, engkau diberi, ajukanlah syafaat engkau akan diberi! Aku pun memuji Tuhanku dengan pujian yang diajarkan Tuhanku kepadaku tentangnya, kemudian aku memberi syafaat. Aku pun memberi syafaat, lantas Dia memberiku batasan yang aku kemudian memasukkan mereka ke dalam surga. Aku kemudian kembali, dan jika kulihat Tuhanku, aku tersungkur sujud dan Allah membiarkanku sekehendak-Nya. Lantas ada suara, 'Angkatlah kepalamu hai Muhammad, katakanlah, engkau didengar, mintalah, engkau pasti diberi, mintalah syafaat, engkau musti diberi syafaat.' Maka aku memuji Tuhanku dengan pujian yang telah diajarkan Tuhanku kepadaku tentangnya. Lantas aku memberi syafaat. Dan Dia memberiku batasan yang aku kemudian memasukkan mereka ke dalam surga. Aku kembali dan kuutarakan kepada Tuhanku, 'Ya Tuhanku, tidak tersisa dalam neraka selain yang ditahan oleh Alquran dan wajib kekal di dalamnya'.\" Nabi shallallahu 'alaihi wasallam kemudian bersabda: \"Akan dikeluarkan dari neraka siapa saja yang mengucapkan laa-ilaaha-illallah dan dalam hatinya mempunyai kebaikan seberat sebiji gandum, kemudian akan keluar dari neraka siapa saja yang mengucapkan laa-ilaaha-illallah dan dalam hatinya terdapat kebaikan seberat biji tepung, dan akan keluar dari neraka siapa saja yang mengucapkan laa-ilaaha illallah sedang dalam hatinya terdapat kebaikan seberat biji atom.\""},"6509":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَدُ اللَّهِ مَلْأَى لَا يَغِيضُهَا نَفَقَةٌ سَحَّاءُ اللَّيْلَ وَالنَّهَارَ وَقَالَ أَرَأَيْتُمْ مَا أَنْفَقَ مُنْذُ خَلَقَ السَّمَوَاتِ وَالْأَرْضَ فَإِنَّهُ لَمْ يَغِضْ مَا فِي يَدِهِ وَقَالَ عَرْشُهُ عَلَى الْمَاءِ وَبِيَدِهِ الْأُخْرَى الْمِيزَانُ يَخْفِضُ وَيَرْفَعُ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] telah menceritakan kepada kami [Abuz Zinad] dari [Al A'raj] dari [Abu Hurairah] Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tangan Allah selalu penuh, tidak kurang karena memberi nafkah, dan selalu dermawan baik siang maupun malam.\" Beliau bersabda lagi: \"Bukankah kalian telah melihat apa yang dibelanjakan-Nya semenjak Dia mencipta langit dan bumi, dan tidak berkurang sedikit pun apa yang di tangan-Nya?\" Beliau bersabda lagi: \"Arsy-Nya di atas air, dan tangan-Nya yang lain memegang timbangan, yang terkadang Ia rendahkan atau Ia tinggikan.\""},"6510":{"ar":"حَدَّثَنَا مُقَدَّمُ بْنُ مُحَمَّدِ بْنِ يَحْيَى قَالَ حَدَّثَنِي عَمِّي الْقَاسِمُ بْنُ يَحْيَى عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِنَّ اللَّهَ يَقْبِضُ يَوْمَ الْقِيَامَةِ الْأَرْضَ وَتَكُونُ السَّمَوَاتُ بِيَمِينِهِ ثُمَّ يَقُولُ أَنَا الْمَلِكُرَوَاهُ سَعِيدٌ عَنْ مَالِكٍ وَقَالَ عُمَرُ بْنُ حَمْزَةَ سَمِعْتُ سَالِمًا سَمِعْتُ ابْنَ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا وَقَالَ أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي أَبُو سَلَمَةَ أَنَّ أَبَا هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْبِضُ اللَّهُ الْأَرْضَ","id":"Telah menceritakan kepada kami [Muqaddam bin Muhammad bin Yahya] berkata, telah menceritakan kepadaku pamanku [Alqasim bin Yahya] dari [Ubaidullah] dari [Nafi'] dari [Ibn Umar] radliyallahu'anhuma, dari Rasulullah Shallallahu'alaihiwasallam, beliau bersabda: \"Pada hari kiamat Allah menggenggam bumi dan langit berada di tangan kanan-Nya, lantas Allah berfirman 'Aku lah sang raja'.\" [Sa'id] meriwayatkannya dari [Malik] dan [Umar bin Hamzah] berkata, 'Aku mendengar [Salim] aku mendengar [Ibn Umar] dari Nabi shallallahu 'alaihi wasallam dengan hadis ini.\" Dan [Abul Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Azzuhri] telah mengabarkan kepadaku [Abu Salamah] bahwa [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah menggenggam bumi.\""},"6511":{"ar":"حَدَّثَنَا مُسَدَّدٌ سَمِعَ يَحْيَى بْنَ سَعِيدٍ عَنْ سُفْيَانَ حَدَّثَنِي مَنْصُورٌ وَسُلَيْمَانُ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِأَنَّ يَهُودِيًّا جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا مُحَمَّدُ إِنَّ اللَّهَ يُمْسِكُ السَّمَوَاتِ عَلَى إِصْبَعٍ وَالْأَرَضِينَ عَلَى إِصْبَعٍ وَالْجِبَالَ عَلَى إِصْبَعٍ وَالشَّجَرَ عَلَى إِصْبَعٍ وَالْخَلَائِقَ عَلَى إِصْبَعٍ ثُمَّ يَقُولُ أَنَا الْمَلِكُ فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى بَدَتْ نَوَاجِذُهُ ثُمَّ قَرَأَ{ وَمَا قَدَرُوا اللَّهَ حَقَّ قَدْرِهِ }قَالَ يَحْيَى بْنُ سَعِيدٍ وَزَادَ فِيهِ فُضَيْلُ بْنُ عِيَاضٍ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَجُّبًا وَتَصْدِيقًا لَهُ","id":"Telah menceritakan kepada kami [Musaddad] ia mendengar [Yahya bin Sa'id] dari [Sufyan] telah menceritakan kepadaku [Manshur] dan [Sulaiman] dari [Ibrahim] dari ['Abidah] dari [Abdullah], bahwa seorang Yahudi menemui nabi shallallahu 'alaihi wasallam dan berkata 'Hai Muhammad, Allah memegang langit di atas satu jari, dan seluruh bumi dengan satu jari, dan seluruh gunung dengan satu jari, dan semua pohon hanya dengan satu jari, dan seluruh makhluk yang ada hanya dengan satu jari, lantas berkata 'Akulah Sang raja.' Maka Rasulullah Shallallahu'alaihiwasallam pun tertawa hingga kelihatan gigi serinya, kemudian beliau membaca ayat: '(Dan mereka tidak menghormati Allah dengan penghormatan yang semestinya) ' (QS.Azzumar 67). [Yahya bin Sa'id] berkata, \"Dan [Fudlail bin Ziyad] di dalam hadis tersebut menambahkan, dari [Manshur] dari [Ibrahim] dari [Abidah] dari [Abdullah] lantas Rasulullah Shallallahu'alaihiwasallam terkagum-kagum seraya membenarkannya.\""},"6512":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ سَمِعْتُ إِبْرَاهِيمَ قَالَ سَمِعْتُ عَلْقَمَةَ يَقُولُ قَالَ عَبْدُ اللَّهِجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَهْلِ الْكِتَابِ فَقَالَ يَا أَبَا الْقَاسِمِ إِنَّ اللَّهَ يُمْسِكُ السَّمَوَاتِ عَلَى إِصْبَعٍ وَالْأَرَضِينَ عَلَى إِصْبَع�� وَالشَّجَرَ وَالثَّرَى عَلَى إِصْبَعٍ وَالْخَلَائِقَ عَلَى إِصْبَعٍ ثُمَّ يَقُولُ أَنَا الْمَلِكُ أَنَا الْمَلِكُ فَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَحِكَ حَتَّى بَدَتْ نَوَاجِذُهُ ثُمَّ قَرَأَ{ وَمَا قَدَرُوا اللَّهَ حَقَّ قَدْرِهِ }","id":"Telah menceritakan kepada kami [Umar bin Hafs bin Ghiyats] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] aku mendengar [Ibrahim] berkata, Aku mendengar [Alqamah] berkata, [Abdullah] berkata, \"Seorang laki-laki ahli kitab menemui nabi shallallahu 'alaihi wasallam dan berkata, 'Wahai Abul qasim, Allah memegang langit hanya dengan satu jari, semua pohon hanya dengan satu jari, semua bintang hanya dengan satu jari, seluruh makhluk hanya dengan satu jari, lalu Allah berfirman: 'Akulah sang raja, akulah sang raja'. Dan kulihat Nabi shallallahu 'alaihi wasallam tertawa hingga kelihatan gigi serinya, lantas beliau membaca ayat: '(Dan mereka tidak menghormati Allah dengan penghormatan yang semestinya) ' (QS.Azzumar 67)."},"6513":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ التَّبُوذَكِيُّ حَدَّثَنَا أَبُو عَوَانَةَ حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ وَرَّادٍ كَاتِبِ الْمُغِيرَةِ عَنْ الْمُغِيرَةِ قَالَقَالَ سَعْدُ بْنُ عُبَادَةَ لَوْ رَأَيْتُ رَجُلًا مَعَ امْرَأَتِي لَضَرَبْتُهُ بِالسَّيْفِ غَيْرَ مُصْفَحٍ فَبَلَغَ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَتَعْجَبُونَ مِنْ غَيْرَةِ سَعْدٍ وَاللَّهِ لَأَنَا أَغْيَرُ مِنْهُ وَاللَّهُ أَغْيَرُ مِنِّي وَمِنْ أَجْلِ غَيْرَةِ اللَّهِ حَرَّمَ الْفَوَاحِشَ مَا ظَهَرَ مِنْهَا وَمَا بَطَنَ وَلَا أَحَدَ أَحَبُّ إِلَيْهِ الْعُذْرُ مِنْ اللَّهِ وَمِنْ أَجْلِ ذَلِكَ بَعَثَ الْمُبَشِّرِينَ وَالْمُنْذِرِينَ وَلَا أَحَدَ أَحَبُّ إِلَيْهِ الْمِدْحَةُ مِنْ اللَّهِ وَمِنْ أَجْلِ ذَلِكَ وَعَدَ اللَّهُ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Musa bin Ismail At Tabudzaki] telah menceritakan kepada kami [Abu 'Awanah] telah menceritakan kepada kami [Abdul Malik] dari [Warrad] juru tulis Mughira, dari [Mughirah] berkata, \"Sa'd bin Ubadah berkata, \"Kalaulah kulihat seorang laki-laki bersama isteriku, niscaya aku penggal dia dengan pedang di bagian mata pedangnya, bukan dengan pinggirnya.\" Berita ini kemudian terdengar oleh Rasulullah Shallallahu'alaihiwasallam, sehingga beliau bersabda: \"Adakah kalian merasa heran dengan kecemburuan Sa'd? Demi Allah, sungguh aku lebih cemburu daripada dia, dan Allah lebih cemburu daripada aku, dan karena kecemburuan Allah itulah Allah mengharamkan segala kejahatan baik yang nampak maupun yang tersembunyi, dan tidak ada seorangpun yang lebih suka terhadap argumentasi daripada Allah, karena itulah Allah mengutus para rasul sebagai pembawa berita gembira dan pemberi peringatan, dan tak ada seorang pun yang lebih menyukai pujian daripada Allah, karena itulah Allah menjanjikan surga.\" "},"6514":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِرَجُلٍ أَمَعَكَ مِنْ الْقُرْآنِ شَيْءٌ قَالَ نَعَمْ سُورَةُ كَذَا وَسُورَةُ كَذَا لِسُوَرٍ سَمَّاهَا","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Abu Hazim] dari [Sahal bin Sa'd] berkata, \"Nabi shallallahu 'alaihi wasallam pernah bertanya kepada seseorang: 'Apakah engkau mempunyai hapalan alquran? ' Ia menjawab, 'Ada, yaitu surat sedemikian sedemikian, ' yang ia sebut namanya.\""},"6515":{"ar":"حَدَّثَنَا عَبْدَانُ قَالَ أَخْبَرَنَا أَبُو حَمْزَةَ عَنْ الْأَعْمَشِ عَنْ جَامِعِ بْنِ شَدَّادٍ عَنْ صَفْوَانَ بْنِ مُحْرِزٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَإِنِّي عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَهُ قَوْمٌ مِنْ بَنِي تَمِيمٍ فَقَالَ اقْبَلُوا الْبُشْرَى يَا بَنِي تَمِيمٍ قَالُوا بَشَّرْتَنَا فَأَعْطِنَا فَدَخَلَ نَاسٌ مِنْ أَهْلِ الْيَمَنِ فَقَالَ اقْبَلُوا الْبُشْرَى يَا أَهْلَ الْيَمَنِ إِذْ لَمْ يَقْبَلْهَا بَنُو تَمِيمٍ قَالُوا قَبِلْنَا جِئْنَاكَ لِنَتَفَقَّهَ فِي الدِّينِ وَلِنَسْأَلَكَ عَنْ أَوَّلِ هَذَا الْأَمْرِ مَا كَانَ قَالَ كَانَ اللَّهُ وَلَمْ يَكُنْ شَيْءٌ قَبْلَهُ وَكَانَ عَرْشُهُ عَلَى الْمَاءِ ثُمَّ خَلَقَ السَّمَوَاتِ وَالْأَرْضَ وَكَتَبَ فِي الذِّكْرِ كُلَّ شَيْءٍ ثُمَّ أَتَانِي رَجُلٌ فَقَالَ يَا عِمْرَانُ أَدْرِكْ نَاقَتَكَ فَقَدْ ذَهَبَتْ فَانْطَلَقْتُ أَطْلُبُهَا فَإِذَا السَّرَابُ يَنْقَطِعُ دُونَهَا وَايْمُ اللَّهِ لَوَدِدْتُ أَنَّهَا قَدْ ذَهَبَتْ وَلَمْ أَقُمْ","id":"Telah menceritakan kepada kami [Abdan] berkata, Telah mengabarkan kepada kami [Abu Hamzah] dari [Al A'masy] dari [Jami' bin Syidad] dari [Shafwan bin Muhriz] dari ['Imran bin Hushain] berkata, \"Pernah aku di sisi Nabi shallallahu 'alaihi wasallam. Tiba-tiba ada sekelompok kaum dari bani Tamim mendatanginya dan berkata, 'Terimalah berita gembira wahai bani Tamim! Mereka menjawab, 'Engkau telah memberi kami kabar gembira, maka berikanlah! Lantas beberapa orang penduduk Yaman datang dan beliau katakan: 'Terimalah kabar gembira wahai penduduk Yaman, sebab bani Tamim belum menemerimanya! ' Mereka jawab, 'kami menerimanya, kami datang untuk belajar agama dan bertanya kepadamu awal-awal kejadian alam ini! Nabi menjawab: 'Allah telah ada dan tidak ada sesuatu pun terjadi sebelum-Nya, arsy-Nya berada di atas air, kemudian Allah mencipta langit dan bumi dan Allah menetapkan segala sesuatu dalam alquran'. Lantas seorang laki-laki mendatangiku dan berujar 'Wahai Imran, carilah untamu, sebab untamu pergi! Aku bergegas mencarinya, tidak tahunya fatamorgana (padang pasir) menghilangkan pandangannya. Demi Allah, sungguh aku mengimpikan sekiranya untaku biarlah hilang sedang aku tidak usah berdiri.\""},"6516":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامٍ حَدَّثَنَا أَبُو هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ يَمِينَ اللَّهِ مَلْأَى لَا يَغِيضُهَا نَفَقَةٌ سَحَّاءُ اللَّيْلَ وَالنَّهَارَ أَرَأَيْتُمْ مَا أَنْفَقَ مُنْذُ خَلَقَ السَّمَوَاتِ وَالْأَرْضَ فَإِنَّهُ لَمْ يَنْقُصْ مَا فِي يَمِينِهِ وَعَرْشُهُ عَلَى الْمَاءِ وَبِيَدِهِ الْأُخْرَى الْفَيْضُ أَوْ الْقَبْضُ يَرْفَعُ وَيَخْفِضُ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Hammam] telah menceritakan kepada kami [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Tangan kanan Allah selalu penuh dan sama sekali tidak pernah kurang karena berderma (infak), Dia sangat dermawan baik malam maupun siang, tidakkah kalian tahu apa yang telah diinfakan-Nya semenjak Ia mencipta langit dan bumi dan itu semua tidak mengurangi apa yang berada di tangan kanan-Nya? Dan arsy-Nya berada diatas air, dan ditangan-Nya yang lain urusan menjulurkan atau menahan, karenanya Dia meninggikan atau merendahkan.\""},"6517":{"ar":"حَدَّثَنَا أَحْمَدُ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَجَاءَ زَيْدُ بْنُ حَارِثَةَ يَشْكُو فَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اتَّقِ اللَّهَ وَأَمْسِكْ عَلَيْكَ زَوْجَكَ قَالَ أَنَسٌ لَوْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَاتِمًا شَيْئًا لَكَتَمَ هَذِهِ قَالَ فَكَانَتْ زَيْنَبُ تَفْخَرُ عَلَى أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَقُولُ زَوَّجَكُنَّ أَهَالِيكُنَّ وَزَوَّجَنِي اللَّهُ تَعَالَى مِنْ فَوْقِ سَبْعِ سَمَوَاتٍوَعَنْ ثَابِتٍ{ وَتُخْفِي فِي نَفْسِكَ مَا اللَّهُ مُبْدِيهِ وَتَخْشَى النَّاسَ }نَزَلَتْ فِي شَأْنِ زَيْنَبَ وَزَيْدِ ب��نِ حَارِثَةَ","id":"Telah menceritakan kepada kami [Ahmad] telah menceritakan kepada kami [Muhammad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Anas] berkata, \"Zaid bin Haritsah datang melaporkan keluh kesahnya, lantas Nabi shallallahu 'alaihi wasallam bersabda: \"Bertakwalah engkau kepada Allah, dan tahanlah isterimu.\" Anas berkata, \"Kalaulah Rasulullah sudah merahasiakan sesuatu, beliau sungguh merahasiakannya.\" Ketika itu Zainab binti Jahsyin membanggakan diri kepada isteri-isteri beliau lainnya seraya berkata, 'Kalian dikawinkan oleh keluarga kalian, sebaliknya aku dikawinkan sendiri oleh Allah ta'ala dari atas langit berlapis tujuh.' Dan masih dari Tsabit mengenai ayat: '(Dan kamu merahasiakan urusanmu yang Allah membeberkannya, dan kamu takut kepada manusia) ' (Qs. Al Ahzab: 37), ayat ini diturunkan tentang percekcokan rumah tangga Zainab dan Zaid bin Haritsah.\""},"6518":{"ar":"حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى حَدَّثَنَا عِيسَى بْنُ طَهْمَانَ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ يَقُولُنَزَلَتْ آيَةُ الْحِجَابِ فِي زَيْنَبَ بِنْتِ جَحْشٍ وَأَطْعَمَ عَلَيْهَا يَوْمَئِذٍ خُبْزًا وَلَحْمًا وَكَانَتْ تَفْخَرُ عَلَى نِسَاءِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَتْ تَقُولُ إِنَّ اللَّهَ أَنْكَحَنِي فِي السَّمَاءِ","id":"Telah menceritakan kepada kami [Khallad bin Yahya] telah menceritakan kepada kami [Isa bin Tahman] berkata, aku mendengar [Anas bin Malik] radliyallahu'anhu mengatakan, \"Ayat hijab diturunkan tentang Zainab binti Jahsyin, yang ketika itu beliau Shallallahu'alaihiwasallam memberinya makan berupa roti dan daging, dan Zainab membanggakan diri kepada isteri-isteri Nabi shallallahu 'alaihi wasallam lainnya dengan berkata, 'Allah lah yang menikahkanku di langit.'"},"6519":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ لَمَّا قَضَى الْخَلْقَ كَتَبَ عِنْدَهُ فَوْقَ عَرْشِهِ إِنَّ رَحْمَتِي سَبَقَتْ غَضَبِي","id":"Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] telah menceritakan kepada kami [Abuz zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Ketika Allah menetapkan penciptaan, Dia tulis di sisi-Nya di atas arsy-Nya 'Rahmat-Ku lebih mendominasi kemurkaan-Ku'.\""},"6520":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنِي مُحَمَّدُ بْنُ فُلَيْحٍ قَالَ حَدَّثَنِي أَبِي حَدَّثَنِي هِلَالٌ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ آمَنَ بِاللَّهِ وَرَسُولِهِ وَأَقَامَ الصَّلَاةَ وَصَامَ رَمَضَانَ كَانَ حَقًّا عَلَى اللَّهِ أَنْ يُدْخِلَهُ الْجَنَّةَ هَاجَرَ فِي سَبِيلِ اللَّهِ أَوْ جَلَسَ فِي أَرْضِهِ الَّتِي وُلِدَ فِيهَا قَالُوا يَا رَسُولَ اللَّهِ أَفَلَا نُنَبِّئُ النَّاسَ بِذَلِكَ قَالَ إِنَّ فِي الْجَنَّةِ مِائَةَ دَرَجَةٍ أَعَدَّهَا اللَّهُ لِلْمُجَاهِدِينَ فِي سَبِيلِهِ كُلُّ دَرَجَتَيْنِ مَا بَيْنَهُمَا كَمَا بَيْنَ السَّمَاءِ وَالْأَرْضِ فَإِذَا سَأَلْتُمُ اللَّهَ فَسَلُوهُ الْفِرْدَوْسَ فَإِنَّهُ أَوْسَطُ الْجَنَّةِ وَأَعْلَى الْجَنَّةِ وَفَوْقَهُ عَرْشُ الرَّحْمَنِ وَمِنْهُ تَفَجَّرُ أَنْهَارُ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepadaku [Muhammad bin Fulaih] berkata, telah menceritakan kepadaku [Ayahku] telah menceritakan kepadaku [Hilal] dari ['Atha bin Yasar] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa beriman kepada Allah dan rasul-Nya, mendirikan shalat, dan berpuasa pada bulan Ramadlan, maka Allah berkewajiban memasukkannya kedalam surga, baik ia berhijrah fi sabilillah atau duduk di tempat tinggalnya tempat ia dilahirkannya.\" Para sahabat berkata, \"Wahai Rasulullah, tidak sebaiknyakah kami mengabarkan orang-orang tentang hal ini?\" Nabi malahan menjawab: \"Dalam surga terdapat seratus derajat yang Allah persiapkan bagi para mujahidin di jalan-Nya, yang jarak antara setiap dua tingkatan bagaikan antara langit dan bumi, maka jika kalian meminta Allah, mintalah surga firdaus, sebab firdaus adalah surga yang paling tengah dan paling tinggi, di atasnya ada singgasana Arrahman, dan daripadanya sungai surga memancar.\""},"6521":{"ar":"حَدَّثَنَا يَحْيَى بْنُ جَعْفَرٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ هُوَ التَّيْمِيُّ عَنْ أَبِيهِ عَنْ أَبِي ذَرٍّ قَالَدَخَلْتُ الْمَسْجِدَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ فَلَمَّا غَرَبَتْ الشَّمْسُ قَالَ يَا أَبَا ذَرٍّ هَلْ تَدْرِي أَيْنَ تَذْهَبُ هَذِهِ قَالَ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَإِنَّهَا تَذْهَبُ تَسْتَأْذِنُ فِي السُّجُودِ فَيُؤْذَنُ لَهَا وَكَأَنَّهَا قَدْ قِيلَ لَهَا ارْجِعِي مِنْ حَيْثُ جِئْتِ فَتَطْلُعُ مِنْ مَغْرِبِهَا ثُمَّ قَرَأَ ذَلِكَ مُسْتَقَرٌّ لَهَا فِي قِرَاءَةِ عَبْدِ اللَّهِ","id":"Telah menceritakan kepada kami [Yahya bin Ja'far] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim] -yaitu At Taimi- dari [Ayahnya] dari [Abu Dzar] berkata, \"Aku masuk masjid sedang Rasulullah Shallallahu'alaihiwasallam duduk. Ketika matahari terbenam, beliau bertanya: 'Wahai Abu Dzar, tahukah engkau ke manakah matahari ini pergi?\" Aku menjawab, 'Allah dan rasul-Nya lah yang lebih tahu! ' Nabi menjawab: \"Sesungguhnya matahari ini pergi meminta ijin untuk sujud sehingga diijinkan, seolah-olah dikatakan kepada 'Kembalilah engkau dari tempat engkau datang', maka ia muncul di sebelah baratnya, \" kemudian beliau membaca: '(Itulah tempat tinggalnya) ', menurut bacaan Abdullah.\""},"6522":{"ar":"حَدَّثَنَا مُوسَى عَنْ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ عُبَيْدِ بْنِ السَّبَّاقِ أَنَّ زَيْدَ بْنَ ثَابِتٍ وَقَالَ اللَّيْثُ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ السَّبَّاقِ أَنَّ زَيْدَ بْنَ ثَابِتٍ حَدَّثَهُ قَالَأَرْسَلَ إِلَيَّ أَبُو بَكْرٍ فَتَتَبَّعْتُ الْقُرْآنَ حَتَّى وَجَدْتُ آخِرَ سُورَةِ التَّوْبَةِ مَعَ أَبِي خُزَيْمَةَ الْأَنْصَارِيِّ لَمْ أَجِدْهَا مَعَ أَحَدٍ غَيْرِهِ{ لَقَدْ جَاءَكُمْ رَسُولٌ مِنْ أَنْفُسِكُمْ }حَتَّى خَاتِمَةِ بَرَاءَةٌحَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ بِهَذَا وَقَالَ مَعَ أَبِي خُزَيْمَةَ الْأَنْصَارِيِّ","id":"Telah menceritakan kepada kami [Musa] dari [Ibrahim] telah menceritakan kepada kami [Ibn Syihab] dari ['Ubaid bin Sibaq] bahwa [Zaid bin Tsabit], sedang [Al Laits] berkata, telah menceritakan kepadaku [Abdurrahman bin Khalid] dari [Ibn Syihab] dari [Ibn Sibaq Zaid bin Tsabit] menceritakannya dengan berkata, \"Abu Bakar mengutus seseorang kepadaku dan Abu Khuzaimah Al Anshari, sehingga aku telusuri alquran dan hingga aku temukan akhir surat At Taubah, yang aku tidak menemukannya dengan seorang pun selain bersamanya, yaitu ayat: '(Telah datang kepada kalian seorang rasul dari kalian sendiri) ' (QS. Attaubah 128), hingga penghabisan surat al Bara'ah (surat At Taubah).\" Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Yunus] dengan hadis ini, dan beliau berkata; telah menceritakan kepada kami Yahya bin Bukair telah menceritakan kepada kami Al Laits dari Yunus dengan hadis ini, dan ia menyebutkan, 'Bersama Abu Khuzaimah Al anshari.\""},"6523":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا وُهَيْبٌ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَبِي الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عِنْدَ الْكَرْبِ لَا إِلَهَ إِلَّا اللَّهُ الْعَلِيمُ الْحَلِيمُ لَا إِلَهَ إِلَّا اللَّهُ رَبُّ الْعَرْشِ الْعَظِيمِ لَا إِلَهَ إِلَّا اللَّهُ رَبُّ السَّمَوَاتِ وَرَبُّ الْأَرْضِ رَبُّ الْعَرْشِ الْكَرِيمِ","id":"Telah menceritakan kepada kami [Mu'alla bin Asad] telah menceritakan kepada kami [Wuhaib] dari [Sa'id] dari [Qatadah] dari [Abul 'Aliyah] dari [Ibn Abbas] radliyallahu'anhuma berkata, \"Jika susah, Nabi shallallahu 'alaihi wasallam memanjatkan doa: 'LAA-ILAAHA ILLALLAHUL 'ALIIMUL HALIIM, LAA-ILAAHA ILLALLAH RABBUL'ARSYIL 'AZHIIMI LAA-ILAAHA ILLALLAH RABBUS SAMAAWAATI WARABBUL ARDLI RABBUL'ASYIL KARIIMI (Tiada sesembahan yang hak selain Allah Yang Maha Mengetahui lagi Maha Bijaksana, tiada sesembahan yang hak selain Allah, Tuhan pemelihara arsy Yang Maha Agung, tiada sesembahan yang hak selain Allah Yang memelihara langit dan bumi, Tuhan pemelihara arsy yang mulia) '.\""},"6524":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ النَّاسُ يَصْعَقُونَ يَوْمَ الْقِيَامَةِ فَإِذَا أَنَا بِمُوسَى آخِذٌ بِقَائِمَةٍ مِنْ قَوَائِمِ الْعَرْشِوَقَالَ الْمَاجِشُونُ عَنْ عَبْدِ اللَّهِ بْنِ الْفَضْلِ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَأَكُونُ أَوَّلَ مَنْ بُعِثَ فَإِذَا مُوسَى آخِذٌ بِالْعَرْشِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari ['Amru bin Yahya] dari [Ayahnya] dari [Abu Sa'id Al Khudzri] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Pada hari kiamat semua manusia pingsan, tak tahunya saya dan Musa berpegangan dengan salah satu penyangga 'arsy.\" Sedang [Al Majisyun] berkata dari [Abdullah bin Fadll] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Dan aku menjadi manusia yang pertama-tama dibangkitkan, tak tahunya Musa sudah menyangga arsy.\""},"6525":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَتَعَاقَبُونَ فِيكُمْ مَلَائِكَةٌ بِاللَّيْلِ وَمَلَائِكَةٌ بِالنَّهَارِ وَيَجْتَمِعُونَ فِي صَلَاةِ الْعَصْرِ وَصَلَاةِ الْفَجْرِ ثُمَّ يَعْرُجُ الَّذِينَ بَاتُوا فِيكُمْ فَيَسْأَلُهُمْ وَهُوَ أَعْلَمُ بِكُمْ فَيَقُولُ كَيْفَ تَرَكْتُمْ عِبَادِي فَيَقُولُونَ تَرَكْنَاهُمْ وَهُمْ يُصَلُّونَ وَأَتَيْنَاهُمْ وَهُمْ يُصَلُّونَوَقَالَ خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ دِينَارٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَمَنْ تَصَدَّقَ بِعَدْلِ تَمْرَةٍ مِنْ كَسْبٍ طَيِّبٍ وَلَا يَصْعَدُ إِلَى اللَّهِ إِلَّا الطَّيِّبُ فَإِنَّ اللَّهَ يَتَقَبَّلُهَا بِيَمِينِهِ ثُمَّ يُرَبِّيهَا لِصَاحِبِهِ كَمَا يُرَبِّي أَحَدُكُمْ فُلُوَّهُ حَتَّى تَكُونَ مِثْلَ الْجَبَلِوَرَوَاهُ وَرْقَاءُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ سَعِيدِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا يَصْعَدُ إِلَى اللَّهِ إِلَّا الطَّيِّبُ","id":"Telah menceritakan kepada kami [Ismail] telah menceritakan kepadaku [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] radliyallahu'anhu, Rasulullah Shallallahu'alaihiwasallam bersabda: \"Di tengah-tengah kalian ada malaikat yang silih berganti bertugas mengiringi kalian diwaktu malam dan siang, mereka berkumpul ketika shalat 'ashr dan shalat subuh. Malaikat yang mengawasi amal kalian di malam hari naik ke langit lantas Allah bertanya mereka -dan Allah lebih tahu keadaan kalian- bagaimana kalian tinggalkan hamba-hamba-Ku? Para malaikat menjawab, 'Kami tinggalkan mereka sedang mereka tengah mendirikan shalat, dan kami datangi mereka sedang mereka mendirikan shalat'.\" Sedang Khalid bin Makhlad berkata, telah menceritakan kepada kami Sulaiman telah menceritakan kepadaku Abdullah bin Dinar dari Abu Shalih dari Abu Hurairah berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersedekah dengan separuh biji kurma dari penghasilan yang baik, dan tidak ada yang naik kepada Allah kecuali amal yang baik, maka Allah menerimanya dengan tangan kanan-Nya, kemudian mengembangkannya untuk pelakunya sebagaimana salah seorang diantara kalian merawat kuda piaraannya hingga sebesar gunung.\" Dan hadis ini diriwayatkan oleh Warqa' dari 'Abdullah bin Dinar dari Sa'id bin Yasar dari Abu Hurairah dari Nabi shallallahu 'alaihi wasallam dengan redaksi, 'Dan tidak ada yang naik kepada Allah kecuali kebaikan'.\""},"6526":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَبِي الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو بِهِنَّ عِنْدَ الْكَرْبِ لَا إِلَهَ إِلَّا اللَّهُ الْعَظِيمُ الْحَلِيمُ لَا إِلَهَ إِلَّا اللَّهُ رَبُّ الْعَرْشِ الْعَظِيمِ لَا إِلَهَ إِلَّا اللَّهُ رَبُّ السَّمَوَاتِ وَرَبُّ الْعَرْشِ الْكَرِيمِ","id":"Telah menceritakan kepada kami [Abdul A'la bin Hammad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Abul 'Aliyah] dari [Ibn Abbas] bahwa nabi shallallahu 'alaihi wasallam membaca kalimat-kalimat berikut ketika susah: 'LAA ILAAHA ILLALLAHUL 'AZHIIM, LAA-ILAAHA ILLALLAH RABBUL'ARSYIL 'AZHIIMU, LAA-ILAAHA ILLALLAAH RABBUSSAMAAWAATI WARABBUL'ARSYIL KARIIM (Tiada sesembahan yang hak selain Allah Yang Maha agung, tiada sesembahan yang hak selain Allah pemilik arsy yang Agung, tiada sesembahan yang hak selain Allah pemilik langit dan pemilik arsy yang mulia) '."},"6527":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ أَبِيهِ عَنْ ابْنِ أَبِي نُعْمٍ أَوْ أَبِي نُعْمٍ شَكَّ قَبِيصَةُ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ بُعِثَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذُهَيْبَةٍ فَقَسَمَهَا بَيْنَ أَرْبَعَةٍ و حَدَّثَنِي إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِيهِ عَنْ ابْنِ أَبِي نُعْمٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَبَعَثَ عَلِيٌّ وَهُوَ بِالْيَمَنِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذُهَيْبَةٍ فِي تُرْبَتِهَا فَقَسَمَهَا بَيْنَ الْأَقْرَعِ بْنِ حَابِسٍ الْحَنْظَلِيِّ ثُمَّ أَحَدِ بَنِي مُجَاشِعٍ وَبَيْنَ عُيَيْنَةَ بْنِ بَدْرٍ الْفَزَارِيِّ وَبَيْنَ عَلْقَمَةَ بْنِ عُلَاثَةَ الْعَامِرِيِّ ثُمَّ أَحَدِ بَنِي كِلَابٍ وَبَيْنَ زَيْدِ الْخَيْلِ الطَّائِيِّ ثُمَّ أَحَدِ بَنِي نَبْهَانَ فَتَغَيَّظَتْ قُرَيْشٌ وَالْأَنْصَارُ فَقَالُوا يُعْطِيهِ صَنَادِيدَ أَهْلِ نَجْدٍ وَيَدَعُنَا قَالَ إِنَّمَا أَتَأَلَّفُهُمْ فَأَقْبَلَ رَجُلٌ غَائِرُ الْعَيْنَيْنِ نَاتِئُ الْجَبِينِ كَثُّ اللِّحْيَةِ مُشْرِفُ الْوَجْنَتَيْنِ مَحْلُوقُ الرَّأْسِ فَقَالَ يَا مُحَمَّدُ اتَّقِ اللَّهَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَنْ يُطِيعُ اللَّهَ إِذَا عَصَيْتُهُ فَيَأْمَنُنِي عَلَى أَهْلِ الْأَرْضِ وَلَا تَأْمَنُونِي فَسَأَلَ رَجُلٌ مِنْ الْقَوْمِ قَتْلَهُ أُرَاهُ خَالِدَ بْنَ الْوَلِيدِ فَمَنَعَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا وَلَّى قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ ضِئْضِئِ هَذَا قَوْمًا يَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ حَنَاجِرَهُمْ يَمْرُقُونَ مِنْ الْإِسْلَامِ مُرُوقَ السَّهْمِ مِنْ الرَّمِيَّةِ يَقْتُلُونَ أَهْلَ الْإِسْلَامِ وَيَدَعُونَ أَهْلَ الْأَوْثَانِ لَئِنْ أَدْرَكْتُهُمْ لَأَقْتُلَنَّهُمْ قَتْلَ عَادٍ","id":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Ayahnya] dari [Ibn Abu Nu'm] -atau Abu Nu'm, Qabishah masih ragu antara keduanya- dari [Abu Sa'id Al Khudzri] berkata, \"Beberapa potongan emas didatangkan kepada nabi shallallahu 'alaihi wasallam, lantas beliau membaginya di antara empat orang.\" Dan telah menceritakan kepadaku [Ishaq bin Nashr] telah menceritakan kepada kami ['Abdurrazaq] telah mengabarkan kepada kami [Sufyan] dari [Ayahnya] dari [Ibn Abu Nu'm] dari [Abu Sa'id Al Khudzri] berkata, \"Ali, yang ketika itu di Yaman mengirimkan beberapa potongan emas yang masih dengan tanahnya kepada nabi shallallahu 'alaihi wasallam, lantas beliau membagi-bagikannya antara Al aqra' bin Habis Al Hanzhali, lalu salah seorang Bani Majasyi', lalu 'Uyainah bin Badar Al Fazari, Alqamah bin 'Al Atsah Al 'Amiri, kemudian seorang Bani Kilab dan Zaid Al Khail Ath Thai, kemudian salah seorang Bani Nabhan. Maka beberapa orang qurasy dan Anshar pun marah, mereka berkata, 'Nabi berikan emas itu kepada pemuka-pemuka penduduk Nejed dan ia meninggalkan kita-kita'. Nabi terus berkata: 'Hanyasanya aku beri mereka untuk menjinakkan hati mereka.' Kemudian datanglah seseorang yang kedua matanya menjorok ke dalam, dahinya menjorok keluar, jenggotnya lebat, dua keningnya menjorok keluar dan berkepala gundul, orang itu kemudian berkata, 'Hai Muhammad, bertakwalah kepada Allah (maksudnya bertindaklah hati-hati dan adil)! ' Spontan Nabi shallallahu 'alaihi wasallam menjawab: \"Siapa lagi yang menaati Allah jika aku membangkang-Nya, sesungguhnya Allah telah memberiku kepercayaan untuk memimpin penduduk bumi sedang kalian tidak percaya kepadaku.\" Lantas ada seorang sahabat yang meminta beliau untuk membunuh orang itu, dan seingatku orang sahabat itu adalah Khalid bin Al Walid, namun nabi mencegahnya. Tatkala orang itu pergi nabi shallallahu 'alaihi wasallam bersabda: \"Diantara keturunan orang ini ada suatu kaum yang membaca al quran yang tidak melebihi tenggorokan mereka (membaca alquran tidak meresap dalam hati), mereka keluar dari Islam sebagaimana anak panah keluar dari busurnya, mereka membantai pemeluk Islam dan membiarkan pemuja patung-patung, kalaulah aku temui mereka, niscaya aku bunuh mereka sebagaimana pembunuhan terhadap kaum 'Ad.\""},"6528":{"ar":"حَدَّثَنَا عَيَّاشُ بْنُ الْوَلِيدِ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِيهِ عَنْ أَبِي ذَرٍّ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَوْلِهِ{ وَالشَّمْسُ تَجْرِي لِمُسْتَقَرٍّ لَهَا }قَالَ مُسْتَقَرُّهَا تَحْتَ الْعَرْشِ","id":"Telah menceritakan kepada kami ['Ayyasy bin Al Walid] telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Ibrahim At Taimi] dari [Ayahnya] dari [Abu Dzar] berkata, \"Aku bertanya nabi shallallahu 'alaihi wasallam mengenai kutipan ayat: '(dan matahari berjalan di persinggahannya) ' (Qs. Yasin: 38), beliau berkomentar: \"Persingghannya adalah di bawah 'Arsy.\""},"6529":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا خَالِدٌ وَهُشَيْمٌ عَنْ إِسْمَاعِيلَ عَنْ قَيْسٍ عَنْ جَرِيرٍ قَالَكُنَّا جُلُوسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ نَظَرَ إِلَى الْقَمَرِ لَيْلَةَ الْبَدْرِ قَالَ إِنَّكُمْ سَتَرَوْنَ رَبَّكُمْ كَمَا تَرَوْنَ هَذَا الْقَمَرَ لَا تُضَامُونَ فِي رُؤْيَتِهِ فَإِنْ اسْتَطَعْتُمْ أَنْ لَا تُغْلَبُوا عَلَى صَلَاةٍ قَبْلَ طُلُوعِ الشَّمْسِ وَصَلَاةٍ قَبْلَ غُرُوبِ الشَّمْسِ فَافْعَلُوا","id":"Telah menceritakan kepada kami ['Amru bin Aun] telah menceritakan kepada kami [Khalid] dan [Husyaim] dari [Ismail] dari [Qais] dari [Jarir] berkata, \"Pernah kami duduk-duduk di sisi Nabi shallallahu 'alaihi wasallam. Tiba-tiba beliau melihat bulan yang ketika itu malam purnama, lantas beliau bersabda: \"Sungguh kalian akan melihat Tuhan kalian sebagaimana kalian melihat bulan ini, kalian tidak bakalan kesulitan melihatnya, maka jika kalian mampu untuk tidak kewalahan melakukan shalat sebelum matahari terbit dan matahari terbenam, maka lakukanlah.\""},"6530":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا عَاصِمُ بْنُ يُوسُفَ الْيَرْبُوعِيُّ حَدَّثَنَا أَبُو شِهَابٍ عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكُمْ سَتَرَوْنَ رَبَّكُمْ عِيَانًا","id":"Telah menceritakan kepada kami [Yusuf bin Musa] telah menceritakan kepada kami ['Ashim bin Yusuf Al Yarbu'i] telah menceritakan kepada kami [Abu Syihab] dari [Ismail bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Jarir bin Abdullah] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Kalian akan melihat Rabb kalian dengan mata telanjang.\""},"6531":{"ar":"حَدَّثَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا حُسَيْنٌ الْجُعْفِيُّ عَنْ زَائِدَةَ حَدَّثَنَا بَيَانُ بْنُ بِشْرٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ حَدَّثَنَا جَرِيرٌ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ الْبَدْرِ فَقَالَ إِنَّكُمْ سَتَرَوْنَ رَبَّكُمْ يَوْمَ الْقِيَامَةِ كَمَا تَرَوْنَ هَذَا لَا تُضَامُونَ فِي رُؤْيَتِهِ","id":"Telah menceritakan kepada kami ['Abdah bin Abdullah] telah menceritakan kepada kami [Husain Al Ju'fi] dari [Zaidah] telah menceritakan kepada kami [Bayan bin Bisyr] dari [Qais bin Abu Hazim] telah menceritakan kepada kami [Jarir], bahwa Rasulullah Shallallahu'alaihiwasallam menemui kami di malam purnama, lantas beliau bersabda: \"Kalian akan melihat Tuhan kalian pada hari kiamat sebagaimana kalian melihat bulan ini dengan tidak kesulitan melihatnya.\""},"6532":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّاسَ قَالُوا يَا رَسُولَ اللَّهِ هَلْ نَرَى رَبَّنَا يَوْمَ الْقِيَامَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ تُضَارُّونَ فِي الْقَمَرِ لَيْلَةَ الْبَدْرِ قَالُوا لَا يَا رَسُولَ اللَّهِ قَالَ فَهَلْ تُضَارُّونَ فِي الشَّمْسِ لَيْسَ دُونَهَا سَحَابٌ قَالُوا لَا يَا رَسُولَ اللَّهِ قَالَ فَإِنَّكُمْ تَرَوْنَهُ كَذَلِكَ يَجْمَعُ اللَّهُ النَّاسَ يَوْمَ الْقِيَامَةِ فَيَقُولُ مَنْ كَانَ يَعْبُدُ شَيْئًا فَلْيَتْبَعْهُ فَيَتْبَعُ مَنْ كَانَ يَعْبُدُ الشَّمْسَ الشَّمْسَ وَيَتْبَعُ مَنْ كَانَ يَعْبُدُ الْقَمَرَ الْقَمَرَ وَيَتْبَعُ مَنْ كَانَ يَعْبُدُ الطَّوَاغِيتَ الطَّوَاغِيتَ وَتَبْقَى هَذِهِ الْأُمَّةُ فِيهَا شَافِعُوهَا أَوْ مُنَافِقُوهَا شَكَّ إِبْرَاهِيمُ فَيَأْتِيهِمْ اللَّهُ فَيَقُولُ أَنَا رَبُّكُمْ فَيَقُولُونَ هَذَا مَكَانُنَا حَتَّى يَأْتِيَنَا رَبُّنَا فَإِذَا جَاءَنَا رَبُّنَا عَرَفْنَاهُ فَيَأْتِيهِمْ اللَّهُ فِي صُورَتِهِ الَّتِي يَعْرِفُونَ فَيَقُولُ أَنَا رَبُّكُمْ فَيَقُولُونَ أَنْتَ رَبُّنَا فَيَتْبَعُونَهُ وَيُضْرَبُ الصِّرَاطُ بَيْنَ ظَهْرَيْ جَهَنَّمَ فَأَكُونُ أَنَا وَأُمَّتِي أَوَّلَ مَنْ يُجِيزُهَا وَلَا يَتَكَلَّمُ يَوْمَئِذٍ إِلَّا الرُّسُلُ وَدَعْوَى الرُّسُلِ يَوْمَئِذٍ اللَّهُمَّ سَلِّمْ سَلِّمْ وَفِي جَهَنَّمَ كَلَالِيبُ مِثْلُ شَوْكِ السَّعْدَانِ هَلْ رَأَيْتُمْ السَّعْدَانَ قَالُوا نَعَمْ يَا رَسُولَ اللَّهِ قَالَ فَإِنَّهَا مِثْلُ شَوْكِ السَّعْدَانِ غَيْرَ أَنَّهُ لَا يَعْلَمُ مَا قَدْرُ عِظَمِهَا إِلَّا اللَّهُ تَخْطَفُ النَّاسَ بِأَعْمَالِهِمْ فَمِنْهُمْ الْمُوبَقُ بَقِيَ بِعَمَلِهِ أَوْ الْمُوثَقُ بِعَمَلِهِ وَمِنْهُمْ الْمُخَرْدَلُ أَوْ الْمُجَازَى أَوْ نَحْوُهُ ثُمَّ يَتَجَلَّى حَتَّى إِذَا فَرَغَ اللَّهُ مِنْ الْقَضَاءِ بَيْنَ الْعِبَادِ وَأَرَادَ أَنْ يُخْرِجَ بِرَحْمَتِهِ مَنْ أَرَادَ مِنْ أَهْلِ النَّارِ أَمَرَ الْمَلَائِكَةَ أَنْ يُخْرِجُوا مِنْ النَّارِ مَنْ كَانَ لَا يُشْرِكُ بِاللَّهِ شَيْئًا مِمَّنْ أَرَادَ اللَّهُ أَنْ يَرْحَمَهُ مِمَّنْ يَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ فَيَعْرِفُونَهُمْ فِي النَّارِ بِأَثَرِ السُّجُودِ تَأْكُلُ النَّارُ ابْنَ آدَمَ إِلَّا أَثَرَ السُّجُودِ حَرَّمَ اللَّهُ عَلَى النَّارِ أَنْ تَأْكُلَ أَثَرَ السُّجُودِ فَيَخْرُجُونَ مِنْ النَّارِ قَدْ امْتُحِشُوا فَيُصَبُّ عَلَيْهِمْ مَاءُ الْحَيَاةِ فَيَنْبُتُونَ تَحْتَهُ كَمَا تَنْبُتُ الْحِبَّةُ فِي حَمِيلِ السَّيْلِ ثُمَّ يَفْرُغُ اللَّهُ مِنْ الْقَضَاءِ بَيْنَ الْعِبَادِ وَيَبْقَى رَجُلٌ مِنْهُمْ مُقْبِلٌ بِوَجْهِهِ عَلَى النَّارِ هُوَ آخِرُ أَهْلِ النَّارِ دُخُولًا الْجَنَّةَ فَيَقُولُ أَيْ رَبِّ اصْرِفْ وَجْهِي عَنْ النَّارِ فَإِنَّهُ قَدْ قَشَبَنِي رِيحُهَا وَأَحْرَقَنِي ذَكَاؤُهَا فَيَدْعُو اللَّهَ بِمَا شَاءَ أَنْ يَدْعُوَهُ ثُمَّ يَقُولُ اللَّهُ هَلْ عَسَيْتَ إِنْ أَعْطَيْتُكَ ذَلِكَ أَنْ تَسْأَلَنِي غَيْرَهُ فَيَقُولُ لَا وَعِزَّتِكَ لَا أَسْأَلُكَ غَيْرَهُ وَيُعْطِي رَبَّهُ مِنْ عُهُودٍ وَمَوَاثِيقَ مَا شَاءَ فَيَصْرِفُ اللَّهُ وَجْهَهُ عَنْ النَّارِ فَإِذَا أَقْبَلَ عَلَى الْجَنَّةِ وَرَآهَا سَكَتَ مَا شَاءَ اللَّهُ أَنْ يَسْكُتَ ثُمَّ يَقُولُ أَيْ رَبِّ قَدِّمْنِي إِلَى بَابِ الْجَنَّةِ فَيَقُولُ اللَّهُ لَهُ أَلَسْتَ قَدْ أَعْطَيْتَ عُهُودَكَ وَمَوَاثِيقَكَ أَنْ لَا تَسْأَلَنِي غَيْرَ الَّذِي أُعْطِيتَ أَبَدًا وَيْلَكَ يَا ابْنَ آدَمَ مَا أَغْدَرَكَ فَيَقُولُ أَيْ رَبِّ وَيَدْعُو اللَّهَ حَتَّى يَقُولَ هَلْ عَسَيْتَ إِنْ أُعْطِيتَ ذَلِكَ أَنْ تَسْأَلَ غَيْرَهُ فَيَقُولُ لَا وَعِزَّتِكَ لَا أَسْأَلُكَ غَيْرَهُ وَيُعْطِي مَا شَاءَ مِنْ عُهُودٍ وَمَوَاثِيقَ فَيُقَدِّمُهُ إِلَى بَابِ الْجَنَّةِ فَإِذَا قَامَ إِلَى بَابِ الْجَنَّةِ انْفَهَقَتْ لَهُ الْجَنَّةُ فَرَأَى مَا فِيهَا مِنْ الْحَبْرَةِ وَالسُّرُورِ فَيَسْكُتُ مَا شَاءَ اللَّهُ أَنْ يَسْكُتَ ثُمَّ يَقُولُ أَيْ رَبِّ أَدْخِلْنِي الْجَنَّةَ فَيَقُولُ اللَّهُ أَلَسْتَ قَدْ أَعْطَيْتَ عُهُودَكَ وَمَوَاثِيقَكَ أَنْ لَا تَسْأَلَ غَيْرَ مَا أُعْطِيتَ فَيَقُولُ وَيْلَكَ يَا ابْنَ آدَمَ مَا أَغْدَرَكَ فَيَقُولُ أَيْ رَبِّ لَا أَكُونَنَّ أَشْقَى خَلْقِكَ فَلَا يَزَالُ يَدْعُو حَتَّى يَضْحَكَ اللَّهُ مِنْهُ فَإِذَا ضَحِكَ مِنْهُ قَالَ لَهُ ادْخُلْ الْجَنَّةَ فَإِذَا دَخَلَهَا قَالَ اللَّهُ لَهُ تَمَنَّهْ فَسَأَلَ رَبَّهُ وَتَمَنَّى حَتَّى إِنَّ اللَّهَ لَيُذَكِّرُهُ يَقُولُ كَذَا وَكَذَا حَتَّى انْقَطَعَتْ بِهِ الْأَمَانِيُّ قَالَ اللَّهُ ذَلِكَ لَكَ وَمِثْلُهُ مَعَهُقَالَ عَطَاءُ بْنُ يَزِيدَ وَأَبُو سَعِيدٍ الْخُدْرِيُّ مَعَ أَبِي هُرَيْرَةَ لَا يَرُدُّ عَلَيْهِ مِنْ حَدِيثِهِ شَيْئًا حَتَّى إِذَا حَدَّثَ أَبُو هُرَيْرَةَ أَنَّ اللَّهَ تَبَارَكَ وَتَعَالَى قَالَ ذَلِكَ لَكَ وَمِثْلُهُ مَعَهُ قَالَ أَبُو سَعِيدٍ الْخُدْرِيُّ وَعَشَرَةُ أَمْثَالِهِ مَعَهُ يَا أَبَا هُرَيْرَةَ قَالَ أَبُو هُرَيْرَةَ مَا حَفِظْتُ إِلَّا قَوْلَهُ ذَلِكَ لَكَ وَمِثْلُهُ مَعَهُ قَالَ أَبُو سَعِيدٍ الْخُدْرِيُّ أَشْهَدُ أَنِّي حَفِظْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَوْلَهُ ذَلِكَ لَكَ وَعَشَرَةُ أَمْثَالِهِ قَالَ أَبُو هُرَيْرَةَ فَذَلِكَ الرَّجُلُ آخِرُ أَهْلِ الْجَنَّةِ دُخُولًا الْجَنَّةَ","id":"Telah menceritakan kepada kami ['Abdul Aziz bin Abdullah] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibn Syihab] dari ['Atha' bin Yazid allaitsi] dari [Abu Hurairah] para sahabat bertanya, 'Wahai Rasulullah, apakah kami akan melihat Tuhan kami pada hari kiamat nanti? ' Rasulullah Shallallahu'alaihiwasallam lantas bersabda: \"Apakah kalian kesulitan melihat bulan ketika malam purnama?\" \"Tidak\", Jawab para sahabat. Rasulullah bertanya lagi: \"Apakah kalian kesulitan melihat matahari ketika tidak ada mendung?\" Para sahabat menjawab, \"Tidak ya Rasulullah.\" Nabi bersabda: \"Sesungguhnya kalian akan melihat-Nya demikian pula Allah akan mengumpulkan manusia pada hari kiamat dan berfirman: 'Barangsiapa menyembah sesuatu, hendaklah ia mengikuti yang disembahnya.' Maka siapa yang menyembah matahari, ia mengikuti matahari, siapa yang menyembah bulan, ia ikuti bulan, siapa yang menyembah thaghut, ia ikuti thaghut, dan tersisalah dari umat ini orang penolongnya atau justru orang-orang munafiknya -Ibrahim ragu kepastian redaksinya-. Lantas Allah menemui mereka dan berkata, \"Aku Tuhan kalian.\" Lantas mereka menjawab, \"Ini adalah tempat tinggal kami sehingga Tuhan kami mendatangi kami, jika Tuhan kami menemui kami, niscaya kami mengenalnya.\" Allah kemudian menemui mereka dengan bentuk yang mereka kenal, Allah lalu berfirman: \"Aku Tuhan kalian.\" Lantas mereka katakan, \"Engkau memang Tuhan kami.\" Mereka pun mengikuti-Nya. Titian (jembatan) lantas dipasang antara dua tepi jahanam dan aku dan umatkulah yang pertama-tama menyeberangimnya. Tak ada yang berani bicara ketika itu selain para rasul, sedang seruan para rasul ketika itu yang ada hanyalah 'Allaahumma sallim sallim (Ya Allah, selamatkan kami. Ya Allah, selamatkan kami) '. Sedang di neraka jahannam terdapat besi-besi pengait seperti duri pohon berduri yang namanya Sa'dan. Bukankah kalian sudah tahu pohon berduri Sa'dan?\" Para sahabat menjawab, \"Benar, wahai Rasulullah.\" Nabi meneruskan: \"Sungguh pohon itu semisal pohon berduri Sa'dan, hanya tidak ada yang tahu kadar besarnya selain Allah semata. Pohon itu menculik siapa saja sesuai kadar amal mereka, ada diantara mereka yang celaka dengan sisa amalnya atau terikat dengan amalnya, diantara mereka ada yang binasa yang langgeng dengan amalnya atau terikat dengan amalnya, diantara mereka ada yang diseberangkan. Atau dengan redaksi semisal-. Kemudian Allah menampakkan diri, hingga jika Allah selesai memutuskan nasib hamba-Nya dan ingin mengeluarkan penghuni neraka karena rahmat-Nya, Ia perintahkan malaikat untuk mengeluarkan penghuni neraka siapa saja yang tidak menyekutukan Allah dengan sesuatu apapun, yaitu diantara mereka yang Dia masih ingin merahmatinya, diantara yang bersyahadat bahwasanya tiada sesembahan yang hak selain Allah, sehingga malaikat mengenal mereka di neraka dari bekas-bekas sujud, sebab neraka memangsa anak adam selain bekas-bekas sujud. Allah mengharamkan neraka memangsa bekas-bekas sujud, sehingga mereka keluar dari neraka dengan badan yang hangus terbakar, mereka kemudian disiram dengan air kehidupan sehingga tumbuh dibawahnya sebagaimana biji-bijian tumbuh dalam aliran sungai, kemudian Allah selesai memutuskan hamba-hamba-Nya dan tersisa diantara mereka seseorang yang menghadapkan wajahnya ke neraka, dan dialah mantan penghuni neraka yang terakhir kali masuk surga, kecuali ia berdoa, 'Ya Tuhan, palingkanlah wajahku dari neraka, sebab baunya saja sudah cukup menggangguku dan jilatan apinya telah membakarku.' Orang itu kemudian memohon kepada Allah sekehendaknya untuk berdoa, kemudian Allah berfirman: 'Kalaulah Aku memenuhi permintaanmu, jangan-jangan engkau nanti meminta harapan lain! Ia menjawab, 'Tidak, demi kemuliaan-Mu, saya tidak akan meminta selainnya.' Dan Tuhannya pun mengambil janji dan ikrar sekehendak-Nya lalu memalingkan wajahnya dari neraka. Namun kemudian ia menghadap surga dan melihat keindahan surga, ia pun lantas terdiam beberapa saat dan memohon, 'Ya Allah, jadikanlah aku berada di pintu surga.' Allah bertanya: 'Bukankah engkau telah menyerahkan janjimu dan ikrarmu untuk tidak meminta-Ku selama-lamanya selain yang telah Aku berikan. Hai engkau Anak Adam, alangkah senangnya engkau berkhianat.' Namun hamba itu tetap saja memohon, 'Ya Tuhanku, ' dan ia terus memohon Allah hingga Allah bertanya: 'Kalaulah Aku memberimu apa yang kau minta sekarang, jangan-jangan engkau minta lagi dengan permintaan lain.' Ia menjawab, 'Tidak, demi kemuliaan-Mu, saya tidak akan meminta-Mu lagi dengan permintaan lain.' Lantas orang itu menyerahkan janji dan ikrarnya sehingga Allah mengajukan ke pintu surga. Namun ketika hamba itu telah berdiri ke pintu surga, surga terbuka baginya sehingga ia melihat kesenangan hidup dan kegembiraan di dalamnya sehingga ia terdiam sekehendak Allah ia diam. Kemudian ia memohon, 'Ya Tuhanku, masukkanlah aku dalam surga, maka Allah mengatakan, 'Hai, bukankah telah engkau serahkan janjimu untuk tidak meminta yang lain selain yang telah Aku berikan, wahai Anak Adam, alangkah cepatnya engkau berkhianat.' Maka si hamba tadi memohon, 'Ya Tuhanku, jangan aku menjadi hamba-Mu yang paling sengsara, ' si hamba itu terus tiada henti memohon hingga Allah tertawa. Dan jika Allah telah tertawa kepada seorang hamba, Allah musti berkata kepadanya 'Masuklah kamu ke surga.' Jika si hamba telah memasukinya, Allah berkata kepadanya: 'Tolong buatlah impian'. Maka si hamba meminta Tuhannya dan membuat impian-impian, hingga Allah mengingatkannya dengan berfirman sedemikian-sedemikian hingga impian si hamba sudah sampai puncaknya, Allah berfirman kepadanya: 'Itu semua untukku, dan ditambah seperti itu pula.' ['Atha' bin Yazid] berkata, \" [Abu Sa'id alkhudzri] bersama Abu Hurairah tidak mengembalikan sedikitpun hadisnya, hingga jika Abu Hurairah telah menceritakan bahwa Allah berfirman 'dan bagimu semisalnya', Abu Sa'id Al Khudzri berkata 'dan sepuluh semisalnya bersamanya' wahai Abu Hurairah? ' Abu Hurairah berkata, 'Saya tidak hapal selain ucapannya itu 'bagimu dan semisalnya'. Abu Sa'id Al Khudzri berkata lagi, \"Saya bersaksi bahwa saya menghapalnya dari Rasulullah Shallallahu'alaihiwasallam, yaitu redaksi 'Dan bagimu sepuluh semisalnya'. Abu Hurairah berkata, 'Itulah manusia terakhir kali masuk surga.'"},"6533":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ زَيْدٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقُلْنَا يَا رَسُولَ اللَّهِ هَلْ نَرَى رَبَّنَا يَوْمَ الْقِيَامَةِ قَالَ هَلْ تُضَارُونَ فِي رُؤْيَةِ الشَّمْسِ وَالْقَمَرِ إِذَا كَانَتْ صَحْوًا قُلْنَا لَا قَالَ فَإِنَّكُمْ لَا تُضَارُونَ فِي رُؤْيَةِ رَبِّكُمْ يَوْمَئِذٍ إِلَّا كَمَا تُضَارُونَ فِي رُؤْيَتِهِمَا ثُمَّ قَالَ يُنَادِي مُنَادٍ لِيَذْهَبْ كُلُّ قَوْمٍ إِلَى مَا كَانُوا يَعْبُدُونَ فَيَذْهَبُ أَصْحَابُ الصَّلِيبِ مَعَ صَلِيبِهِمْ وَأَصْحَابُ الْأَوْثَانِ مَعَ أَوْثَانِهِمْ وَأَصْحَابُ كُلِّ آلِهَةٍ مَعَ آلِهَتِهِمْ حَتَّى يَبْقَى مَنْ كَانَ يَعْبُدُ اللَّهَ مِنْ بَرٍّ أَوْ فَاجِرٍ وَغُبَّرَاتٌ مِنْ أَهْلِ الْكِتَابِ ثُمَّ يُؤْتَى بِجَهَنَّمَ تُعْرَضُ كَأَنَّهَا سَرَابٌ فَيُقَالُ لِلْيَهُودِ مَا كُنْتُمْ تَعْبُدُونَ قَالُوا كُنَّا نَعْبُدُ عُزَيْرَ ابْنَ اللَّهِ فَيُقَالُ كَذَبْتُمْ لَمْ يَكُنْ لِلَّهِ صَاحِبَةٌ وَلَا وَلَدٌ فَمَا تُرِيدُونَ قَالُوا نُرِيدُ أَنْ تَسْقِيَنَا فَيُقَالُ اشْرَبُوا فَيَتَسَاقَطُونَ فِي جَهَنَّمَ ثُمَّ يُقَالُ لِلنَّصَارَى مَا كُنْتُمْ تَعْبُدُونَ فَيَقُولُونَ كُنَّا نَعْبُدُ الْمَسِيحَ ابْنَ اللَّهِ فَيُقَالُ كَذَبْتُمْ لَمْ يَكُنْ لِلَّهِ صَاحِبَةٌ وَلَا وَلَدٌ فَمَا تُرِيدُونَ فَيَقُولُونَ نُرِيدُ أَنْ تَسْقِيَنَا فَيُقَالُ اشْرَبُوا فَيَتَسَاقَطُونَ فِي جَهَنَّمَ حَتَّى يَبْقَى مَنْ كَانَ يَعْبُدُ اللَّهَ مِنْ بَرٍّ أَوْ فَاجِرٍ فَيُقَالُ لَهُمْ مَا يَحْبِسُكُمْ وَقَدْ ذَهَبَ النَّاسُ فَيَقُولُونَ فَارَقْنَاهُمْ وَنَحْنُ أَحْوَجُ مِنَّا إِلَيْهِ الْيَوْمَ وَإِنَّا سَمِعْنَا مُنَادِيًا يُنَادِي لِيَلْحَقْ كُلُّ قَوْمٍ بِمَا كَانُوا يَعْبُدُونَ وَإِنَّمَا نَنْتَظِرُ رَبَّنَا قَالَ فَيَأْتِيهِمْ الْجَبَّارُ فِي صُورَةٍ غَيْرِ صُورَتِهِ الَّتِي رَأَوْهُ فِيهَا أَوَّلَ مَرَّةٍ فَيَقُولُ أَنَا رَبُّكُمْ فَيَقُولُونَ أَنْتَ رَبُّنَا فَلَا يُكَلِّمُهُ إِلَّا الْأَنْبِيَاءُ فَيَقُولُ هَلْ بَيْنَكُمْ وَبَيْنَهُ آيَةٌ تَعْرِفُونَهُ فَيَقُولُونَ السَّاقُ فَيَكْشِفُ عَنْ سَاقِهِ فَيَسْجُدُ لَهُ كُلُّ مُؤْمِنٍ وَيَبْقَى مَنْ كَانَ يَسْجُدُ لِلَّهِ رِيَاءً وَسُمْعَةً فَيَذْهَبُ كَيْمَا يَسْجُدَ فَيَعُودُ ظَهْرُهُ طَبَقًا وَاحِدًا ثُمَّ يُؤْتَى بِالْجَسْرِ فَيُجْعَلُ بَيْنَ ظَهْرَيْ جَهَنَّمَ قُلْنَا يَا رَسُولَ اللَّهِ وَمَا الْجَسْرُ قَالَ مَدْحَضَةٌ مَزِلَّةٌ عَلَيْهِ خَطَاطِيفُ وَكَلَالِيبُ وَحَسَكَةٌ مُفَلْطَحَةٌ لَهَا شَوْكَةٌ عُقَيْفَاءُ تَكُونُ بِنَجْدٍ يُقَالُ لَهَا السَّعْدَانُ الْمُؤْمِنُ عَلَيْهَا كَالطَّرْفِ وَكَالْبَرْقِ وَكَالرِّيحِ وَكَأَجَاوِيدِ الْخَيْلِ وَالرِّكَابِ فَنَاجٍ مُسَلَّمٌ وَنَاجٍ مَخْدُوشٌ وَمَكْدُوسٌ فِي نَارِ جَهَنَّمَ حَتَّى يَمُرَّ آخِرُهُمْ يُسْحَبُ سَحْبًا فَمَا أَنْتُمْ بِأَشَدَّ لِي مُنَاشَدَةً فِي الْحَقِّ قَدْ تَبَيَّنَ لَكُمْ مِنْ الْمُؤْمِنِ يَوْمَئِذٍ لِلْجَبَّارِ وَإِذَا رَأَوْا أَنَّهُمْ قَدْ نَجَوْا فِي إِخْوَانِهِمْ يَقُولُونَ رَبَّنَا إِخْوَانُنَا كَانُوا يُصَلُّونَ مَعَنَا وَيَصُومُونَ مَعَنَا وَيَعْمَلُونَ مَعَنَا فَيَقُولُ اللَّهُ تَعَالَى اذْهَبُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ دِينَارٍ مِنْ إِيمَانٍ فَأَخْرِجُوهُ وَيُحَرِّمُ اللَّهُ صُوَرَهُمْ عَلَى النَّارِ فَيَأْتُونَهُمْ وَبَعْضُهُمْ قَدْ غَابَ فِي النَّارِ إِلَى قَدَمِهِ وَإِلَى أَنْصَافِ سَاقَيْهِ فَيُخْرِجُونَ مَنْ عَرَفُوا ثُمَّ يَعُودُونَ فَيَقُولُ اذْهَبُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ نِصْفِ دِينَارٍ فَأَخْرِجُوهُ فَيُخْرِجُونَ مَنْ عَرَفُوا ثُمَّ يَعُودُونَ فَيَقُولُ اذْهَبُوا فَمَنْ وَجَدْتُمْ فِي قَلْبِهِ مِثْقَالَ ذَرَّةٍ مِنْ إِيمَانٍ فَأَخْرِجُوهُ فَيُخْرِجُونَ مَنْ عَرَفُوا قَالَ أَبُو سَعِيدٍ فَإِنْ لَمْ تُصَدِّقُونِي فَاقْرَءُوا{ إِنَّ اللَّهَ لَا يَظْلِمُ مِثْقَالَ ذَرَّةٍ وَإِنْ تَكُ حَسَنَةً يُضَاعِفْهَا }فَيَشْفَعُ النَّبِيُّونَ وَالْمَلَائِكَةُ وَالْمُؤْمِنُونَ فَيَقُولُ الْجَبَّارُ بَقِيَتْ شَفَاعَتِي فَيَقْبِضُ قَبْضَةً مِنْ النَّارِ فَيُخْرِجُ أَقْوَامًا قَدْ امْتُحِشُوا فَيُلْقَوْنَ فِي نَهَرٍ بِأَفْوَاهِ الْجَنَّةِ يُقَالُ لَهُ مَاءُ الْحَيَاةِ فَيَنْبُتُونَ فِي حَافَتَيْهِ كَمَا تَنْبُتُ الْحِبَّةُ فِي حَمِيلِ السَّيْلِ قَدْ رَأَيْتُمُوهَا إِلَى جَانِبِ الصَّخْرَةِ وَإِلَى جَانِبِ الشَّجَرَةِ فَمَا كَانَ إِلَى الشَّمْسِ مِنْهَا كَانَ أَخْضَرَ وَمَا كَانَ مِنْهَا إِلَى الظِّلِّ كَانَ أَبْيَضَ فَيَخْرُجُونَ كَأَنَّهُمْ اللُّؤْلُؤُ فَيُجْعَلُ فِي رِقَابِهِمْ الْخَوَاتِيمُ فَيَدْخُلُونَ الْجَنَّةَ فَيَقُولُ أَهْلُ الْجَنَّةِ هَؤُلَاءِ عُتَقَاءُ الرَّحْمَنِ أَدْخَلَهُمْ الْجَنَّةَ بِغَيْرِ عَمَلٍ عَمِلُوهُ وَلَا خَيْرٍ قَدَّمُوهُ فَيُقَالُ لَهُمْ لَكُمْ مَا رَأَيْتُمْ وَمِثْلَهُ مَعَهُوَقَالَ حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُحْبَسُ الْمُؤْمِنُونَ يَوْمَ الْقِيَامَةِ حَتَّى يُهِمُّوا بِذَلِكَ فَيَقُولُونَ لَوْ اسْتَشْفَعْنَا إِلَى رَبِّنَا فَيُرِيحُنَا مِنْ مَكَانِنَا فَيَأْتُونَ آدَمَ فَيَقُولُونَ أَنْتَ آدَمُ أَبُو النَّاسِ خَلَقَكَ اللَّهُ بِيَدِهِ وَأَسْكَنَكَ جَنَّتَهُ وَأَسْجَدَ لَكَ مَلَائِكَتَهُ وَعَلَّمَكَ أَسْمَاءَ كُلِّ شَيْءٍ لِتَشْفَعْ لَنَا عِنْدَ رَبِّكَ حَتَّى يُرِيحَنَا مِنْ مَكَانِنَا هَذَا قَالَ فَيَقُولُ لَسْتُ هُنَاكُمْ قَالَ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ أَكْلَهُ مِنْ الشَّجَرَةِ وَقَدْ نُهِيَ عَنْهَا وَلَكِنْ ائْتُوا نُوحًا أَوَّلَ نَبِيٍّ بَعَثَهُ اللَّهُ إِلَى أَهْلِ الْأَرْضِ فَيَأْتُونَ نُوحًا فَيَقُولُ لَسْتُ هُنَاكُمْ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ سُؤَالَهُ رَبَّهُ بِغَيْرِ عِلْمٍ وَلَكِنْ ائْتُوا إِبْرَاهِيمَ خَلِيلَ الرَّحْمَنِ قَالَ فَيَأْتُونَ إِبْرَاهِيمَ فَيَقُولُ إِنِّي لَسْتُ هُنَاكُمْ وَيَذْكُرُ ثَلَاث�� كَلِمَاتٍ كَذَبَهُنَّ وَلَكِنْ ائْتُوا مُوسَى عَبْدًا آتَاهُ اللَّهُ التَّوْرَاةَ وَكَلَّمَهُ وَقَرَّبَهُ نَجِيًّا قَالَ فَيَأْتُونَ مُوسَى فَيَقُولُ إِنِّي لَسْتُ هُنَاكُمْ وَيَذْكُرُ خَطِيئَتَهُ الَّتِي أَصَابَ قَتْلَهُ النَّفْسَ وَلَكِنْ ائْتُوا عِيسَى عَبْدَ اللَّهِ وَرَسُولَهُ وَرُوحَ اللَّهِ وَكَلِمَتَهُ قَالَ فَيَأْتُونَ عِيسَى فَيَقُولُ لَسْتُ هُنَاكُمْ وَلَكِنْ ائْتُوا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدًا غَفَرَ اللَّهُ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَا تَأَخَّرَ فَيَأْتُونِي فَأَسْتَأْذِنُ عَلَى رَبِّي فِي دَارِهِ فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي فَيَقُولُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ وَسَلْ تُعْطَ قَالَ فَأَرْفَعُ رَأْسِي فَأُثْنِي عَلَى رَبِّي بِثَنَاءٍ وَتَحْمِيدٍ يُعَلِّمُنِيهِ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأَخْرُجُ فَأُدْخِلُهُمْ الْجَنَّةَ قَالَ قَتَادَةُ وَسَمِعْتُهُ أَيْضًا يَقُولُ فَأَخْرُجُ فَأُخْرِجُهُمْ مِنْ النَّارِ وَأُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَعُودُ الثَّانِيَةَ فَأَسْتَأْذِنُ عَلَى رَبِّي فِي دَارِهِ فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي ثُمَّ يَقُولُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ وَسَلْ تُعْطَ قَالَ فَأَرْفَعُ رَأْسِي فَأُثْنِي عَلَى رَبِّي بِثَنَاءٍ وَتَحْمِيدٍ يُعَلِّمُنِيهِ قَالَ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأَخْرُجُ فَأُدْخِلُهُمْ الْجَنَّةَ قَالَ قَتَادَةُ وَسَمِعْتُهُ يَقُولُ فَأَخْرُجُ فَأُخْرِجُهُمْ مِنْ النَّارِ وَأُدْخِلُهُمْ الْجَنَّةَ ثُمَّ أَعُودُ الثَّالِثَةَ فَأَسْتَأْذِنُ عَلَى رَبِّي فِي دَارِهِ فَيُؤْذَنُ لِي عَلَيْهِ فَإِذَا رَأَيْتُهُ وَقَعْتُ سَاجِدًا فَيَدَعُنِي مَا شَاءَ اللَّهُ أَنْ يَدَعَنِي ثُمَّ يَقُولُ ارْفَعْ مُحَمَّدُ وَقُلْ يُسْمَعْ وَاشْفَعْ تُشَفَّعْ وَسَلْ تُعْطَهْ قَالَ فَأَرْفَعُ رَأْسِي فَأُثْنِي عَلَى رَبِّي بِثَنَاءٍ وَتَحْمِيدٍ يُعَلِّمُنِيهِ قَالَ ثُمَّ أَشْفَعُ فَيَحُدُّ لِي حَدًّا فَأَخْرُجُ فَأُدْخِلُهُمْ الْجَنَّةَ قَالَ قَتَادَةُ وَقَدْ سَمِعْتُهُ يَقُولُ فَأَخْرُجُ فَأُخْرِجُهُمْ مِنْ النَّارِ وَأُدْخِلُهُمْ الْجَنَّةَ حَتَّى مَا يَبْقَى فِي النَّارِ إِلَّا مَنْ حَبَسَهُ الْقُرْآنُ أَيْ وَجَبَ عَلَيْهِ الْخُلُودُ قَالَ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ عَسَى أَنْ يَبْعَثَكَ رَبُّكَ مَقَامًا مَحْمُودًا }قَالَ وَهَذَا الْمَقَامُ الْمَحْمُودُ الَّذِي وُعِدَهُ نَبِيُّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Allaits bin Sa'd] dari [Khalid bin Yazid] dari [Sa'id bin Abu Hilal] dari [Zaid] dari ['Atha' bin Yasar] dari [Abu Sa'id Al Khudzri] berkata, \"Kami bertanya, \"Ya Rasulullah, apakah kita akan melihat Tuhan kita pada hari kiamat?\" Nabi balik bertanya: \"Apakah kalian merasa kesulitan melihat matahari dan bulan ketika terang benderang?\" kami menjawab, \"Tidak.\" Nabi meneruskan: \"Begitulah kalian tidak kesulitan melihat melihat Tuhan kalian ketika itu, selain sebagaimana kesulitan kalian melihat keduanya.\" Kemudian beliau berkata: \"Lantas ada seorang penyeru memanggil-manggil, \"Hendaklah setiap kaum pergi menemui yang disembahnya!\" Maka pemuja salib pergi bersama salib mereka, dan pemuja patung menemui patung-patung mereka, dan setiap pemuja Tuhan bersama tuhan-tuhan mereka hingga tinggal orang-orang yang menyembah Allah, entah baik atau durhaka dan ahli kitab terdahulu. Kemudian jahannam didatangkan dan dipasang, ia seolah-olah fatamorgana, lantas orang-orang yahudi ditanya, \"Apa yang dahulu kalian sembah?\" Mereka menjawab, \"Kami dahulu menyembah Uzair anak Allah.\" Lalu ada suara, \"Kalian dusta! Allah sama sekali tidak mempunyai isteri dan tidak pula anak.\" Lalu apa yang kalian inginkan?\" Mereka menjawab, \"Kami ingin jika Engkau memberi kami minuman!\" Lantas ada suara, \"Minumlah kalian!\" Lalu mereka berjatuhan di neraka jahannam. Lantas orang-orang Nashara diseru, \"Apa yang kalian dahulu sembah?\" Mereka menjawab, \"Kami dahulu menyembah Isa al Masih, anak Anak Allah.\" Mereka dijawab, \"Kamu semua bohong! Allah sama sekali tidak mempunyai isteri atau bahkan anak, dan apa yang kalian inginkan?\" Mereka menjawab, \"Kami ingin agar Engkau memberi kami minuman!\" Lalu dijawab, \"Minumlah kalian!\" Dan langsung mereka berjatuhan di neraka jahannam hingga tersisa manusia yang menyembah Allah, entah yang baik atau berbuat durhaka. Mereka ditanya, \"Apa yang menyebabkan kalian tertahan padahal manusia lainnya sudah pergi?\" Mereka menjawab, \"Kami memisahkan diri dari mereka dan kami adalah manusia yang paling membutuhkan-Nya, kami dengar ada seorang juru seru menyerukan diri, \"Hendaklah setiap kaum menemui yang mereka sembah! Hanyasanya kami menunggu-nunggu Tuhan kami.\" Beliau melanjutkan, \"Lantas Allah (Al jabbar) mendatangi mereka dengan bentuk yang belum pernah mereka lihat pertama kali, lalu Allah firmankan: 'Akulah Tuhan kalian.' Mereka menjawab, 'Engkau adalah rabb kami, dan tidak ada yang berani mengajak-Nya bicara selain para nabi shallallahu 'alaihi wasallam, lantas para nabi berkata, 'Bukankah di antara kalian dan Allah ada tanda yang kalian mengenalnya? ' Mereka menjawab, 'Ya, yaitu betis, ' maka Allah pun menyingkap betis-Nya sehingga setiap mukmin bersujud kepada-Nya. Lalu tersisalah orang-orang yang sujud kepada Allah karena riya dan sum'ah sehingga ia pergi sujud dan punggungnya kembali menjadi satu bagian, kemudian titian (jembatan) jahannam didatangkan dan dipasang antara dua tepi jahannam, kami bertanya, 'Wahai Rasulullah, memang jembatan jahannam tersebut misterinya apa? ' Nabi menjawab: 'Jembatan itu bisa menggelincirkan, menjatuhkan, ada pengait-pengait besi, ada duri-duri yang lebar dan tajam, durinya besok yang terbuat dari kayu berduri namanya Sa'dan (kayu berduri tajam). Orang mukmin yang melewatinya sedemikian cepat, ada yang bagaikan kedipan mata, ada yang bagaikan kilat, ada yang bagaikan angin, dan ada yang bagaikan kuda pilihan. Ada yang bagaikan kuda tunggangan, ada yang selamat dengan betul-betul terselamatkan, namun ada juga yang selamat setelah tercabik-cabik oleh besi-besi pengait itu, atau terlempar karenanya di neraka jahannam, hingga manusia terakhir kali melewati dengan diseret seret, dan kalian tidak bisa sedemikian gigihnya menyumpahiku terhadap kebenaran yang jelas bagi kalian daripada terhadap seorang mukmin ketika itu kepada Allah Al Jabbar. Jika mereka melihat bahwasanya mereka telah selamat di kalangan teman-teman mereka, mereka berkata, 'Ya Tuhan kami, sesungguhnya kawan-kawan kami mendirikn shalat bersama kami dan berpuasa bersama kami, dan beramal bersama kami! ' Allah Ta'ala berfirman, 'Pergilah kalian, siapa diantara kalian dapatkan dalam hatinya masih ada seberat dinar keimanan, maka keluarkanlah dia', dan Allah mengharamkan bentuk mereka dalam neraka. Maka mereka datangi kawan-kawan mereka sedang sebagian mereka telah terendam dalam neraka ada yang sampai telapak kakinya, setengah betisnya, sehingga mereka keluarkan siapa saja yang mereka, kemudian mereka kembali dan Allah berkata, 'Pergilah kalian sekali lagi, dan siapa yang kalian temukan dalam hatinya seberat atom keimanan, maka keluarkanlah dia.' Maka mereka keluarkan siapa saja yang mereka kenal.\" Rasulullah berkata: 'Jika kalian tidak mempercayaiku, maka bacalah: '(Allah tidak menzhalimi seberat biji sawi pun, jika ada kebaikan, maka Allah melipatgandakan balasannya) ' (Qs. An nisaa': 40), maka para nabi shallallahu 'alaihi wasallam, malaikat dan orang-orang yang beriman, kesemuanya memberi syafaat. Kemudian Allah Al Jabbar berkata, syafaat-Ku masih ada. Lantas Allah menggenggam segenggam dari neraka dan mengentaskan beberapa kaum yang mereka telah terbakar, lantas mereka dilempar ke sebuah sungai di pintu surga yang namanya 'Sungai kehidupan' sehingga mereka tumbuh dalam kedua tepinya sebagaimana biji-bijian tumbuh dalam genangan sungai yang kalian sering melihatnya di samping batu karang dan samping pohon, apa yang diantaranya condong kepada matahari, maka berwarna hijau, dan apa yang diantaranya condong kepada bayangan, maka berwarna putih, lantas mereka muncul seolah-olah mutiara dan dalam tengkuk mereka terdapat cincin-cincin. Mereka kemudian masuk surga hingga penghuni surga berkata, 'Mereka adalah 'utaqa' Ar Rahman (orang-orang yang dibebaskan Arrahman), Allah memasukkan mereka bukan karena amal yang mereka lakukan, dan bukan pula karena kebaikan yang mereka persembahkan sehingga mereka memperoleh jawaban 'Bagimu yang kau lihat dan semisalnya'.\" [Hajjaj bin Minhal] berkata; telah menceritakan kepada kami [Hammam bin Yahya] telah menceritakan kepada kami [Qatadah] dari [Anas] radliyallahu'anhu, bahwa Nabi shallallahu 'alaihi wasallam bersabda: 'Pada hari kiamat nanti orang-orang mukmin ditahan hingga yang demikian menjadikan mereka sedih. Mereka katakan, 'Duh, sekiranya kita meminta syafaat kepada Tuhan kami sehingga Dia menjadikan kita merasa nyaman dari tempat kita ini.' Mereka pun mendatangi Adam dan berkata, 'Engkau hai Adam, Engkau adalah nenek moyang seluruh manusia, Allah menciptamu dengan tangan-Nya, menjadikan surga sebagai tempat hunianmu dan menjadikan malaikat bertunduk sujud kepadamu, Allah juga mengajarimu nama-nama segala sesuatu agar engkau bisa memberi syafaat kepada kami disisi Tuhanmu sehingga engkau bisa memberi kenyamanan di tempat kami ini. Namun Adam hanya menjawab, 'Disini saya tak berhak memberi syafaat untuk kalian'.\" Rasulullah melanjutkan: \"Lantas Adam mengingatkan kesalahan yang pernah dilakukannya, yaitu memakan pohon larangan padahal telah dilarang, dan ia katakan 'Coba kalian datangi Nuh, sebab ia adalah nabi shallallahu 'alaihi wasallam pertama-tama yang Allah utus kepada penduduk bumi.' Mereka pun mendatangi Nuh, namun Nuh juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', dan Nuh menyebutkan kesalahan yang pernah dilakukannya, yaitu bertanya kepada Rabbnya dengan tanpa ilmu sambil ia katakan, 'Cobalah kalian datangi Ibrahim, sebab ia adalah Khalilurrahman (kekasih Arrahman).\" Rasulullah melanjutkan lagi kisahnya: \"Mereka pun mendatangi Ibrahim, hanya Ibrahim juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', Ibrahim lantas menyebutkan kesalahannya, yaitu tiga kebohongan yang pernah dilakukannya sambil berkata, 'Cobalah kalian datangi Musa, seorang hamba yang Allah memberinya taurat, mengajaknya bicara dan mendekatkannya kepada-Nya sedekat-dekatnya'.\" Rasulullah lanjutkan: \"Mereka pun mendatangi Musa, hanya Musa juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', sambil Musa mengingatkan kesalahan yang pernah dilakukannya, yaitu membunuh jiwa tanpa alasan yang dibenarkan, sambil ia katakan, 'Coba kalian datangi Isa, seorang hamba Allah dan rasul-Nya, ruh Allah dan kalimah-Nya. Merekapun mendatangi Isa, namun 'Isa juga menjawab, 'Maaf, disini saya tak berhak memberi syafaat untuk kalian', sambil ia katakan 'Cobalah kalian datangi Muhammad Shallallahu'alaihiwasallam, seorang hamba yang Allah telah mengampuni dosanya yang terdahulu dan yang akan datang.' Lantas mereka mendatangi aku (Muhammad) dan aku meminta ijin Tuhanku di rumah-Nya dan aku diijinkan menemui-Nya, jika aku melihat-Nya, maka aku tersungkur sujud, Allah lalu membiarkan aku sekehendak Dia membiarkaku. Allah lantas berkata, 'Angkat kepalamu hai Muhammad, katakanlah, engkau didengar, mintailah syafaat, engkau diberi syafaat, mintalah, engkau diberi.' Aku lalu angkat kepalaku dan aku memuji Tuhanku dengan pujian yang Ia ajarkannya kepadaku, kemudian aku memberi syafaat dan Dia memberiku batasan. Kemudian aku keluar dan memasukkan mereka ke dalam surga.\" Qatadah berkata, \"Dan aku juga mendengarnya menyebutkan, \"Aku lalu keluar, kemudian aku keluarkan mereka dari neraka dan kumasukkan ke dalam surga. Setelah itu aku kembali untuk kali kedua dan aku meminta ijin Tuhanku di rumah-Nya dan aku diijinkan untuk menemui-Nya, jika aku melihat-Nya, maka aku tersungkur sujud. Allah lantas membiarkanku sekehendak Allah membiarkan, kemudian Allah berkata, 'Angkatlah kepalamu hai Muhammad dan katakanlah engkau akan didengar, dan berilah syafaat engkau akan diberi syafaat, dan mintalah engkau akan diberi.' Aku lalu angkat kepalaku dan memanjatkan pujian dan pujaan terhadap tuhanku sebagaimana yang diajakrkan-Nya kepadaku. Kemudian aku memberi syafaat, dan Ia memberiku batasan sehingga aku keluar dan aku masukkan mereka ke dalam surga.\" Qatadah berkata, \"Dan aku mendengarnya menyebutkan, \"Dan aku berangkat sehingga aku keluarkan mereka dari neraka, lalu mereka aku masukkan ke dalam surga.\" Qatadah berkata, \"Dan aku mendengarnya menyebutkan, 'Maka aku berangkat dan aku keluarkan mereka dari neraka, untuk kemudian aku masukkan mereka ke dalam surga, hingga tidak tersisa dalam neraka selain yang digi ditahan oleh alquran, atau maksudnya ia wajib abadi, kemudian beliau membaca ayat ini '(semoga Tuhanmu membangkitkankmu di tempat yang terpuji) ' (Qs. Al Isra': 79). Nabi mengatakan, \"Inilah maqam terpuji yang dijanjikan untuk nabi shallallahu 'alaihi wasallam kalian.\""},"6534":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ حَدَّثَنِي عَمِّي حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي أَنَسُ بْنُ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسَلَ إِلَى الْأَنْصَارِ فَجَمَعَهُمْ فِي قُبَّةٍ وَقَالَ لَهُمْ اصْبِرُوا حَتَّى تَلْقَوْا اللَّهَ وَرَسُولَهُ فَإِنِّي عَلَى الْحَوْضِ","id":"Telah menceritakan kepada kami [Ubaidullah bin Sa'd bin Ibrahim] telah menceritakan kepadaku [Pamanku] telah menceritakan kepada kami [Ayahku] dari [Shalih] dari [Ibn Syihab] berkata, telah menceritakan kepadaku [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengutus seorang utusan ke Anshar dan mengumpulkan mereka dalam sebuah kubah (rumah bundar terbuat dari tanah liat) dan berkata, 'Bersabarlah kalian hingga kalian bertemu Allah dan rasul-Nya, sebab aku nanti berada di telaga.'"},"6535":{"ar":"حَدَّثَنِي ثَابِتُ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ عَنْ سُلَيْمَانَ الْأَحْوَلِ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَهَجَّدَ مِنْ اللَّيْلِ قَالَ اللَّهُمَّ رَبَّنَا لَكَ الْحَمْدُ أَنْتَ قَيِّمُ السَّمَوَاتِ وَالْأَرْضِ وَلَكَ الْحَمْدُ أَنْتَ رَبُّ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ وَلَكَ الْحَمْدُ أَنْتَ نُورُ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ أَنْتَ الْحَقُّ وَقَوْلُكَ الْحَقُّ وَوَعْدُكَ الْحَقُّ وَلِقَاؤُكَ الْحَقُّ وَالْجَنَّةُ حَقٌّ وَالنَّارُ حَقٌّ وَالسَّاعَةُ حَقٌّ اللَّهُمَّ لَكَ أَسْلَمْتُ وَبِكَ آمَنْتُ وَعَلَيْكَ تَوَكَّلْتُ وَإِلَيْكَ خَاصَمْتُ وَبِكَ حَاكَمْتُ فَاغْفِرْ لِي مَا قَدَّمْتُ وَمَا أَخَّرْتُ وَأَسْرَرْتُ وَأَعْلَنْتُ وَمَا أَنْتَ أَعْلَمُ بِهِ مِنِّي لَا إِلَهَ إِلَّا أَنْتَقَالَ أَبُو عَبْد اللَّهِ قَالَ قَيْسُ بْنُ سَعْدٍ وَأَبُو الزُّبَيْرِ عَنْ طَاوُسٍ قَيَّامُ وَقَالَ مُجَاهِدٌ{ الْقَيُّومُ }الْقَائِمُ عَلَى كُلِّ شَيْءٍ وَقَرَأَ عُمَرُ الْقَيَّامُ وَكِلَاهُمَا مَدْحٌ","id":"Telah menceritakan kepadaku [Tsabit bin Muhammad] telah menceritakan kepada kami [Sufyan] dari [Ibn Juraij] dari [Sulaiman Al Ahwal] dari [Thawus] dari [Ibn Abbas] radliyallahu'anhuma berkata, \"Jika Nabi shallallahu 'alaihi wasallam tahajjud di malam hari, beliau memanjatkan doa: 'ALLAAHUMA RABBANA LAKAL HAMDU ANTA QAYYIMUS SAMAAWAATI WAL ARDLI, WALAKAL HAMDU ANTA RABBUS SAMAAWAATI WAL ARDLI WAMAN FIIHINNA, WALAKAL HAMDU ANTA NUURUS SAMAAWAATI WAL ARDLI WAMAN FIIHINNA, ANTAL HAQQ, WAQULUKAL HAQQ, WAWA'DUKAL HAQQ, WALIQAA'UKA HAQQ, WAL JANNATU HAQQ, WANNAARU HAQQ, WASSAA'ATU HAQ, ALLAAHUMMA LAKA ASLAMTU, WABIKA AMANTU WA'ALAIKA TAWAKKALTU, WAILAIKA KHAASHAMTU WABIKA HAKAMTU FAGHFIRLII MAA QADDAMTU WAMAA AKHKHARTU WA ASRARTU WA A'LANTU, WAMAA ANTA A'LAMU BIHI MINNII, LAA-ILAAHA ILLAA ANTA (Ya Allah Tuhan kami, bagi-Mu segala puji, Engkau adalah pengurus langit dan bumi, bagi-Mu segala puji, Engkau adalah pemelihara langit dan bumi dan semua penghuninya, bagi-Mu segala puji, Engkau adalah cahaya langit dan bumi dan semua penghuninya, Engkau adalah benar, firman-Mu benar, janji-Mu benar dan perjumpaan kepada-Mu benar, surga benar, neraka benar, kiamat benar, Ya Allah, kepada-Mu aku berserah, kepada-Mu aku beriman, kepada-Mu aku bertawakkal, karena-Mu aku memusuhi (musuh), kepada-Mu aku berhukum, maka ampunilah bagiku apa yang telah aku lakukan dan yang belum aku lakukan, apa yang kulakukan secara sembunyi-sembunyi dan apa yang kulakukan secara terang-terangan, dan apa yang Engkau lebih tahu terhadapnya daripadaku, tiada sesembahan yang hak selain Engkau) '. Abu Abdullah berkata, [Qais bin Sa'd] dan [Abu Zubair] berkata dari [Thawus] dengan redaksi 'Qayyaam' bukan qayyum, sedang Mujahid berkata, 'Alqayyum (dengan definitif al) yang maknanya mengurus segala sesuatu, sedang Umar juga berkata Alqayyaam, dan keduanya sama-sama pujian.\""},"6536":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنِي الْأَعْمَشُ عَنْ خَيْثَمَةَ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْكُمْ مِنْ أَحَدٍ إِلَّا سَيُكَلِّمُهُ رَبُّهُ لَيْسَ بَيْنَهُ وَبَيْنَهُ تُرْجُمَانٌ وَلَا حِجَابٌ يَحْجُبُهُ","id":"Telah menceritakan kepada kami [Yusuf bin Musa] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepadaku [Al A'masy] dari [Khaitsumah] dari ['Adi bin Hatim] berkata, 'Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah salah seorang diantara kalian kecuali ia akan diajak bicara oleh Rabbnya, antara dia dan Allah tidak ada seorang penerjemah, dan tidak pula hijab yang menghalanginya.\""},"6537":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ الصَّمَدِ عَنْ أَبِي عِمْرَانَ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ اللَّهِ بْنِ قَيْسٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جَنَّتَانِ مِنْ فِضَّةٍ آنِيَتُهُمَا وَمَا فِيهِمَا وَجَنَّتَانِ مِنْ ذَهَبٍ آنِيَتُهُمَا وَمَا فِيهِمَا وَمَا بَيْنَ الْقَوْمِ وَبَيْنَ أَنْ يَنْظُرُوا إِلَى رَبِّهِمْ إِلَّا رِدَاءُ الْكِبْرِ عَلَى وَجْهِهِ فِي جَنَّةِ عَدْنٍ","id":"Telah menceritakan kepada kami ['Ali bin Abdullah] telah menceritakan kepada kami [Abdul Aziz bin Abd shamad] dari [Abu Imran] dari [Abu Bakar bin Abdullah bin Qais] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ada dua surga dari perak, baik bejananya maupun isinya, dan ada dua surga terbuat dari emas, baik bejananya maupun isinya, dan tidak ada yang menghalangi sebuah kaum untuk melihat Rabb mereka selain selendang kesombongan di wajahnya di surga Adn.\""},"6538":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ أَعْيَنَ وَجَامِعُ بْنُ أَبِي رَاشِدٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اقْتَطَعَ مَالَ امْرِئٍ مُسْلِمٍ بِيَمِينٍ كَاذِبَةٍ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ قَالَ عَبْدُ اللَّهِ ثُمَّ قَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِصْدَاقَهُ مِنْ كِتَابِ اللَّهِ جَلَّ ذِكْرُهُ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا أُولَئِكَ لَا خَلَاقَ لَهُمْ فِي الْآخِرَةِ وَلَا يُكَلِّمُهُمْ اللَّهُ }الْآيَةَ","id":"Telah menceritakan kepada kami [Al Humaidi] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Abdul Malik bin A'yan] dan [Jami' bin Abu Rasyid] dari [Abu Wail] dari [Abdullah] radliyallahu'anhu berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berambisi memperoleh harta seorang muslim dengan sumpah palsu, ia berjumpa Allah sedang Allah dalam keadaan murka kepadanya.\" Abdullah berkata, \"Kemudian Rasulullah Shallallahu'alaihiwasallam membacakan pembenarannya dari kitabullah: '(Sesungguhnya orang-orang yang membeli janji Allah dan sumpah mereka dengan harga yang sedikit, mereka itulah orang-orang yang tidak memperoleh bagian di akherat, dan Allah tidak mengajak mereka bicara) ' (QS.Ali Imran: 77)."},"6539":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا عَاصِمٌ عَنْ أَبِي عُثْمَانَ عَنْ أُسَامَةَ قَالَكَانَ ابْنٌ لِبَعْضِ بَنَاتِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْضِي فَأَرْسَلَتْ إِلَيْهِ أَنْ يَأْتِيَهَا فَأَرْسَلَ إِنَّ لِلَّهِ مَا أَخَذَ وَلَهُ مَا أَعْطَى وَكُلٌّ إِلَى أَجَلٍ مُسَمًّى فَلْتَصْبِرْ وَلْتَحْتَسِبْ فَأَرْسَلَتْ إِلَيْهِ فَأَقْسَمَتْ عَلَيْهِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقُمْتُ مَعَهُ وَمُعَاذُ بْنُ جَبَلٍ وَأُبَيُّ بْنُ كَعْبٍ وَعُبَادَةُ بْنُ الصَّامِتِ فَلَمَّا دَخَلْنَا نَاوَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّبِيَّ وَنَفْسُهُ تَقَلْقَلُ فِي صَدْرِهِ حَسِبْتُهُ قَالَ كَأَنَّهَا شَنَّةٌ فَبَكَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ سَعْدُ بْنُ عُبَادَةَ أَتَبْكِي فَقَالَ إِنَّمَا يَرْحَمُ اللَّهُ مِنْ عِبَادِهِ الرُّحَمَاءَ","id":"Telah menceritakan kepada kami [Musa bin Ismail] telah menceritakan kepada kami ['Abdul Wahid] telah menceritakan kepada kami ['Ashim] dari [Abu Usman] dari [Usamah] berkata, \"Anak laki-laki dari anak perempuan Nabi shallallahu 'alaihi wasallam sakit, lantas puteri Nabi mengutus seorang utusan yang inti pesannya agar beliau mendatanginya. Hanya nabi berhalangan dan menyampaikan pesan: 'INNAA LILLAAHI MAA AKHDZA WALAHU MAA A'THAA WAKULLUN ILAA AJALIN MUSAMMAA FAL TASHBIR WAL TAHTASHIB' (Milik Allah sajalah segala yang diambil dan yang diberikan, dan segala sesuatu mempunyai batasan waktu tertentu, hendaklah engkau bersabar dan mengharap-harap ganjaran) '. Lantas puteri nabi untuk kali kedua mengutus utusannya seraya menyatakan sumpah agar beliau mendatangi. Maka Rasulullah Shallallahu'alaihiwasallam pun berangkat dan aku bersamanya, juga Mu'adz bin Jabal, Ubbay bin Ka'b, dan Ubadah bin Shamit. Ketika kami masuk, Rasulullah Shallallahu'alaihiwasallam membopong cucunya sedang napasnya sudah tersengal-sengal di dadanya -seingatku Usamah mengatakan seperti geriba kuno-, maka Rasulullah Shallallahu'alaihiwasallam pun menangis sehingga Sa'd bin 'Ubadah berkata, 'Mengapa baginda menangis? ' Nabi menjawab: 'Hanyasanya Allah menyayangi hamba-Nya yang penyayang.'"},"6540":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اخْتَصَمَتْ الْجَنَّةُ وَالنَّارُ إِلَى رَبّهِمَا فَقَالَتْ الْجَنَّةُ يَا رَبِّ مَا لَهَا لَا يَدْخُلُهَا إِلَّا ضُعَفَاءُ النَّاسِ وَسَقَطُهُمْ وَقَالَتْ النَّارُ يَعْنِي أُوثِرْتُ بِالْمُتَكَبِّرِينَ فَقَالَ اللَّهُ تَعَالَى لِلْجَنَّةِ أَنْتِ رَحْمَتِي وَقَالَ لِلنَّارِ أَنْتِ عَذَابِي أُصِيبُ بِكِ مَنْ أَشَاءُ وَلِكُلِّ وَاحِدَةٍ مِنْكُمَا مِلْؤُهَا قَالَ فَأَمَّا الْجَنَّةُ فَإِنَّ اللَّهَ لَا يَظْلِمُ مِنْ خَلْقِهِ أَحَدًا وَإِنَّهُ يُنْشِئُ لِلنَّارِ مَنْ يَشَاءُ فَيُلْقَوْنَ فِيهَا فَ{ تَقُولُ هَلْ مِنْ مَزِيدٍ }ثَلَاثًا حَتَّى يَضَعَ فِيهَا قَدَمَهُ فَتَمْتَلِئُ وَيُرَدُّ بَعْضُهَا إِلَى بَعْضٍ وَتَقُولُ قَطْ قَطْ قَطْ","id":"Telah menceritakan kepada kami [Ubaidullah bin Sa'd bin Ibrahim] telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [Ayahku] dari [Shalih bin Kisan] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Surga dan neraka saling berselisih kepada Tuhan keduanya, surga berkata, 'Wahai Tuhan, mengapa aku tak dimasuki selain orang-orang lemah dan rakyat jelata? ' Sedang neraka berkata, 'Mengapa aku dikhususkan untuk orang-orang yang sombong? ' Allah ta'ala menjawab surga: \"Engkau adalah rahmat-Ku\", dan Allah berfirman kepada neraka, 'Engkau adalah Siksa-Ku, yang Aku timpakan kepada siapa saja yang Aku kehendaki, dan masing-masing diantara kalian berdua harus dipenuhi.' Nabi bersabda: \"Adapun surga sesungguhnya Allah tidak menzhalimi satupun dari makhluk-Na, dan Allah akan memenuhi neraka dengan siapa saja yang dikehendaki-Nya, lantas mereka dilempar ke dalamnya '(neraka berkata, 'Masihkah ada tambahan) ' (QS. Qaaf ayat: 30) -beliau mengulanginya tiga kali-, kemudian Allah meletakkan telapak kakinya sehingga neraka menjadi penuh, sebagian satu dengan sebagian yang lain saling berhimpitan, neraka pun berkata, 'cukup, cukup, sukup.\""},"6541":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيُصِيبَنَّ أَقْوَامًا سَفْعٌ مِنْ النَّارِ بِذُنُوبٍ أَصَابُوهَا عُقُوبَةً ثُمَّ يُدْخِلُهُمْ اللَّهُ الْجَنَّةَ بِفَضْلِ رَحْمَتِهِ يُقَالُ لَهُمْ الْجَهَنَّمِيُّونَوَقَالَ هَمَّامٌ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا أَنَسٌ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Anas] radliyallahu'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Akan ada beberapa kaum memperoleh kehitaman-hitaman dari neraka, karena dosa-dosa yang pernah mereka lakukan sebagai hukuman atas mereka, kemudian Allah memasukkan mereka ke dalam surga dengan kurnia rahmat-Nya, mereka itulah yang dinamakan jahannamiyun (mantan penghuni neraka jahannam).\" Sedang [Hamam] berkata; telah menceritakan kepada kami [Qatadah] telah menceritakan kepada kami [Anas] dari Nabi shallallahu 'alaihi wasallam.\""},"6542":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَجَاءَ حَبْرٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا مُحَمَّدُ إِنَّ اللَّهَ يَضَعُ السَّمَاءَ عَلَى إِصْبَعٍ وَالْأَرْضَ عَلَى إِصْبَعٍ وَالْجِبَالَ عَلَى إِصْبَعٍ وَالشَّجَرَ وَالْأَنْهَارَ عَلَى إِصْبَعٍ وَسَائِرَ الْخَلْقِ عَلَى إِصْبَعٍ ثُمَّ يَقُولُ بِيَدِهِ أَنَا الْمَلِكُ فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ{ وَمَا قَدَرُوا اللَّهَ حَقَّ قَدْرِهِ }","id":"Telah menceritakan kepada kami [Musa] telah menceritakan kepada kami [Abu 'Awanah] dari [Al A'masy] dari [Ibrahim] dari [Alqamah] dari [Abdullah] berkata, \"Seorang biarawan yahudi menemui Rasulullah Shallallahu'alaihiwasallam dan berkata: \"Wahai Muhammad, sesungguhnya Allah meletakkan langit diatas satu jari, seluruh bumi diatas satu jari, semua gunung diatas satu jari, pohon dan sungai diatas satu jari, dan semua makhluk diatas satu jari, kemudian Allah berfirman seraya menunjukan jarinya, 'Akulah Sang raja'.\" Maka Rasulullah Shallallahu'alaihiwasallam tertawa dan membacakan kutipan ayat: '(Dan mereka tidak menghormati Allah dengan penghormatan yang semestinya) ' (QS. Azzumar: 67)."},"6543":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ أَخْبَرَنِي شَرِيكُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ قَالَبِتُّ فِي بَيْتِ مَيْمُونَةَ لَيْلَةً وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَهَا لِأَنْظُرَ كَيْفَ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِاللَّيْلِ فَتَحَدَّثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ أَهْلِهِ سَاعَةً ثُمَّ رَقَدَ فَلَمَّا كَانَ ثُلُثُ اللَّيْلِ الْآخِرُ أَوْ بَعْضُهُ قَعَدَ فَنَظَرَ إِلَى السَّمَاءِ فَقَرَأَ{ إِنَّ فِي خَلْقِ السَّمَوَاتِ وَالْأَرْضِ إِلَى قَوْلِهِ لِأُولِي الْأَلْبَابِ }ثُمَّ قَامَ فَتَوَضَّأَ وَاسْتَنَّ ثُمَّ صَلَّى إِحْدَى عَشْرَةَ رَكْعَةً ثُمَّ أَذَّنَ بِلَالٌ بِالصَّلَاةِ فَصَلَّى رَكْعَتَيْنِ ثُمَّ خَرَجَ فَصَلَّى لِلنَّاسِ الصُّبْحَ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] telah mengabarkan kepada kami [Muhammad bin Ja'far] telah mengabarkan kepadaku [Syarik bin Abdullah bin Abu Namir] dari [Kuraib] dari [Ibn Abbas] mengatakan, \"Suatu malam aku bermalam di rumah maimunah sedang Nabi shallallahu 'alaihi wasallam Shallallahu'alaihiwasallam di sisinya, itu kulakukan dengan niat agar aku bisa melihat Shalat Rasulullah Shallallahu'alaihiwasallam ketika malam. Rasulullah Shallallahu'alaihiwasallam berbincang-bincang bersama isterinya beberapa saat, kemudian tidur, ketika sepertiga malam terakhir tiba, atau sebagiannya, beliau duduk dan menatap langit lantas membaca ayat: '(Sesungguhnya dalam penciptaan langit dan bumi hingga ayat terdapat tanda-tanda bagi orang yang berakal) ' (QS. Ali'Imran: 190). Kemudian beliau berdiri dan berwudlu', beliau membersihkan gigi-giginya kemudian shalat sebelas rakaat. Kemudian setelah Bilal mengumandangkan adzan (subuh), beliau shalat dua rakaat, kemudian keluar untuk mengimami orang-orang shalat subuh.\""},"6544":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَمَّا قَضَى اللَّهُ الْخَلْقَ كَتَبَ عِنْدَهُ فَوْقَ عَرْشِهِ إِنَّ رَحْمَتِي سَبَقَتْ غَضَبِي","id":"Telah menceritakan kepada kami [Ismail] telah menceritakan kepadaku [Malik] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] radliyallahu'anhu, \"Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tatkala Allah menetapkan penciptaan, Dia menulis di sisi-Nya di atas arsy-Nya 'Sesungguhnya rahmat-Ku lebih mendominasi kemurkaan-Ku.\""},"6545":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا الْأَعْمَشُ سَمِعْتُ زَيْدَ بْنَ وَهْبٍ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُحَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ الصَّادِقُ الْمَصْدُوقُ أَنَّ خَلْقَ أَحَدِكُمْ يُجْمَعُ فِي بَطْنِ أُمِّهِ أَرْبَعِينَ يَوْمًا أَوْ أَرْبَعِينَ لَيْلَةً ثُمَّ يَكُونُ عَلَقَةً مِثْلَهُ ثُمَّ يَكُونُ مُضْغَةً مِثْلَهُ ثُمَّ يُبْعَثُ إِلَيْهِ الْمَلَكُ فَيُؤْذَنُ بِأَرْبَعِ كَلِمَاتٍ فَيَكْتُبُ رِزْقَهُ وَأَجَلَهُ وَعَمَلَهُ وَشَقِيٌّ أَمْ سَعِيدٌ ثُمَّ يَنْفُخُ فِيهِ الرُّوحَ فَإِنَّ أَحَدَكُمْ لَيَعْمَلُ بِعَمَلِ أَهْلِ الْجَنَّةِ حَتَّى لَا يَكُونُ بَيْنَهَا وَبَيْنَهُ إِلَّا ذِرَاعٌ فَيَسْبِقُ عَلَيْهِ الْكِتَابُ فَيَعْمَلُ بِعَمَلِ أَهْلِ النَّارِ فَيَدْخُلُ النَّارَ وَإِنَّ أَحَدَكُمْ لَيَعْمَلُ بِعَمَلِ أَهْلِ النَّارِ حَتَّى مَا يَكُونُ بَيْنَهَا وَبَيْنَهُ إِلَّا ذِرَاعٌ فَيَسْبِقُ عَلَيْهِ الْكِتَابُ فَيَعْمَلُ عَمَلَ أَهْلِ الْجَنَّةِ فَيَدْخُلُهَا","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Al A'masy] aku mendengar [Zaid bin Wahb] aku mendengar ['Abdullah bin Mas'ud] radliyallahu'anhu, telah menceritakan kepada kami Rasulullah Shallallahu'alaihiwasallam yang beliau adalah seorang yang jujur menyampaikan, dan berita yang disampaikan kepadanya adalah benar, bahwa penciptaan salah seorang diantara kalian dihimpun dalam perut ibunya selama empat puluh hari, atau empat puluh malam, kemudian menjadi segumpal darah dalam empat puluh hari berikutnya, kemudian menjadi segumpal daging dalam empat puluh hari berikutnya, kemudian Allah mengutus malaikat kepadanya dan memerintahkan untuk menetapkan empat kalimat (empat hal); tentang rejekinya, ajalnya, amalnya, sengsara ataukah bahagia. Kemudian Allah meniupkan ruh padanya, sungguh ada salah seorang diantara kalian yang melakukan amalan-amalan penghuni surga hingga tak ada jarak antara dia dan surga selain sehasta, namun kemudian takdir telah mendahului dia, lantas ia pun melakukan amalan penghuni neraka dan akhirnya masuk neraka. Dan sungguh ada salah seorang diantara kalian yang melakukan amalan penghuni neraka, hingga tak ada jarak antara dia dan neraka selain sehasta, namun kemudian takdir mendahuluinya, lantas ia pun mengamalkan amalan penghuni surga sehingga ia memasukinya.\""},"6546":{"ar":"حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى حَدَّثَنَا عُمَرُ بْنُ ذَرٍّ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا جِبْرِيلُ مَا يَمْنَعُكَ أَنْ تَزُورَنَا أَكْثَرَ مِمَّا تَزُورُنَا فَنَزَلَتْ{ وَمَا نَتَنَزَّلُ إِلَّا بِأَمْرِ رَبِّكَ لَهُ مَا بَيْنَ أَيْدِينَا وَمَا خَلْفَنَا }إِلَى آخِرِ الْآيَةِ قَالَ كَانَ هَذَا الْجَوَابَ لِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Khallad bin Yahya] telah menceritakan kepada kami [Umar bin Dzar] aku mendengar [Ayahku] menceritakan dari [Said bin Jubair] dari [Ibn Abbas] Radliyallahu'anhuma, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Jibril, apa yang menghalangimu untuk mengunjungi kami lebih sering daripada apa yang telah engkau lakukan?\" Maka turunlah ayat: '(Dan tidaklah Kami menurunkan ayat melainkan dengan perintah Tuhanmu, milik Dialah apa yang didepan kami dan di belakang kami) ', hingga akhir ayat (Qs. Maryam: 64). Dan jawaban ini adalah untuk Muhammad shallallahu 'alaihi wasallam.\""},"6547":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَكُنْتُ أَمْشِي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَرْثٍ بِالْمَدِينَةِ وَهُوَ مُتَّكِئٌ عَلَى عَسِيبٍ فَمَرَّ بِقَوْمٍ مِنْ الْيَهُودِ فَقَالَ بَعْضُهُمْ لِبَعْضٍ سَلُوهُ عَنْ الرُّوحِ وَقَالَ بَعْضُهُمْ لَا تَسْأَلُوهُ عَنْ الرُّوحِ فَسَأَلُوهُ فَقَامَ مُتَوَكِّئًا عَلَى الْعَسِيبِ وَأَنَا خَلْفَهُ فَظَنَنْتُ أَنَّهُ يُوحَى إِلَيْهِ فَقَالَ{ وَيَسْأَلُونَكَ عَنْ الرُّوحِ قُلْ الرُّوحُ مِنْ أَمْرِ رَبِّي وَمَا أُوتِيتُمْ مِنْ الْعِلْمِ إِلَّا قَلِيلًا }فَقَالَ بَعْضُهُمْ لِبَعْضٍ قَدْ قُلْنَا لَكُمْ لَا تَسْأَلُوهُ","id":"Telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] berkata, \"Pernah aku berjalan bersama Rasulullah shallallahu 'alaihi wasallam di sebuah kebun di Madinah, saat beliau bertelekan di atas tongkat. Kemudian beliau melewati sekelompok orang Yahudi, sebagian diantara mereka bertanya kepada sebagian lainnya 'Coba tanyailah dia tentang nyawa', sedang sebagian lain berkata 'Jangan tanyai dia tentang nyawa'. Kemudian beliau berdiri bertelekan di atas tongkatnya sedang saya berada di belakangnya, aku taksir beliau sedang menerima wahyu, lantas beliau membacakan kepada mereka: '(Dan mereka bertanya kepadamu tentang nyawa, katakanlah bahwa nyawa itu adalah urusan tuhanku, dan tidaklah kamu diberi ilmu melainkan sedikit) ' (Qs. Al Isra': 85). Maka sebagian di antara mereka berkata kepada sebagian lainnya, 'Kan telah kami katakan kepada kalian, jangan kalian tanya tentangnya! '"},"6548":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَكَفَّلَ اللَّهُ لِمَنْ جَاهَدَ فِي سَبِيلِهِ لَا يُخْرِجُهُ إِلَّا الْجِهَادُ فِي سَبِيلِهِ وَتَصْدِيقُ كَلِمَاتِهِ بِأَنْ يُدْخِلَهُ الْجَنَّةَ أَوْ يَرْجِعَهُ إِلَى مَسْكَنِهِ الَّذِي خَرَجَ مِنْهُ مَعَ مَا نَالَ مِنْ أَجْرٍ أَوْ غَنِيمَةٍ","id":"Telah menceritakan kepada kami [Ismail] telah menceritakan kepadaku [Malik] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah menjamin bagi siapa yang berjihad di jalan-Nya, yang tidaklah ia berangkat selain benar-benar untuk berjihad di jalan-Nya dan membenarkan kalimat-Nya, bahwa Dia akan memasukkannya dalam surga atau Ia akan mengembalikannya ke tempat tinggalnya yang ia tinggalkan beserta yang diperolehnya berupa pahala dan ghanimah.\""},"6549":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مُوسَى قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ الرَّجُلُ يُقَاتِلُ حَمِيَّةً وَيُقَاتِلُ شَجَاعَةً وَيُقَاتِلُ رِيَاءً فَأَيُّ ذَلِكَ فِي سَبِيلِ اللَّهِ قَالَ مَنْ قَاتَلَ لِتَكُونَ كَلِمَةُ اللَّهِ هِيَ الْعُلْيَا فَهُوَ فِي سَبِيلِ اللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Wail] dari [Abu Musa] berkata, \"Satang seseorang kepada Nabi Shallalahu'alaihiwasallam dan berujar, 'Ada seseorang yang berperang karena dorongan fanatisme, atau berperang karena ingin memperlihatkan keberanian, dan ada yang berperang karena ingin dilihat orang, siapakah yang disebut fi sabilillah? ' Nabi menjawab: \"Siapa yang berperang agar kalimatullah menjadi tinggi, ia berada fii sabilillah.\""},"6550":{"ar":"حَدَّثَنَا شِهَابُ بْنُ عَبَّادٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ حُمَيْدٍ عَنْ إِسْمَاعِيلَ عَنْ قَيْسٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَزَالُ مِنْ أُمَّتِي قَوْمٌ ظَاهِرِينَ عَلَى النَّاسِ حَتَّى يَأْتِيَهُمْ أَمْرُ اللَّهِ","id":"Telah menceritakan kepada kami [Syihab bin Ibad] telah menceritakan kepada kami [Ibrahim bin Humaid] dari [Ismail] dari [Qais] dari [Mughirah bin Syu'bah] berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Akan senantiasa ada dari umatku sekelompok orang (kaum) yang menang mengalahkan manusia, hingga keputusan Allah mendatangi mereka.\""},"6551":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا ابْنُ جَابِرٍ حَدَّثَنِي عُمَيْرُ بْنُ هَانِئٍ أَنَّهُ سَمِعَ مُعَاوِيَةَ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَزَالُ مِنْ أُمَّتِي أُمَّةٌ قَائِمَةٌ بِأَمْرِ اللَّهِ مَا يَضُرُّهُمْ مَنْ كَذَّبَهُمْ وَلَا مَنْ خَالَفَهُمْ حَتَّى يَأْتِيَ أَمْرُ اللَّهِ وَهُمْ عَلَى ذَلِكَفَقَالَ مَالِكُ بْنُ يُخَامِرَ سَمِعْتُ مُعَاذًا يَقُولُ وَهُمْ بِالشَّأْمِ فَقَالَ مُعَاوِيَةُ هَذَا مَالِكٌ يَزْعُمُ أَنَّهُ سَمِعَ مُعَاذًا يَقُولُ وَهُمْ بِالشَّأْمِ","id":"Telah menceritakan kepada kami [Humaidi] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Ibnu Jabir] telah menceritakan kepadaku [Umair bin Hani'] ia mendengar [Mu'awiyah] mengatakan, \"Pernah aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Akan senantiasa ada dari umatku sebuah umat yang menegakkan perintah Allah, tidak membahayakan mereka orang yang mendustakan mereka, tidak pula yang menyelisihi mereka hingga keputusan Allah datang kepada mereka sedang mereka masih dalam keadaan seperti itu.\" [Malik bin Yukhamir] berkata, \"Aku mendengar [Mu'adz] berkata, \"Dan mereka berada di Syam.\" Mu'awiyah juga mengatakan, \"Malik beranggapan bahwa ia mendengar Mu'adz berkata, \"Dan mereka berada di Syam.\""},"6552":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي حُسَيْنٍ حَدَّثَنَا نَافِعُ بْنُ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَوَقَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مُسَيْلِمَةَ فِي أَصْحَابِهِ فَقَالَ لَوْ سَأَلْتَنِي هَذِهِ الْقِطْعَةَ مَا أَعْطَيْتُكَهَا وَلَنْ تَعْدُوَ أَمْرَ اللَّهِ فِيكَ وَلَئِنْ أَدْبَرْتَ لَيَعْقِرَنَّكَ اللَّهُ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Abdullah bin Abu Husain] telah menceritakan kepada kami [Nafi' bin Jubair] dari [Ibn Abbas] berkata, \"Pernah nabi shallallahu 'alaihi wasallam berdiri pada Musailamah di sekelompok kawan-kawannya, lantas beliau berkata \"Kalaulah engkau meminta sebidang tanah ini, niscaya aku tidak akan memberikannya kepadamu selama-lamanya, dan kamu sekali-kali tidak bisa melampaui urusan Allah yang ada padamu, dan kalaulah engkau berbalik ke belakang, Allah akan membunuhmu.\""},"6553":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ عَنْ عَبْدِ الْوَاحِدِ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ ابْنِ مَسْعُودٍ قَالَبَيْنَا أَنَا أَمْشِي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ حَرْثِ الْمَدِينَةِ وَهُوَ يَتَوَكَّأُ عَلَى عَسِيبٍ مَعَهُ فَمَرَرْنَا عَلَى نَفَرٍ مِنْ الْيَهُودِ فَقَالَ بَعْضُهُمْ لِبَعْضٍ سَلُوهُ عَنْ الرُّوحِ فَقَالَ بَعْضُهُمْ لَا تَسْأَلُوهُ أَنْ يَجِيءَ فِيهِ بِشَيْءٍ تَكْرَهُونَهُ فَقَالَ بَعْضُهُمْ لَنَسْأَلَنَّهُ فَقَامَ إِلَيْهِ رَجُلٌ مِنْهُمْ فَقَالَ يَا أَبَا الْقَاسِمِ مَا الرُّوحُ فَسَكَتَ عَنْهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلِمْتُ أَنَّهُ يُوحَى إِلَيْهِ فَقَالَ{ وَيَسْأَلُونَكَ عَنْ الرُّوحِ قُلْ الرُّوحُ مِنْ أَمْرِ رَبِّي }وَمَا أُوتُوا مِنْ الْعِلْمِ إِلَّا قَلِيلًاقَالَ الْأَعْمَشُ هَكَذَا فِي قِرَاءَتِنَا","id":"Telah menceritakan kepada kami [Musa bin Ismail] dari [Abdul Wahid] dari [Al A'masy] dari [Ibrahim] dari [Alqamah] dari [Ibnu Mas'ud] berkata, \"Pernah aku berjalan bersama nabi shallallahu 'alaihi wasallam di sebagian kebun Madinah, sedang ketika itu beliau bersandar di atas sebuah dahan pohon kurma, saat kami melewati beberapa orang Yahudi, sebagian mereka berkata kepada sebagian lainnya, 'Tolong tanyailah dia (Muhammad) tentang nyawa', sementara sebagian mereka berkata, 'Jangan engkau bertanya kepadanya suatu hal yang kalian sendiri ketakutan terhadapnya'. Namun sebagian mereka ngotot berkata, 'Sungguh kami akan bertanya kepadanya! ' Lalu sebagian di antara mereka datang menemui beliau dan berkata, \"Wahai abu Qasim, apa nyawa itu?\" Nabi shallallhu'lihiwasallam terdiam, maka aku pun tahu bahwa beliau sedang menerima wahyu. Lantas beliau membacakan ayat: '(Dan mereka bertanya kepadamu tentang nyawa, katakanlah 'Bahwasanya nyawa itu urusan Tuhanku, dan tidaklah kalian diberi ilmu kecuali sedikit saja) ' (Qs. Al Isra': 85)."},"6554":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَكَفَّلَ اللَّهُ لِمَنْ جَاهَدَ فِي سَبِيلِهِ لَا يُخْرِجُهُ مِنْ بَيْتِهِ إِلَّا الْجِهَادُ فِي سَبِيلِهِ وَتَصْدِيقُ كَلِمَتِهِ أَنْ يُدْخِلَهُ الْجَنَّةَ أَوْ يَرُدَّهُ إِلَى مَسْكَنِهِ بِمَا نَالَ مِنْ أَجْرٍ أَوْ غَنِيمَةٍ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah menjamin siapa saja yang berjihad di jalan-Nya, tidak ada dorongan baginya untuk berjihad di jalan-Nya selain jihad di jalan-Nya dan membenarkan kalimat-Nya, untuk masukkan ke dalam surga, atau Allah mengembalikannya ke tempat tinggalnya dengan ganjaran atau ghanimah.\""},"6555":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَبْدِ الْعَزِيزِ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَعَوْتُمْ اللَّهَ فَاعْزِمُوا فِي الدُّعَاءِ وَلَا يَقُولَنَّ أَحَدُكُمْ إِنْ شِئْتَ فَأَعْطِنِي فَإِنَّ اللَّهَ لَا مُسْتَكْرِهَ لَهُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami ['Abdul Warits] dari ['Abdul 'Aziz] dari [Anas] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian berdoa kepada Allah, maka seriuslah dalam berdoa dan jangan salah seorang di antara kalian berkata 'Jika Engkau berkehendak maka berilah aku', sebab Allah sama sekali tidak ada yang bisa memaksa.\""},"6556":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ ح و حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي أَخِي عَبْدُ الْحَمِيدِ عَنْ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ أَبِي عَتِيقٍ عَنْ ابْنِ شِهَابٍ عَنْ عَلِيِّ بْنِ حُسَيْنٍ أَنَّ حُسَيْنَ بْنَ عَلِيٍّ عَلَيْهِمَا السَّلَام أَخْبَرَهُ أَنَّ عَلِيَّ بْنَ أَبِي طَالِبٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَرَقَهُ وَفَاطِمَةَ بِنْتَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً فَقَالَ لَهُمْ أَلَا تُصَلُّونَ قَالَ عَلِيٌّ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّمَا أَنْفُسُنَا بِيَدِ اللَّهِ فَإِذَا شَاءَ أَنْ يَبْعَثَنَا بَعَثَنَا فَانْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ قُلْتُ ذَلِكَ وَلَمْ يَرْجِعْ إِلَيَّ شَيْئًا ثُمَّ سَمِعْتُهُ وَهُوَ مُدْبِرٌ يَضْرِبُ فَخِذَهُ وَيَقُولُ{ وَكَانَ الْإِنْسَانُ أَكْثَرَ شَيْءٍ جَدَلًا }","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Azzuhri]. (dalam jalur lain disebutkan) telah menceritakan kepada kami [Ismail] telah menceritakan kepadaku saudaraku [Abdul Hamid] dari [Sulaiman] dari [Muhammad bin 'Atiq] dari [Ibn Syihab] dari [Ali bin Husain], bahwa [Husain bin Ali] 'alaihimassalam mengabarkan kepadanya, bahwa [Ali bin Abu Thalib] mengabarkan kepadanya, bahwa Rasulullah Shallallahu'alihiwasallam mendatangi Ali dan Fatimah di malam hari, lantas beliau berkata: \"Tidakkah kalian mendirikan shalat?\" Namun Ali menjawab, \"Wahai Rasulullah, sesungguhnya nyawa kita berada di tangan Allah, jika Dia berkenan, maka Dia akan membangunkan kita.\" Secara spontan Rasulullah Shallhu'laihiwasallam pergi begitu aku menjawab yang demikian, dan beliau sama sekali tidak kembali, kemudian aku mendengar ketika beliau berbalik ke belakang bersabda sambil menepuk pahanya: \"Sungguh manusia itu adalah makhluk yang suka sekali membantah!\""},"6557":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سِنَانٍ حَدَّثَنَا فُلَيْحٌ حَدَّثَنَا هِلَالُ بْنُ عَلِيٍّ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلُ الْمُؤْمِنِ كَمَثَلِ خَامَةِ الزَّرْعِ يَفِيءُ وَرَقُهُ مِنْ حَيْثُ أَتَتْهَا الرِّيحُ تُكَفِّئُهَا فَإِذَا سَكَنَتْ اعْتَدَلَتْ وَكَذَلِكَ الْمُؤْمِنُ يُكَفَّأُ بِالْبَلَاءِ وَمَثَلُ الْكَافِرِ كَمَثَلِ الْأَرْزَةِ صَمَّاءَ مُعْتَدِلَةً حَتَّى يَقْصِمَهَا اللَّهُ إِذَا شَاءَ","id":"Telah menceritakan kepada kami [Muhammad bin Sinan] telah menceritakan kepada kami [Fulaih] telah menceritakan kepada kami [Hilal bin Ali] dari ['Atha' bin Yasar] dari [Abu Hurairah] radliyallahu'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpamaan orang mukmin adalah bagai dahan tumbuhan yang daunnya miring sesuai tempat datangnya angin, namun jika telah tenang, dahan itu bisa kembali lurus. Demikian pula seorang mukmin, terkadang dalam keadaan miring karena ujian. Sebaliknya perumpamaan orang kafir bagaikan pohon padi yang lurus dan keras, sehingga Allah (dengan mudah) mematahkannya kapan saja sekehendak-Nya.\""},"6558":{"ar":"حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ قَائِمٌ عَلَى الْمِنْبَرِ يَقُولَ إِنَّمَا بَقَاؤُكُمْ فِيمَا سَلَفَ قَبْلَكُمْ مِنْ الْأُمَمِ كَمَا بَيْنَ صَلَاةِ الْعَصْرِ إِلَى غُرُوبِ الشَّمْسِ أُعْطِيَ أَهْلُ التَّوْرَاةِ التَّوْرَاةَ فَعَمِلُوا بِهَا حَتَّى انْتَصَفَ النَّهَارُ ثُمَّ عَجَزُوا فَأُعْطُوا قِيرَاطًا قِيرَاطًا ثُمَّ أُعْطِيَ أَهْلُ الْإِنْجِيلِ الْإِنْجِيلَ فَعَمِلُوا بِهِ حَتَّى صَلَاةِ الْعَصْرِ ثُمَّ عَجَزُوا فَأُعْطُوا قِيرَاطًا قِيرَاطًا ثُمَّ أُعْطِيتُمْ الْقُرْآنَ فَعَمِلْتُمْ بِهِ حَتَّى غُرُوبِ الشَّمْسِ فَأُعْطِيتُمْ قِيرَاطَيْنِ قِيرَاطَيْنِ قَالَ أَهْلُ التَّوْرَاةِ رَبَّنَا هَؤُلَاءِ أَقَلُّ عَمَلًا وَأَكْثَرُ أَجْرًا قَالَ هَلْ ظَلَمْتُكُمْ مِنْ أَجْرِكُمْ مِنْ شَيْءٍ قَالُوا لَا فَقَالَ فَذَلِكَ فَضْلِي أُوتِيهِ مَنْ أَشَاءُ","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi'] Telah mengabarkan kepada kami [Syu'aib] dari [Azzuhri] telah mengabarkan kepadaku [Salim bin Abdullah], bahwa [Abdullah bin Umar] berkata, \"Aku mendengar Rasulullah Shalllhu'alaihiwasallam di atas minbar berkata: \"Keberadaan kalian dibandingkan umat-umat sebelum kalian adalah bagaikan antara shalat ashar hingga matahari terbenam. Ahli taurat diberi taurat, lantas mereka mengamalkannya hingga pertengahan siang, kemudian mereka tak mampu bekerja lagi sehingga mereka diberi satu qirath. Lantas ahlu injil diberi injil dan mengamalkannya hingga shalat ashar, kemudian mereka tak mampu lagi melaksanakannya, sehingga diberi satu qirath. Kemudian kalian diberi al Quran, lantas kalian mengamalkannya hingga matahari terbenam, lantas kalian diberi dua qirath, maka ahli taurat dan injil menyampaikan protes 'Bagaimana ini, mereka (umat Islam) lebih sedikit bekerja, namun pahalanya lebih banyak? ' Maka Allah menjawab, 'Namun apakah aku menzhalimi pahala kalian? ' Mereka menjawab, 'Engkau tidak menzhalimi! ' Maka Allah berkata, 'Itulah keutamaan-Ku yang Aku berikan kepada siapa saja yang Aku kehendaki'.\""},"6559":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ الْمُسْنَدِيُّ حَدَّثَنَا هِشَامٌ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي إِدْرِيسَ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَبَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَهْطٍ فَقَالَ أُبَايِعُكُمْ عَلَى أَنْ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَسْرِقُوا وَلَا تَزْنُوا وَلَا تَقْتُلُوا أَوْلَادَكُمْ وَلَا تَأْتُوا بِبُهْتَانٍ تَفْتَرُونَهُ بَيْنَ أَيْدِيكُمْ وَأَرْجُلِكُمْ وَلَا تَعْصُونِي فِي مَعْرُوفٍ فَمَنْ وَفَى مِنْكُمْ فَأَجْرُهُ عَلَى اللَّهِ وَمَنْ أَصَابَ مِنْ ذَلِكَ شَيْئًا فَأُخِذَ بِهِ فِي الدُّنْيَا فَهُوَ لَهُ كَفَّارَةٌ وَطَهُورٌ وَمَنْ سَتَرَهُ اللَّهُ فَذَلِكَ إِلَى اللَّهِ إِنْ شَاءَ عَذَّبَهُ وَإِنْ شَاءَ غَفَرَ لَهُ","id":"Telah menceritakan kepada kami [Abdullah almusnadi] telah menceritakan kepada kami [Hisyam] Telah mengabarkan kepada kami [Ma'mar] dari [Azzuhri] dari [Abu Idris] dari ['Ubadah bin shamit] berkata, \"Pernah aku berbaiat kepada Rasulullah shallallhu'alaihiwasallam bersama serombongan orang. Lantas Nabi bersabda: \"Saya membaiat kalian agar kalian tidak menyekutukan Allah dengan sesuatu apapun, tidak mencuri, tidak berzina, tidak membunuh anak-anak kalian, dan tidak mengada-adakan kebohongan yang kalian ada-adakan antara tangan dan kaki kalian, dan tidak membangkangku dalam perkara ma'ruf. Maka barangsiapa diantara kalian memenuhi baiatnya, ganjarannya berada di sisi Allah. Barangsiapa melanggar janjinya, lantas Allah menghukumnya di dunia, maka yang demikian sebagai kaffarat dosanya. Dan barangsiapa yang Allah menutupinya (membiarkannya), maka yang demikian terserah Allah, jika berkehendak Dia akan menyiksanya, dan jika berkehendak Dia akan mengampuninya.\""},"6560":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا وُهَيْبٌ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ نَبِيَّ اللَّهِ سُلَيْمَانَ عَلَيْهِ السَّلَام كَانَ لَهُ سِتُّونَ امْرَأَةً فَقَالَ لَأَطُوفَنَّ اللَّيْلَةَ عَلَى نِسَائِي فَلْتَحْمِلْنَ كُلُّ امْرَأَةٍ وَلْتَل��دْنَ فَارِسًا يُقَاتِلُ فِي سَبِيلِ اللَّهِ فَطَافَ عَلَى نِسَائِهِ فَمَا وَلَدَتْ مِنْهُنَّ إِلَّا امْرَأَةٌ وَلَدَتْ شِقَّ غُلَامٍ قَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ كَانَ سُلَيْمَانُ اسْتَثْنَى لَحَمَلَتْ كُلُّ امْرَأَةٍ مِنْهُنَّ فَوَلَدَتْ فَارِسًا يُقَاتِلُ فِي سَبِيلِ اللَّهِ","id":"Telah menceritakan kepada kami [Mu'alla bin Asad] Telah menceritakan kepada kami [Wuhaib] dari [Ayyub] dari [Muhammad] dari [Abu Hurairah], bahwa Nabiyullah Sulaiman 'alaihimassalam mempunyai enam puluh isteri dan berkata, \"Sungguh, malam ini aku akan menggilir isteri-isteriku sehingga masing-masing isteriku hamil dan melahirkan seorang penunggang kuda yang berperang fi sabilillah.' Lantas Sulaiman menggilir isteri-isterinya, namun sama sekali tidak ada yang hamil selain satu orang isteri yang melahirkan separoh orang. Maka Nabi Shallallahu'alaihjiwasallam bersabda: \"Kalaulah Sulaiman mengucapkan 'insya allah', niscaya setiap isterinya hamil dan melahirkan seorang anak yang berperang fi sabilillah.\""},"6561":{"ar":"حَدَّثَنَا مُحَمَّدٌ حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَى أَعْرَابِيٍّ يَعُودُهُ فَقَالَ لَا بَأْسَ عَلَيْكَ طَهُورٌ إِنْ شَاءَ اللَّهُ قَالَ قَالَ الْأَعْرَابِيُّ طَهُورٌ بَلْ هِيَ حُمَّى تَفُورُ عَلَى شَيْخٍ كَبِيرٍ تُزِيرُهُ الْقُبُورَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَعَمْ إِذًا","id":"Telah menceritakan kepada kami [Muhammad] telah menceritakan kepada kami ['Abdul Wahhab Ats Tsaqafi] telah menceritakan kepada kami [Khalid Al Hadzdza'] dari ['Ikrimah] dari [Ibn Abbas] radliyallahu'anhuma, bahwa Rasulullah shallallahu 'alaihi wasallam pernah menjenguk seorang arab badui yang sedang sakit. Beliau katakan: \"Tidak apa-apa kamu, insya Allah nggak masalah.\" Lantas si arab badui menjawab, \"Apa, nggak apa-apa? Bahkan itu adalah demam yang menggelegak atas orang yang sudah tua renta yang menghantarkannya kepada kuburan.\" Maka Nabi shallallahu 'alaihi wasallam berkata: \"Semoga iya, kalau begitu.\""},"6562":{"ar":"حَدَّثَنَا ابْنُ سَلَامٍ أَخْبَرَنَا هُشَيْمٌ عَنْ حُصَيْنٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِحِينَ نَامُوا عَنْ الصَّلَاةِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ قَبَضَ أَرْوَاحَكُمْ حِينَ شَاءَ وَرَدَّهَا حِينَ شَاءَ فَقَضَوْا حَوَائِجَهُمْ وَتَوَضَّئُوا إِلَى أَنْ طَلَعَتْ الشَّمْسُ وَابْيَضَّتْ فَقَامَ فَصَلَّى","id":"Telah menceritakan kepada kami [Ibn Salam] Telah mengabarkan kepada kami [Husyaim] dari [Hushain] dari [Abdullah bin Abu Qatadah] dari [ayahnya], bahwa ketika para sahabat ketiduran dari waktu shalat, Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah menggenggam roh kalian sekehendak-Nya, dan Dia mengembalikannya sekehendak-Nya.\" Para sahabat kemudian menuntaskan kebutuhan mereka, dan berwudlu hingga matahari terbit dan putih, dan beliau kemudian berdiri dan shalat.\""},"6563":{"ar":"حَدَّثَنَا يَحْيَى بْنُ قَزَعَةَ حَدَّثَنَا إِبْرَاهِيمُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ وَالْأَعْرَجِ ح و حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي أَخِي عَنْ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ أَبِي عَتِيقٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ وَسَعِيدِ بْنِ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ قَالَاسْتَبَّ رَجُلٌ مِنْ الْمُسْلِمِينَ وَرَجُلٌ مِنْ الْيَهُودِ فَقَالَ الْمُسْلِمُ وَالَّذِي اصْطَفَى مُحَمَّدًا عَلَى الْعَالَمِينَ فِي قَسَمٍ يُقْسِمُ بِهِ فَقَالَ الْيَهُودِيُّ وَالَّذِي اصْطَفَى مُوسَى عَلَى الْعَالَمِينَ فَرَفَعَ الْمُسْلِمُ يَدَهُ عِنْدَ ذَلِكَ فَلَطَمَ الْيَهُودِيَّ فَذَهَبَ الْيَهُودِيُّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ بِالَّذِي كَانَ مِنْ أَمْرِهِ وَأَمْرِ الْمُسْلِمِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُخَيِّرُونِي عَلَى مُوسَى فَإِنَّ النَّاسَ يَصْعَقُونَ يَوْمَ الْقِيَامَةِ فَأَكُونُ أَوَّلَ مَنْ يُفِيقُ فَإِذَا مُوسَى بَاطِشٌ بِجَانِبِ الْعَرْشِ فَلَا أَدْرِي أَكَانَ فِيمَنْ صَعِقَ فَأَفَاقَ قَبْلِي أَوْ كَانَ مِمَّنْ اسْتَثْنَى اللَّهُ","id":"Telah menceritakan kepada kami [Yahya bin Qaza'ah] telah menceritakan kepada kami [Ibrahim] dari [Ibn Syihab] dari [Abu Salamah] dan [Al a'raj]. (dalam jalur lain disebutkan) telah menceritakan kepada kami [Ismail] telah menceritakan kepadaku [Saudaraku] dari [Sulaiman] dari [Muhammad bin Abu 'Atiq] dari [Ibn Syihab] dari [Abu Salmah bin Abdurrahman] dan [Sa'id bin Musayyab] bahwa [Abu Hurairah] berkata, \"Seorang laki-laki muslimin dan seorang laki-laki Yahudi saling memaki (mencela). Si Muslim berkata, 'Demi Dzat yang mengistimewakan Muhammad di atas semua manusia', dan ia mengucapkannya disertai sumpah. Sedang si Yahudi berkata, 'Demi Dzat yang telah mengistimewakan Musa di atas semua manusia'. Lantas si muslim mengangkat tangannya dan menempeleng si Yahudi. Maka si Yahudi melaporkan kasusnya kepada Rasulullah Shallalahu'alaihiwasallam dan mengutarakan segala kasus yang terjadi antara dirinya dan si Muslim, maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Janganlah kalian mengistimewakanku di atas Musa, sebab manusia di hari kiamat nanti akan pingsan sehingga akulah manusia pertama-tama yang bisa siuman. Tiba-tiba Musa telah berdiri di samping 'arsy, sehingga aku tidak tahu apakah dia termasuk yang pingsan ataukah dia telah siuman sebelumku, atau dia diantara manusia yang Allah kecualikan (tidak pingsan).\""},"6564":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ أَبِي عِيسَى أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةُ يَأْتِيهَا الدَّجَّالُ فَيَجِدُ الْمَلَائِكَةَ يَحْرُسُونَهَا فَلَا يَقْرَبُهَا الدَّجَّالُ وَلَا الطَّاعُونُ إِنْ شَاءَ اللَّهُ","id":"Telah menceritakan kepada kami [Ishaq bin Abu 'Isa] telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Syu'bah] dari [Qatadah] dari [Anas bin Malik] radliyallahu'anhu berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Madinah akan didatangi oleh dajjal dan ia temukan kota tersebut dijaga oleh para malaikat, sehingga dajjal tidak bisa mendekatinya, dan tidak pula penyakit tha'un, insya allah.\""},"6565":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ عِكْرِمَةَ عَنْ أَبِي هُرَيْرَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَضَى اللَّهُ الْأَمْرَ فِي السَّمَاءِ ضَرَبَتْ الْمَلَائِكَةُ بِأَجْنِحَتِهَا خُضْعَانًا لِقَوْلِهِ كَأَنَّهُ سِلْسِلَةٌ عَلَى صَفْوَانٍ قَالَ عَلِيٌّ وَقَالَ غَيْرُهُ صَفْوَانٍ يَنْفُذُهُمْ ذَلِكَ فَإِذَا{ فُزِّعَ عَنْ قُلُوبِهِمْ قَالُوا مَاذَا قَالَ رَبُّكُمْ قَالُوا الْحَقَّ وَهُوَ الْعَلِيُّ الْكَبِيرُ }قَالَ عَلِيٌّ وَحَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرٌو عَنْ عِكْرِمَةَ عَنْ أَبِي هُرَيْرَةَ بِهَذَا قَالَ سُفْيَانُ قَالَ عَمْرٌو سَمِعْتُ عِكْرِمَةَ حَدَّثَنَا أَبُو هُرَيْرَةَ قَالَ عَلِيٌّ قُلْتُ لِسُفْيَانَ قَالَ سَمِعْتُ عِكْرِمَةَ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ قَالَ نَعَمْ قُلْتُ لِسُفْيَانَ إِنَّ إِنْسَانًا رَوَى عَنْ عَمْرٍو عَنْ عِكْرِمَةَ عَنْ أَبِي هُرَيْرَةَ يَرْفَعُهُ أَنَّهُ قَرَأَ فُرِّغَ قَالَ سُفْيَانُ هَكَذَا قَرَأَ عَمْرٌو فَلَا أَدْرِي سَمِعَهُ هَكَذَا أَمْ لَا قَالَ سُفْيَانُ وَهِيَ قِرَاءَتُنَا","id":"Telah menceritakan kepada kami ['Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] dari ['Amru] dari ['Ikrimah] dari [Abu Hurairah] yang Nabi shallallahu 'alaihi wasallam menyampaikan kepadanya, beliau bersabda: \"Jika Allah memutuskan suatu keputusan di langit, maka malaikat akan mengepak-ngepakkan sayapnya karena tunduk kepada titah-Nya, seolah-olah kepakan sayapnya seperti rantai di atas batu licin.\" Ali berkata, \"Sedang lainnya berkata, 'Seperti batu licin yang menembus mereka.' Allah berfirman: '(Apabila ketakutan telah hilang dari hati mereka, mereka bertanya 'Apa yang difirmankan Rabb kalian? Mereka menjawab 'Kebenaran, dan Dia Maha Tinggi lagi Maha Besar) ' (Qs. Saba': 34). Ali berkata; telah menceritakan kepada kami Sufyan telah menceritakan kepada kami 'Amru dari 'Ikrimah dari Abu Hurairah dengan redaksi ini.\" Sedang Sufyan berkata, Amru berkata, aku mendengar Ikrimah telah menceritakan kepada kami Abu Hurairah, [Ali] berkata, saya bertanya [Sufyan] ia menjawab, 'Aku mendengar [Ikrimah] berkata, aku mendengar [Abu Hurairah] berkata, 'Ya.' Saya bertanya kepada Sufyan, 'Beberapa orang meriwayatkan dari 'Amru dari 'Ikrimah dari Abu Hurairah yang beliau memarfu'kannya, hanya ia membaca 'furrigha (jika telah selesai) '. Sufyan berkata, 'Beginilah 'Amru membaca, maka aku tidak tahu, apakah ia mendengarnya seperti ini atau.' Sufyan berkata, 'Dan begitulah bacaan kami.'"},"6566":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ كَانَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَذِنَ اللَّهُ لِشَيْءٍ مَا أَذِنَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَغَنَّى بِالْقُرْآنِ وَقَالَ صَاحِبٌ لَهُ يُرِيدُ أَنْ يَجْهَرَ بِهِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibn Syihab] telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman] dari [Abu Hurairah], bahwa ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah tidak pernah mengijinkan sesuatu sebagaimana ijin-Nya kepada Nabi shallallahu 'alaihi wasallam untuk melagukan Al Qur'an, \" sedang salah seorang sahabatnya berkata 'maksud melagukan yaitu membaca dengan keras.\""},"6567":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا أَبُو صَالِحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ ��َضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ يَا آدَمُ فَيَقُولُ لَبَّيْكَ وَسَعْدَيْكَ فَيُنَادَى بِصَوْتٍ إِنَّ اللَّهَ يَأْمُرُكَ أَنْ تُخْرِجَ مِنْ ذُرِّيَّتِكَ بَعْثًا إِلَى النَّارِ","id":"Telah menceritakan kepada kami [Umar bin Hafs bin Ghiyats] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada kami [Abu Shalih] dari [Abu Said Al Khudzri] radliyallahu'anhu berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Allah berfirman, 'Wahai Adam! ' Adam menjawab, 'Aku penuhi panggilan-Mu! ' lantas Adam dipanggil dengan suatu suara, 'Sesungguhnya Allah Tabaraka wa Ta'ala menyuruhmu untuk mengeluarkan utusan-utusan dari anak cucumu ke neraka'.\""},"6568":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْمَا غِرْتُ عَلَى امْرَأَةٍ مَا غِرْتُ عَلَى خَدِيجَةَ وَلَقَدْ أَمَرَهُ رَبُّهُ أَنْ يُبَشِّرَهَا بِبَيْتٍ فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Ubaid bin Ismail] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin Urwah] dari [Ayahnya] dari ['Aisyah] radliyallahu'anhuma berkata, \"Belum pernah aku sedemikian cemburu kepada seorang wanita sebagaimana kecemburuanku terhadap Khadijah, sebab Tuhan Muhammad telah menyuruhnya agar memberinya kabar gembira dengan surga.\""},"6569":{"ar":"حَدَّثَنِي إِسْحَاقُ حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ هُوَ ابْنُ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ أَبِيهِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى إِذَا أَحَبَّ عَبْدًا نَادَى جِبْرِيلَ إِنَّ اللَّهَ قَدْ أَحَبَّ فُلَانًا فَأَحِبَّهُ فَيُحِبُّهُ جِبْرِيلُ ثُمَّ يُنَادِي جِبْرِيلُ فِي السَّمَاءِ إِنَّ اللَّهَ قَدْ أَحَبَّ فُلَانًا فَأَحِبُّوهُ فَيُحِبُّهُ أَهْلُ السَّمَاءِ وَيُوضَعُ لَهُ الْقَبُولُ فِي أَهْلِ الْأَرْضِ","id":"Telah menceritakan kepadaku [Ishaq] telah menceritakan kepada kami [Abdushshamad] telah menceritakan kepada kami ['Abdurrahman] -yaitu Ibnu Abdullah bin Dinar- dari [Ayahnya] dari [Abu Shalih] dari [Abu Hurairah] radliyallahu'anhu berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Tabaraka wa Ta'ala jika mencintai seseorang, Ia memanggil Jibril 'Sesungguhnya Allah mencintai si fulan maka cintailah dia, sehingga Jibril pun mencintainya. Kemudian Jibril memanggil seluruh penghuni langit seraya berseru, 'Sesungguhnya Allah mencintai si fulan maka cintailah dia, maka penghuni langit pun mencintainya, sehingga orang tersebut diterima oleh penduduk bumi.\""},"6570":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَتَعَاقَبُونَ فِيكُمْ مَلَائِكَةٌ بِاللَّيْلِ وَمَلَائِكَةٌ بِالنَّهَارِ وَيَجْتَمِعُونَ فِي صَلَاةِ الْعَصْرِ وَصَلَاةِ الْفَجْرِ ثُمَّ يَعْرُجُ الَّذِينَ بَاتُوا فِيكُمْ فَيَسْأَلُهُمْ وَهُوَ أَعْلَمُ بِهِمْ كَيْفَ تَرَكْتُمْ عِبَادِي فَيَقُولُونَ تَرَكْنَاهُمْ وَهُمْ يُصَلُّونَ وَأَتَيْنَاهُمْ وَهُمْ يُصَلُّونَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Malaikat malam dan malaikat siang secara bergantian menjaga kalian, dan mereka berkumpul pada waktu shalat 'ashar dan shalat subuh, kemudian malaikat yang menjaga kalian di malam hari naik ke langit dan Allah menanyai mereka -sekalipun Dia paling tahu terhadap keadaan mereka- bagaimana kalian tinggalkan para hamba-Ku? ' Para malaikat menjawab, 'Kami tinggalkan saat mereka sedang melaksanakan shalat, dan kami datangi mereka juga saat melaksanakan shalat'.\""},"6571":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ وَاصِلٍ عَنْ الْمَعْرُورِ قَالَ سَمِعْتُ أَبَا ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَتَانِي جِبْرِيلُ فَبَشَّرَنِي أَنَّهُ مَنْ مَاتَ لَا يُشْرِكُ بِاللَّهِ شَيْئًا دَخَلَ الْجَنَّةَ قُلْتُ وَإِنْ سَرَقَ وَإِنْ زَنَى قَالَ وَإِنْ سَرَقَ وَإِنْ زَنَى","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Washil] dari [Al Ma'rur] berkata, \"Aku mendengar [Abu Dzar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jibril menemuiku dan memberiku kabar gembira, bahwasanya siapa saja yang meninggal dengan tidak menyekutukan Allah dengan sesuatu apapun, maka dia masuk surga.\" Maka saya bertanya, 'Meskipun dia mencuri dan berzina? ' Nabi menjawab: 'Meskipun dia mencuri dan juga berzina'.\""},"6572":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو الْأَحْوَصِ حَدَّثَنَا أَبُو إِسْحَاقَ الْهَمْدَانِيُّ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا فُلَانُ إِذَا أَوَيْتَ إِلَى فِرَاشِكَ فَقُلْ اللَّهُمَّ أَسْلَمْتُ نَفْسِي إِلَيْكَ وَوَجَّهْتُ وَجْهِي إِلَيْكَ وَفَوَّضْتُ أَمْرِي إِلَيْكَ وَأَلْجَأْتُ ظَهْرِي إِلَيْكَ رَغْبَةً وَرَهْبَةً إِلَيْكَ لَا مَلْجَأَ وَلَا مَنْجَا مِنْكَ إِلَّا إِلَيْكَ آمَنْتُ بِكِتَابِكَ الَّذِي أَنْزَلْتَ وَبِنَبِيِّكَ الَّذِي أَرْسَلْتَ فَإِنَّكَ إِنْ مُتَّ فِي لَيْلَتِكَ مُتَّ عَلَى الْفِطْرَةِ وَإِنْ أَصْبَحْتَ أَصَبْتَ أَجْرًا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abul Ahwash] telah menceritakan kepada kami [Abu Ishaq Al Hamdani] dari [Barra' bin Azib] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hai fulan, jika engkau mendatangi kasurmu, maka panjatkanlah doa: \"ALLAAHUMMA ASLAMTU NAFSII ILAIKA, WAWAJJAHTU WAJHII ILAIKA, WAFAWWADLTU AMRII ILAIKA, WA ALJA\"TU ZHAHRII ILAIKA, RUGHBTAN WA RUHBATAN ILAIKA, LAA MALJA'A WA LAA MANJAA MINKA ILLAA ILAIKA, AAMANTU BIKITAABIKAL LADZII ANZALTA WABINABIYYIKAL LADZII ARSALTA '(Ya Allah, aku pasrahkan jiwaku kepada-Mu, dan kuhadapkan wajahku kepada-Mu, dan aku serahkan urusanku kepada-Mu, dan aku sandarkan punggungku kepada-Mu, dengan berharap-harap cemas kepada-Mu, sesungguhnya tidak ada tempat bersandar dan tempat keselamatan selain kepada-Mu, saya beriman kepada kitab-Mu yang Engkau turunkan dan nabi-Mu yang Engkau utus) '. Maka sekiranya engkau meninggal di malammu, engkau meninggal di atas fitrah, dan jika engkau meninggal pagi harinya, engkau peroleh pahala.\""},"6573":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْأَحْزَابِ اللَّهُمَّ مُنْزِلَ الْكِتَابِ سَرِيعَ الْحِسَابِ اهْزِمْ الْأَحْزَابَ وَزَلْزِلْ بِهِمْزَادَ الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا ابْنُ أَبِي خَالِدٍ سَمِعْتُ عَبْدَ اللَّهِ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Sufyan] dari [Ismail bin Abu Khalid] dari [Abdullah bin Abu Aufa] berkata, \"Dalam perang Ahzab, Rasulullah Shallallhu'alaihiwasallam berdoa: \"ALLAAHUMMA MUNZILAL KITAAB, SARII'AL HISAAB, AHZIMIL AHZAAB, WAZALZIL BIHIM (Ya Allah yang menurunkan kitab, yang cepat perhitungan-Nya, hancur leburkanlah pasukan ahzab, guncangkanlah mereka) '. Sedang [Humaidi] menambahkan; telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Ibnu Abu Khalid] aku mendengar ['Abdullah] aku mendengar nabi shallallahu 'alaihi wasallam.\""},"6574":{"ar":"حَدَّثَنَا مُسَدَّدٌ عَنْ هُشَيْمٍ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }قَالَ أُنْزِلَتْ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَوَارٍ بِمَكَّةَ فَكَانَ إِذَا رَفَعَ صَوْتَهُ سَمِعَ الْمُشْرِكُونَ فَسَبُّوا الْقُرْآنَ وَمَنْ أَنْزَلَهُ وَمَنْ جَاءَ بِهِ فَقَالَ اللَّهُ تَعَالَى{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }{ لَا تَجْهَرْ بِصَلَاتِكَ }حَتَّى يَسْمَعَ الْمُشْرِكُونَ{ وَلَا تُخَافِتْ بِهَا }عَنْ أَصْحَابِكَ فَلَا تُسْمِعُهُمْ{ وَابْتَغِ بَيْنَ ذَلِكَ سَبِيلًا }أَسْمِعْهُمْ وَلَا تَجْهَرْ حَتَّى يَأْخُذُوا عَنْكَ الْقُرْآنَ","id":"Telah menceritakan kepada kami [Musaddad] dari [Husyaim] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibn Abbas] mengenai ayat: '(Dan janganlah engkau mengeraskan bacaan shalatmu dan jangan pula engkau merendahkan bacaannya) ' (Qs. Al Isra': 110), ayat ini diturunkan kepada Rasulullah shallallahu 'alaihi wasallam secara berturut-turut di Makkah. Ketika itu, jika beliau mengencangkan bacaannya, maka kaum musyrikin mendengarnya hingga mereka mencela Al Qur'an secara habis-habisan, juga mencela yang menurunkannya dan yang membawanya. Maka Allah menurunkan: '(Jangan kamu mengeraskan bacaan shalatmu dan jangan pula merendahkannya) ' (Qs. Al Isra': 110). Jangan kamu mengeraskan bacaanmu maksudnya hingga terdengar oleh orang-orang musyrik, dan jangan pula kamu merendahkannya, maksudnya sehingga tidak terdengar oleh kawan-kawanmu. Dan carilah jalan tengah di antara keduanya, maksudnya bacalah sehingga terdengar oleh kawanmu namun jangan pula kamu membaca terlalu keras hingga musuh mencela Al Qur'an akibat bacaanmu.\""},"6575":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُ تَعَالَى يُؤْذِينِي ابْنُ آدَمَ يَسُبُّ الدَّهْرَ وَأَنَا الدَّهْرُ بِيَدِي الْأَمْرُ أُقَلِّبُ اللَّيْلَ وَالنَّهَارَ","id":"Telah menceritakan kepada kami [Al Humaidi] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Azzuhri] dari [Sa'id bin Musayyab] dari [Abu Hurairah] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Allah Ta'ala berfirman: 'Anak adam menyakiti-Ku dan mencela masa, padahal Aku adalah masa, di tangan-Ku lah segala urusan, Akulah yang membolak-balikkan siang dan malam'.\""},"6576":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَقُولُ اللَّهُ عَزَّ وَجَلَّ الصَّوْمُ لِي وَأَنَا أَجْزِي بِهِ يَدَعُ شَهْوَتَهُ وَأَكْلَهُ وَشُرْبَهُ مِنْ أَجْلِي وَالصَّوْمُ جُنَّةٌ وَلِلصَّائِمِ فَرْحَتَانِ فَرْحَةٌ حِينَ يُفْطِرُ وَفَرْحَةٌ حِينَ يَلْقَى رَبَّهُ وَلَخُلُوفُ فَمِ الصَّائِمِ أَطْيَبُ عِنْدَ اللَّهِ مِنْ رِيحِ الْمِسْكِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Al A'masy] dari [Abu shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Allah Azza wa Jalla berfirman: 'Puasa adalah milik-Ku, dan Aku sendirilah yang mengganjarinya, orang yang berpuasa itu meninggalkan syahwatnya, makan dan minumnya karena Aku. Puasa adalah perisai, dan bagi orang yang berpuasa mendapat dua kegembiraan, kegembiraan ketika ia berjumpa dengan rabbnya. Dan sungguh, bau mulut orang yang berpuasa jauh lebih wangi di sisi Allah daripada bau minyak kesturi.\""},"6577":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَمَا أَيُّوبُ يَغْتَسِلُ عُرْيَانًا خَرَّ عَلَيْهِ رِجْلُ جَرَادٍ مِنْ ذَهَبٍ فَجَعَلَ يَحْثِي فِي ثَوْبِهِ فَنَادَى رَبُّهُ يَا أَيُّوبُ أَلَمْ أَكُنْ أَغْنَيْتُكَ عَمَّا تَرَى قَالَ بَلَى يَا رَبِّ وَلَكِنْ لَا غِنَى بِي عَنْ بَرَكَتِكَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami ['Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Hammam] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Dikala Ayyub mandi dalam keadaan telanjang, tiba-tiba kaki belalang yang terbuat dari emas jatuh kepadanya, kemudian Ayyub membungkus dengan kainnya. Maka Tuhannya memanggilnya, 'Wahai Ayyub, bukankah Aku telah mengayakanmu daripada sekedar apa yang engkau lihat? ' Ayyub menjawab, 'Benar wahai Rabbku, namun saya belum berkecukupan dari barakah-Mu'.\""},"6578":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي عَبْدِ اللَّهِ الْأَغَرِّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَنْزِلُ رَبُّنَا تَبَارَكَ وَتَعَالَى كُلَّ لَيْلَةٍ إِلَى السَّمَاءِ الدُّنْيَا حِينَ يَبْقَى ثُلُثُ اللَّيْلِ الْآخِرُ فَيَقُولُ مَنْ يَدْعُونِي فَأَسْتَجِيبَ لَهُ مَنْ يَسْأَلُنِي فَأُعْطِيَهُ مَنْ يَسْتَغْفِرُنِي فَأَغْفِرَ لَهُ","id":"Telah menceritakan kepada kami [Ismail] telah menceritakan kepadaku [Malik] dari [Ibn Syihab] dari [Abu Abdullah Al Aghar] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Rabb kita Tabaraka wa Ta'ala setiap malam turun ke langit dunia ketika sepertiga malam, lantas Ia berkata, 'Siapa yang berdoa kepada-Ku maka aku beri, siapa yang meminta ampun kepada-Ku maka Aku ampuni?.\""},"6579":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ أَنَّ الْأَعْرَجَ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ نَحْنُ الْآخِرُونَ السَّابِقُونَ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] telah menceritakan kepada kami [Abuz Zinad] bahwa [Al A'raj] menceritakan kepadanya, bahwa ia mendengar [Abu Hurairah], ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kita adalah orang-orang yang datang terkemudian, namun kita yang terlebih dahulu ke surga pada hari kiamat.\""},"6580":{"ar":"وَبِهَذَا الْإِسْنَادِ قَالَ اللَّهُ أَنْفِقْ أُنْفِقْ عَلَيْكَ","id":"(Masih dari jalur periwayatan yang sama dengan hadits sebelumnya -dari [Abu Hurairah]-) Allah berfirman: \"Berinfaklah engkau, niscya aku memberi infak kepadamu.\""},"6581":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ عُمَارَةَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَفَقَالَ هَذِهِ خَدِيجَةُ أَتَتْكَ بِإِنَاءٍ فِيهِ طَعَامٌ أَوْ إِنَاءٍ فِيهِ شَرَابٌ فَأَقْرِئْهَا مِنْ رَبِّهَا السَّلَامَ وَبَشِّرْهَا بِبَيْتٍ مِنْ قَصَبٍ لَا صَخَبَ فِيهِ وَلَا نَصَبَ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Ibn fudlail] dari ['Umarah] dari [Abu Zur'ah] dari [Abu Hurairah] berkata, \"Inilah Khadijah datang kepadamu dengan bejana berisi makanan dan bejana berisi minuman, dan sampaikanlah salam kepadanya dari tuhannya, dan berilah dia kabar gembira dengan rumah yang terbuat dari mutiara, yang tiada keributan dan kegaduhan di sana.\""},"6582":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ أَسَدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ اللَّهُ أَعْدَدْتُ لِعِبَادِي الصَّالِحِينَ مَا لَا عَيْنٌ رَأَتْ وَلَا أُذُنٌ سَمِعَتْ وَلَا خَطَرَ عَلَى قَلْبِ بَشَرٍ","id":"Telah menceritakan kepada kami [Mu'adz bin Asad] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] radliyallahu'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Allah berfirman, 'Aku persiapkan bagi hamba-Ku yang shalih (ganjaran) yang tidak terlihat oleh mata, belum terdengar oleh telinga dan belum pernah terdetik oleh hati manusia'.\""},"6583":{"ar":"حَدَّثَنَا مَحْمُودٌ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي سُلَيْمَانُ الْأَحْوَلُ أَنَّ طَاوُسًا أَخْبَرَهُ أَنَّهُ سَمِعَ ابْنَ عَبَّاسٍ يَقُولُكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَهَجَّدَ مِنْ اللَّيْلِ قَالَ اللَّهُمَّ لَكَ الْحَمْدُ أَنْتَ نُورُ السَّمَوَاتِ وَالْأَرْضِ وَلَكَ الْحَمْدُ أَنْتَ قَيِّمُ السَّمَوَاتِ وَالْأَرْضِ وَلَكَ الْحَمْدُ أَنْتَ رَبُّ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ أَنْتَ الْحَقُّ وَوَعْدُكَ الْحَقُّ وَقَوْلُكَ الْحَقُّ وَلِقَاؤُكَ الْحَقُّ وَالْجَنَّةُ حَقٌّ وَالنَّارُ حَقٌّ وَالنَّبِيُّونَ حَقٌّ وَالسَّاعَةُ حَقٌّ اللَّهُمَّ لَكَ أَسْلَمْتُ وَبِكَ آمَنْتُ وَعَلَيْكَ تَوَكَّلْتُ وَإِلَيْكَ أَنَبْتُ وَبِكَ خَاصَمْتُ وَإِلَيْكَ حَاكَمْتُ فَاغْفِرْ لِي مَا قَدَّمْتُ وَمَا أَخَّرْتُ وَمَا أَسْرَرْتُ وَمَا أَعْلَنْتُ أَنْتَ إِلَهِي لَا إِلَهَ إِلَّا أَنْتَ","id":"Telah menceritakan kepada kami [Mahmud] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibn Juraij] telah mengabarkan kepadaku [Sulaiman Al Ahwal] bahwa [Thawus] radliyallahu'anhu mengabarkan kepadanya, ia mendengar [Ibn Abbas] berkata, \"Jika Nabi Shallalahu'alaihi wasallam tahajjud malam hari beliau membaca: 'ALLAAHUMA LAKAL HAMDU, ANTA NUURUSSAMAWAATI WAL ARDLI, WALAKAL HAMDU ANTA QOYYIMUSSAWAATI WAL ARDLI, WALAKAL HAMDU ANTA RABBUSSAMAAWAATI WAL ARDLI WAMAN FIIHINNA, ANTAL HAQQU, WAWA'DUKAL HAQQ, WAQOULUKL HAQQ, WALIQOO'UKAL HAQQ, WALJANNATU HAQQ, WANNAARU HAQQ, WANNABIYUUN HAQQ, WASSAA'ATU HAQQ, ALLOOHUMMA LAKA ASLAMTU WABIKA AAMANTU WAILAIKA TAWAKKALTU, WAILAIKA ANABTU, WABIKA KHAASHAMTU, WAILAIKA HAAKAMTU, FAHGHFIRLII MA QADDAMMTU WAMAA AKHKHARTU, WAMA ASRARTU WAMAA A'LANTU, ANTA ILAAHII, LAA-ILAAHA ILLAA ANTA (Ya Allah, bagi-Mu lah segala puji, Engkau cahaya langit dan bumi, bagi-Mu segala puji, Engkau adalah pemelihara langit dan bumi, dan bagi-Mu segala puji, Engkau adalah Pemilik langit dan bumi dan siapa saja yang menghuninya, Engkau adalah Benar, dan janji-Mu benar, firman-Mu benar, pertemuan dengan-Mu benar, surga-Mu benar, neraka-Mu benar, para nabi benar, dan kiamat benar. Ya Allah, kepada-Mu aku berserah, kepada-Mu aku beriman, kepada-Mu aku bertawakkal, kepada-Mu aku menyandarkan diri, karena-Mu aku memusuhi, dan kepada-Mu aku meminta penghakiman, maka ampunilah bagiku apa yang telah aku perbuat dan apa yang belum aku lakukan, apa yang aku lakukan secara sembunyi-sembunyi dan apa yang aku lakukan secara terang-terangan, Engkau adalah Tuhanku, tiada sesembahan yang hak selain Engkau) '.\""},"6584":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ النُّمَيْرِيُّ حَدَّثَنَا يُونُسُ بْنُ يَزِيدَ الْأَيْلِيُّ قَالَ سَمِعْتُ الزُّهْرِيَّ قَالَ سَمِعْتُ عُرْوَةَ بْنَ الزُّبَيْرِ وَسَعِيدَ بْنَ الْمُسَيَّبِ وَعَلْقَمَةَ بْنَ وَقَّاصٍ وَعُبَيْدَ اللَّهِ بْنَ عَبْدِ اللَّهِ عَنْ حَدِيثِ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحِينَ قَالَ لَهَا أَهْلُ الْإِفْكِ مَا قَالُوا فَبَرَّأَهَا اللَّهُ مِمَّا قَالُوا وَكُلٌّ حَدَّثَنِي طَائِفَةً مِنْ الْحَدِيثِ الَّذِي حَدَّثَنِي عَنْ عَائِشَةَ قَالَتْ وَلَكِنِّي وَاللَّهِ مَا كُنْتُ أَظُنُّ أَنَّ اللَّهَ يُنْزِلُ فِي بَرَاءَتِي وَحْيًا يُتْلَى وَلَشَأْنِي فِي نَفْسِي كَانَ أَحْقَرَ مِنْ أَنْ يَتَكَلَّمَ اللَّهُ فِيَّ بِأَمْرٍ يُتْلَى وَلَكِنِّي كُنْتُ أَرْجُو أَنْ يَرَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي النَّوْمِ رُؤْيَا يُبَرِّئُنِي اللَّهُ بِهَا فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الَّذِينَ جَاءُوا بِالْإِفْكِ }الْعَشْرَ الْآيَاتِ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Abdullah bin Umar An Numairi] telah menceritakan kepada kami [Yunus bin Yazid Al Aili] mengatakan, aku mendengar [Azzuhri] berkata, Aku mendengar ['Urwah bin Zubair] dan [Sa'id bin Musayyab] dan ['Alqamah bin Waqqash] dan [Ubaidullah bin Abdullah] dari hadis [Aisyah] isteri Nabi shallallahu 'alaihi wasallam, ketika penyebar-penyebar kebohongan menyebarluaskan kebohongan terhadapnya. Kemudian Allah menyucikannya dari kebohongan yang mereka katakan, dan kesemuanya menceritakan kepadaku sekumpulan hadis yang masing-masing mereka riwayatkan dari Aisyah, Aisyah berkata, \"Akan tetapi demi Allah, aku sama sekali tak punya perkiraan Allah akan menurunkan wahyu terhadap berita kesucianku, sungguh urusanku terhadap diriku lebih remeh daripada Allah berbicara tentangku dengan wahyu yang dibacakan, yang kuharap ketika itu hanyalah sekiranya Rasulullah shallallahu 'alaihi wasallam bermimpi dalam tidurnya, yang menceritakan berita kesucianku dari ghosip yang disebarkan orang-orang. Lantas Allah menurunkan ayat: '(sesungguhnya orang-orang yang datang dengan membawa berita bohong) ', (Qs. An Nuur: 11), dan seterusnya hingga sepuluh ayat.\""},"6585":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ رَاشِدٍ حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ حُمَيْدٍ قَالَ سَمِعْتُ أَنَسًا رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا كَانَ يَوْمُ الْقِيَامَةِ شُفِّعْتُ فَقُلْتُ يَا رَبِّ أَدْخِلْ الْجَنَّةَ مَنْ كَانَ فِي قَلْبِهِ خَرْدَلَةٌ فَيَدْخُلُونَ ثُمَّ أَقُولُ أَدْخِلْ الْجَنَّةَ مَنْ كَانَ فِي قَلْبِهِ أَدْنَى شَيْءٍ فَقَالَ أَنَسٌ كَأَنِّي أَنْظُرُ إِلَى أَصَابِعِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yusuf bin Rasyid] telah menceritakan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Abu Bakar bin 'Iyyasy] dari [Humaid] berkata, \"Aku mendengar [Anas] radliyallahu'anhu berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Jika hari kiamat tiba, maka aku diberi syafaat, lantas aku berkata: 'Wahai rabb, tolong masukkanlah ke dalam surga siapa saja yang dalam hatinya masih ada sebiji sawi iman.' Lantas mereka pun masuk, kemudian aku berkata: 'Masukkanlah dalam surga siapa saja yang dalam hatinya ada iman sekalipun dalam tingkatan paling rendah.\" Anas berkata, \"Seakan aku melihat jari-jari Rasulullah shallallahu 'alaihi wasallam.\""},"6586":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا مَعْبَدُ بْنُ هِلَالٍ الْعَنَزِيُّ قَالَاجْتَمَعْنَا نَاسٌ مِنْ أَهْلِ الْبَصْرَةِ فَذَهَبْنَا إِلَى أَنَسِ بْنِ مَالِكٍ وَذَهَبْنَا مَعَنَا بِثَابِتٍ الْبُنَانِيِّ إِلَيْهِ يَسْأَلُهُ لَنَا عَنْ حَدِيثِ الشَّفَاعَةِ فَإِذَا هُوَ فِي قَصْرِهِ فَوَافَقْنَاهُ يُصَلِّي الضُّحَى فَاسْتَأْذَنَّا فَأَذِنَ لَنَا وَهُوَ قَاعِدٌ عَلَى فِرَاشِهِ فَقُلْنَا لِثَابِتٍ لَا تَسْأَلْهُ عَنْ شَيْءٍ أَوَّلَ مِنْ حَدِيثِ الشَّفَاعَةِ فَقَالَ يَا أَبَا حَمْزَةَ هَؤُلَاءِ إِخْوَانُكَ مِنْ أَهْلِ الْبَصْرَةِ جَاءُوكَ يَسْأَلُونَكَ عَنْ حَدِيثِ الشَّفَاعَةِ فَقَالَ حَدَّثَنَا مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانَ يَوْمُ الْقِيَامَةِ مَاجَ النَّاسُ بَعْضُهُمْ فِي بَعْضٍ فَيَأْتُونَ آدَمَ فَيَقُولُونَ اشْفَعْ لَنَا إِلَى رَبِّكَ فَيَقُولُ لَسْتُ لَهَا وَلَكِنْ عَلَيْكُمْ بِإِبْرَاهِيمَ فَإِنَّهُ خَلِيلُ الرَّحْمَنِ فَيَأْتُونَ إِبْرَاهِيمَ فَيَقُولُ لَسْتُ لَهَا وَلَكِنْ عَلَيْكُمْ بِمُوسَى فَإِنَّهُ كَلِيمُ اللَّهِ فَيَأْتُونَ مُوسَى فَيَقُولُ لَسْتُ لَهَا وَلَكِنْ عَلَيْكُمْ بِعِيسَى فَإِنَّهُ رُوحُ اللَّهِ وَكَلِمَتُهُ فَيَأْتُونَ عِيسَى فَيَقُولُ لَسْتُ لَهَا وَلَكِنْ عَلَيْكُمْ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَأْتُونِي فَأَقُولُ أَنَا لَهَا فَأَسْتَأْذِنُ عَلَى رَبِّي فَيُؤْذَنُ لِي وَيُلْهِمُنِي مَحَامِدَ أَحْمَدُهُ بِهَا لَا تَحْضُرُنِي الْآنَ فَأَحْمَدُهُ بِتِلْكَ الْمَحَامِدِ وَأَخِرُّ لَهُ سَاجِدًا فَيَقُولُ يَا مُحَمَّدُ ارْفَعْ رَأْسَكَ وَقُلْ يُسْمَعْ لَكَ وَسَلْ تُعْطَ وَاشْفَعْ تُشَفَّعْ فَأَقُولُ يَا رَبِّ أُمَّتِي أُمَّتِي فَيَقُولُ انْطَلِقْ فَأَخْرِجْ مِنْهَا مَنْ كَانَ فِي قَلْبِهِ مِثْقَالُ شَعِيرَةٍ مِنْ إِيمَانٍ فَأَنْطَلِقُ فَأَفْعَلُ ثُمَّ أَعُودُ فَأَحْمَدُهُ بِتِلْكَ الْمَحَامِدِ ثُمَّ أَخِرُّ لَهُ سَاجِدًا فَيُقَالُ يَا مُحَمَّدُ ارْفَعْ رَأْسَكَ وَقُلْ يُسْمَعْ لَكَ وَسَلْ تُعْطَ وَاشْفَعْ تُشَفَّعْ فَأَقُولُ يَا رَبِّ أُمَّتِي أُمَّتِي فَيَقُولُ انْطَلِقْ فَأَخْرِجْ مِنْهَا مَنْ كَانَ فِي قَلْبِهِ مِثْقَالُ ذَرَّةٍ أَوْ خَرْدَلَةٍ مِنْ إِيمَانٍ فَأَخْرِجْهُ فَأَنْطَلِقُ فَأَفْعَلُ ثُمَّ أَعُودُ فَأَحْمَدُهُ بِتِلْكَ الْمَحَامِدِ ثُمَّ أَخِرُّ لَهُ سَاجِدًا فَيَقُولُ يَا مُحَمَّدُ ارْفَعْ رَأْسَكَ وَقُلْ يُسْمَعْ لَكَ وَسَلْ تُعْطَ وَاشْفَعْ تُشَفَّعْ فَأَقُولُ يَا رَبِّ أُمَّتِي أُمَّتِي فَيَقُولُ انْطَلِقْ فَأَخْرِجْ مَنْ كَانَ فِي قَلْبِهِ أَدْنَى أَدْنَى أَدْنَى مِثْقَالِ حَبَّةِ خَرْدَلٍ مِنْ إِيمَانٍ فَأَخْرِجْهُ مِنْ النَّارِ فَأَنْطَلِقُ فَأَفْعَلُ فَلَمَّا خَرَجْنَا مِنْ عِنْدِ أَنَسٍ قُلْتُ لِبَعْضِ أَصْحَابِنَا لَوْ مَرَرْنَا بِالْحَسَنِ وَهُوَ مُتَوَارٍ فِي مَنْزِلِ أَبِي خَلِيفَةَ فَحَدَّثْنَاهُ بِمَا حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ فَأَتَيْنَاهُ فَسَلَّمْنَا عَلَيْهِ فَأَذِنَ لَنَا فَقُلْنَا لَهُ يَا أَبَا سَعِيدٍ جِئْنَاكَ مِنْ عِنْدِ أَخِيكَ أَنَسِ بْنِ مَالِكٍ فَلَمْ نَرَ مِثْلَ مَا حَدَّثَنَا فِي الشَّفَاعَةِ فَقَالَ هِيهْ فَحَدَّثْنَاهُ بِالْحَدِيثِ فَانْتَهَى إِلَى هَذَا الْمَوْضِعِ فَقَالَ هِيهْ فَقُلْنَا لَمْ يَزِدْ لَنَا عَلَى هَذَا فَقَالَ لَقَدْ حَدَّثَنِي وَهُوَ جَمِيعٌ مُنْذُ عِشْرِينَ سَنَةً فَلَا أَدْرِي أَنَسِيَ أَمْ كَرِهَ أَنْ تَتَّكِلُوا قُلْنَا يَا أَبَا سَعِيدٍ فَحَدِّثْنَا فَضَحِكَ وَقَالَ خُلِقَ الْإِنْسَانُ عَجُولًا مَا ذَكَرْتُهُ إِلَّا وَأَنَا أُرِيدُ أَنْ أُحَدِّثَكُمْ حَدَّثَنِي كَمَا حَدَّثَكُمْ بِهِ قَالَ ثُمَّ أَعُودُ الرَّابِعَةَ فَأَحْمَدُهُ بِتِلْكَ الْمَحَامِدِ ثُمَّ أَخِرُّ لَهُ سَاجِدًا فَيُقَالُ يَا مُحَمَّدُ ارْفَعْ رَأْسَكَ وَقُلْ يُسْمَعْ وَسَلْ تُعْطَهْ وَاشْفَعْ تُشَفَّعْ فَأَقُولُ يَا رَبِّ ائْذَنْ لِي فِيمَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ فَيَقُولُ وَعِزَّتِي وَجَلَالِي وَكِبْرِيَائِي وَعَظَمَتِي لَأُخْرِجَنَّ مِنْهَا مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Ma'bad bin Hilal Al 'Anazi] berkata, \"Kami, orang-orang penduduk Bashrah, berkumpul dan pergi menemui [Anas bin Malik], lalu kami pergi bersama Tsabit Al Bunani dengan tujuan bertanya tentang hadis Syafaat. Tidak tahunya Anas bin mlik dalam berada istananya, lalu kami temui beliau tepat ketika ia sedang shalat dluha. Kemudian kami meminta ijin dan ia pun memberi ijin yang ketika itu ia tengah duduk di atas kasurnya. Maka kami berkata kepada Tsabit, 'Jangan kamu bertanya kepadanya tentang sesuatu sebelum hadis syafaat.' Lantas Tsabit bertanya, 'Wahai Abu Hamzah, kawan-kawanmu dari penduduk Bashrah datang kepadamu untuk bertanya tentang hadis syafaat.' Lantas Anas berkata, \"Muhammad shallallahu 'alaihi wasallam telah menceritakan kepada kami, beliau bersabda: \"Jika hari kiamat tiba, maka manusia satu sama lain saling bertumpukan. Mereka kemudian mendatangi Adam dan berkata, 'Tolonglah kami agar mendapat syafaat Tuhanmu.' Namun Adam hanya menjawab, 'Aku tak berhak untuk itu, namun datangilah Ibrahim sebab dia adalah khalilurrahman (Kekasih Arrahman).' Lantas mereka mendatangi Ibrahim, namun sayang Ibrahim berkata, 'Aku tak berhak untuk itu, coba datangilah Musa, sebab dia adalah nabi yang diajak bicara oleh Allah (kaliimullah).' Mereka pun mendatangi Musa, namun Musa berkata, 'Saya tidak berhak untuk itu, coba mintalah kepada Isa, sebab ia adalah roh Allah dan kalimah-Nya.' Maka mereka pun mendatang Isa. Namun Isa juga berkata, 'Maaf, aku tak berhak untuk itu, namun cobalah kalian temui Muhammad shallallahu 'alaihi wasallam.' Mereka pun mendatangiku sehingga aku pun berkata: \"Aku kemudian meminta ijin Tuhanku dan aku diijinkan, Allah mengilhamiku dengan puji-pujian yang aku pergunakan untuk memanjatkan pujian terhadap-Nya, yang jika puji-pujian itu menghadiriku sekarang, aku tidak melafadkan puji-pujian itu. Aku lalu tersungkur sujud kepada-Nya, lantas Allah berfirman 'Wahai Muhammad, angkatlah kepalamu, katakanlah engkau akan didengar, mintalah engkau akan diberi, mintalah keringanan engkau akan diberi keringanan.' Maka aku menghiba 'Wahai tuhanku, umatku-umatku.' Allah menjawab, 'Berangkat dan keluarkanlah dari neraka siapa saja yang dalam hatinya masih terdapat sebiji gandum keimanan.' Maka aku mendatangi mereka hingga aku pun memberinya syafaat. Kemudian aku kembali menemui tuhanku dan aku memanjatkan puji-pujian tersebut, kemudian aku tersungkur sujud kepada-Nya, lantas ada suara 'Hai Muhammad, angkatlah kepalamu dan katakanlah engkau akan didengar, dan mintalah engkau akan diberi, dan mintalah syafaat engkau akan diberi syafaat.' Maka aku berkata, 'Umatku, umatku, ' maka Allah berkata, 'Pergi dan keluarkanlah siapa saja yang dalam hatinya masih ada sebiji sawi keimanan, ' maka aku pun pergi dan mengeluarkannya. Kemudian aku kembali memanjatkan puji-pujian itu dan tersungkur sujud kepada-Nya, lantas Allah kembali berkata, 'Hai Muhammad, angkatlah kepalamu, katakanlah engkau akan didengar, mintalah engkau akan diberi, dan mintalah syafaat engkau akan diberi syafaat.' Maka aku berkata, 'Wahai tuhanku, umatku, umatku.' Maka Allah berfirman: 'Berangkat dan keluarkanlah siapa saja yang dalam hatinya masih ada iman meskipun jauh lebih kecil daripada sebiji sawi, ' maka aku pun berangkat dan mengeluarkan mereka dari neraka.\" Tatkala kami pulang tempat dari Anas, aku katakan kepada sebagian sahabat kami, 'Duhai, sekiranya saja kita melewati Al Hasan -yang dia menyepi di rumah Abu khalifah-'. Lantas kami menceritakan kepada Al Hasan dengan apa yang telah diceritakan Anas bin Malik kepada kami. Selanjutnya kami pun menemuinya dan kami ucapkan salam, ia mengijinkan kami dan kami katakan, 'Wahai Abu Sa'id, kami datang menemuimu setelah kami kembali dari saudaramu, Anas bin Malik. Belum pernah kami lihat sebagaimana yang ia ceritakan kepada kami tentang syafaat.' Lantas ia berkata, 'Heiih.' Maka hadits tersebut kemudian kami ceritakan kepadanya (Al Hasan), dan berhenti sampai sini. Namun ia berkata, 'Hei…! Hanya sampai situ? ' Kami jawab, 'Dia tidak menambah kami daripada sekedar ini saja.' Lantas ia berkata, 'Sungguh, dia pernah menceritakan kepadaku itu -secara sempurna- kepadaku sejak dua puluh tahun yang lalu, aku tidak tahu apakah dia lupa ataukah tidak suka jika kalian kemudian pasrah.' Kami lalu berkata, 'Wahai Abu Sa'id, tolong ceritakanlah kepada kami! ' Al Hasan kemudian tertawa seraya berkata, 'Sesungguhnya manusia dicipta dalam keadaan tergesa-gesa. Saya tidak menyebutnya selain saya akan menceritakannya kepada kalian. Anas telah menceritakan kepadaku sebagaimana dia ceritakan kepada kalian. Nabi berkata: \"Kemudian aku kembali untuk keempat kalinya, dan aku memanjatkan dengan puji-pujian itu kemudian aku tersungkur sujud dan diserukan, 'Wahai Muhammad, angkatlah kepalamu, ucapkanlah engkau didengar, mintalah engkau diberi, dan mintalah syafaat engkau akan diberi syafaat, ' maka aku berkata, 'Wahai Tuhanku, ijinkanlah bagiku untuk orang-orang yang mengucapkan La-Ilaaha-Illallah! ' Maka Allah menjawab, 'Demi kemuliaan, keagungan dan kebesaran-Ku, sungguh akan Aku keluarkan siapa saja yang mengucapkan Laa-Ilaaha-Illallah.\""},"6587":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ آخِرَ أَهْلِ الْجَنَّةِ دُخُولًا الْجَنَّةَ وَآخِرَ أَهْلِ النَّارِ خُرُوجًا مِنْ النَّارِ رَجُلٌ يَخْرُجُ حَبْوًا فَيَقُولُ لَهُ رَبُّهُ ادْخُلْ الْجَنَّةَ فَيَقُولُ رَبِّ الْجَنَّةُ مَلْأَى فَيَقُولُ لَهُ ذَلِكَ ثَلَاثَ مَرَّاتٍ فَكُلُّ ذَلِكَ يُعِيدُ عَلَيْهِ الْجَنَّةُ مَلْأَى فَيَقُولُ إِنَّ لَكَ مِثْلَ الدُّنْيَا عَشْرَ مِرَارٍ","id":"Telah menceritakan kepada kami [Muhammad bin Khalid] telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Israil] dari [Manshur] dari [Ibrahim] dari ['Abidah] dari ['Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Manusia yang terakhir kali masuk surga dan terakhir kali keluar dari neraka adalah seseorang yang keluar dengan merangkak, lantas tuhannya berkata, 'Masuklah kamu dalam surga.' Orang tersebut kemudian berkata, 'Wahai Tuhanku, surga sudah sesak! ' Allah mengulangi firman-Nya hingga tiga kali, namun si hamba terus menjawabnya dengan mengatakan 'Surga sudah penuh'. Maka Allah berfirman: 'Sesungguhnya surga bagimu seperti dunia dikalikan sepuluhnya.'"},"6588":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ عَنْ الْأَعْمَشِ عَنْ خَيْثَمَةَ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْكُمْ أَحَدٌ إِلَّا سَيُكَلِّمُهُ رَبُّهُ لَيْسَ بَيْنَهُ وَبَيْنَهُ تُرْجُمَانٌ فَيَنْظُرُ أَيْمَنَ مِنْهُ فَلَا يَرَى إِلَّا مَا قَدَّمَ مِنْ عَمَلِهِ وَيَنْظُرُ أَشْأَمَ مِنْهُ فَلَا يَرَى إِلَّا مَا قَدَّمَ وَيَنْظُرُ بَيْنَ يَدَيْهِ فَلَا يَرَى إِلَّا النَّارَ تِلْقَاءَ وَجْهِهِ فَاتَّقُوا النَّارَ وَلَوْ بِشِقِّ تَمْرَةٍقَالَ الْأَعْمَشُ وَحَدَّثَنِي عَمْرُو بْنُ مُرَّةَ عَنْ خَيْثَمَةَ مِثْلَهُ وَزَادَ فِيهِ وَلَوْ بِكَلِمَةٍ طَيِّبَةٍ","id":"Telah menceritakan kepada kami ['Ali bin Hujr] telah memberitakan kepada kami ['Isa bin Yunus] dari [Al A'masy] dari [Khaitsamah] dari ['Adi bin Hatim] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah salah seorang di antara kalian melainkan akan diajak bicara oleh tuhannya dengan tanpa juru penerjemah, saat ia melihat sebelah kanannya maka ia tidak melihat selain amalnya yang pernah dilakukan, saat ia melihat sebelah kirinya maka ia tidak melihat kecuali apa yang telah ia lakukan sebelumnya, dan saat ia lihat depannya maka melihat selain neraka di depan mukanya. Maka jagalah kalian dari neraka walau hanya dengan separoh biji kurma.\" [Al A'masy] mengatakan, \"Dan telah menceritakan kepadaku ['Amru bin Murrah] dari [Khaitsamah] semisalnya, dan ia tambahi dengan redaksi, 'Walaupun hanya dengan kata-kata yang baik'.\""},"6589":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَجَاءَ حَبْرٌ مِنْ الْيَهُودِ فَقَالَ إِنَّهُ إِذَا كَانَ يَوْمُ الْقِيَامَةِ جَعَلَ اللَّهُ السَّمَوَاتِ عَلَى إِصْبَعٍ وَالْأَرَضِينَ عَلَى إِصْبَعٍ وَالْمَاءَ وَالثَّرَى عَلَى إِصْبَعٍ وَالْخَلَائِقَ عَلَى إِصْبَعٍ ثُمَّ يَهُزُّهُنَّ ثُمَّ يَقُولُ أَنَا الْمَلِكُ أَنَا الْمَلِكُ فَلَقَدْ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضْحَكُ حَتَّى بَدَتْ نَوَاجِذُهُ تَعَجُّبًا وَتَصْدِيقًا لِقَوْلِهِ ثُمَّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَمَا قَدَرُوا اللَّهَ حَقَّ قَدْرِهِ إِلَى قَوْلِهِ يُشْرِكُونَ }","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari ['Abidah] dari ['Abdullah] radliyallahu'anhu berkata, \"Seorang biarawan Yahudi datang dan berkata, 'Jika hari kiamat terjadi, maka Allah meletakkan langit di atas jari-Nya, dan tujuh lapisan bumi juga diletakkan di atas jarinya dan air, bintang juga di atas jari, dan seluruh makhluk yang ada juga di atas satu jarinya, kemudian Allah menggetarkan mereka seraya berkata: 'Aku adalah Sang raja, akulah sang raja! ' Dan kulihat Nabi shallallahu 'alaihi wasallam tertawa hingga kelihatan gigi gerahamnya sebagai pertanda takjub dan membenarkan ucapannya. Kemudian Nabi Shallallahu'alaihiwasalam membacakan firman Allah: '(Dan mereka (orang-orang Yahudi) tidak menghormati Allah dengan penghormatan yang sebenarnya) hingga ayat '(dari apa yang mereka persekutukan) ' (Qs. Azzumar: ayat 67)."},"6590":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ صَفْوَانَ بْنِ مُحْرِزٍ أَنَّرَجُلًا سَأَلَ ابْنَ عُمَرَ كَيْفَ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي النَّجْوَى قَالَ يَدْنُو أَحَدُكُمْ مِنْ رَبِّهِ حَتَّى يَضَعَ كَنَفَهُ عَلَيْهِ فَيَقُولُ أَعَمِلْتَ كَذَا وَكَذَا فَيَقُولُ نَعَمْ وَيَقُولُ عَمِلْتَ كَذَا وَكَذَا فَيَقُولُ نَعَمْ فَيُقَرِّرُهُ ثُمَّ يَقُولُ إِنِّي سَتَرْتُ عَلَيْكَ فِي الدُّنْيَا وَأَنَا أَغْفِرُهَا لَكَ الْيَوْمَوَقَالَ آدَمُ حَدَّثَنَا شَيْبَانُ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا صَفْوَانُ عَنْ ابْنِ عُمَرَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Shafwan bin Mukhraz], bahwa ada seorang laki-laki bertanya [Ibnu Umar], \"Bagaimana engkau mendengar Rasulullah shallallahu 'alaihi wasallam bersabda tentang bisikan?\" Ibnu Umar menjawab, 'Salah seorang di antara kalian mendekati tuhannya hingga Allah meletakkan dekapannya kepadanya dan berujar, 'Bukankah engkau telah melakukan demikian? ' Maka si hamba tadi berkata, 'Benar.' Allah lantas berkata lagi, 'Bukankah engkau melakukan yang demikian-demikian? ' Si hamba tadi menjawab, 'Benar, ' dan dia mengakuinya. Kemudian Allah berkata, 'Sesungguhnya aku telah menutup dosa-dosa itu bagimu di dunia, dan hari ini aku mengampuninya bagimu'.\" Sedang [Adam] berkata, telah menceritakan kepada kami [Syaiban] telah menceritakan kepada kami [Qatadah] telah menceritakan kepada kami [Shafwan] dari [Ibn 'Umar] berkata, 'Aku mendengar Nabi shallallahu 'alaihi wasallam.\""},"6591":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ حَدَّثَنَا عُقَيْلٌ عَنْ ابْنِ شِهَابٍ حَدَّثَنَا حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ احْتَجَّ آدَمُ وَمُوسَى فَقَالَ مُوسَى أَنْتَ آدَمُ الَّذِي أَخْرَجْتَ ذُرِّيَّتَكَ مِنْ الْجَنَّةِ قَالَ آدَمُ أَنْتَ مُوسَى الَّذِي اصْطَفَاكَ اللَّهُ بِرِسَالَاتِهِ وَكَلَامِهِ ثُمَّ تَلُومُنِي عَلَى أَمْرٍ قَدْ قُدِّرَ عَلَيَّ قَبْلَ أَنْ أُخْلَقَ فَحَجَّ آدَمُ مُوسَى","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] telah menceritakan kepada kami [Uqail] dari [Ibn Syihab] telah menceritakan kepada kami [Humaid bin Abdurrahman] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Adam dan Musa berbantah-bantahan pada hari kiamat, Musa berkata kepada Adam, 'Engkaulah penyebab yang mengeluarkan anak cucumu dari surga! ' Sedang Adam berkata, 'Engkau Musa, yang Allah telah memilihmu dengan risalah-Nya dan kalam-Nya, engkau mencelaku atas sesuatu yang telah ditakdirkan bagiku sebelum aku dicipta! ' Maka Adam lah yang mengalahkan Musa.\""},"6592":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُجْمَعُ الْمُؤْمِنُونَ يَوْمَ الْقِيَامَةِ فَيَقُولُونَ لَوْ اسْتَشْفَعْنَا إِلَى رَبِّنَا فَيُرِيحُنَا مِنْ مَكَانِنَا هَذَا فَيَأْتُونَ آدَمَ فَيَقُولُونَ لَهُ أَنْتَ آدَمُ أَبُو الْبَشَرِ خَلَقَكَ اللَّهُ بِيَدِهِ وَأَسْجَدَ لَكَ الْمَلَائِكَةَ وَعَلَّمَكَ أَسْمَاءَ كُلِّ شَيْءٍ فَاشْفَعْ لَنَا إِلَى رَبِّنَا حَتَّى يُرِيحَنَا فَيَقُولُ لَهُمْ لَسْتُ هُنَاكُمْ فَيَذْكُرُ لَهُمْ خَطِيئَتَهُ الَّتِي أَصَابَ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Qatadah] dari [Anas] radliyallahu'anhu berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang mukmin dikumpulkan pada hari kiamat dan berkata, 'Duh sekiranya kita bisa meminta syafaat untuk kami kepada tuhan kami, sehingga Allah bisa memberi kenyamanan bagi kami dari tempat kami ini.' Lantas mereka mendatangi Adam seraya berkata, 'Hai Adam, engkau adalah nenek moyang seluruh manusia, Allah telah menciptamu dengan tangan-Nya, Allah telah menyuruh para malaikat untuk sujud kepadamu, dan Dia mengajarimu nama-nama segala sesuatu, maka mintalah syafaat untuk kami kepada Tuhan kami sehingga Allah bisa memberi kenyamanan bagi kami.' Maka Adam berkata, 'Aku tidak berhak melakukan itu untuk kalian, ' lantas Adam menceritakan kesalahan yang pernah dilakukannya.\""},"6593":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنِي سُلَيْمَانُ عَنْ شَرِيكِ بْنِ عَبْدِ اللَّهِ أَنَّهُ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُلَيْلَةَ أُسْرِيَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ مَسْجِدِ الْكَعْبَةِ أَنَّهُ جَاءَهُ ثَلَاثَةُ نَفَرٍ قَبْلَ أَنْ يُوحَى إِلَيْهِ وَهُوَ نَائِمٌ فِي الْمَسْجِدِ الْحَرَامِ فَقَالَ أَوَّلُهُمْ أَيُّهُمْ هُوَ فَقَالَ أَوْسَطُهُمْ هُوَ خَيْرُهُمْ فَقَالَ آخِرُهُمْ خُذُوا خَيْرَهُمْ فَكَانَتْ تِلْكَ اللَّيْلَةَ فَلَمْ يَرَهُمْ حَتَّى أَتَوْهُ لَيْلَةً أُخْرَى فِيمَا يَرَى قَلْبُهُ وَتَنَامُ عَيْنُهُ وَلَا يَنَامُ قَلْبُهُ وَكَذَلِكَ الْأَنْبِيَاءُ تَنَامُ أَعْيُنُهُمْ وَلَا تَنَامُ قُلُوبُهُمْ فَلَمْ يُكَلِّمُوهُ حَتَّى احْتَمَلُوهُ فَوَضَعُوهُ عِنْدَ بِئْرِ زَمْزَمَ فَتَوَلَّاهُ مِنْهُمْ جِبْرِيلُ فَشَقَّ جِبْرِيلُ مَا بَيْنَ نَحْرِهِ إِلَى لَبَّتِهِ حَتَّى فَرَغَ مِنْ صَدْرِهِ وَجَوْفِهِ فَغَسَلَهُ مِنْ مَاءِ زَمْزَمَ بِيَدِهِ حَتَّى أَنْقَى جَوْفَهُ ثُمَّ أُتِيَ بِطَسْتٍ مِنْ ذَهَبٍ فِيهِ تَوْرٌ مِنْ ذَهَبٍ مَحْشُوًّا إِيمَانًا وَحِكْمَةً فَحَشَا بِهِ صَدْرَهُ وَلَغَادِيدَهُ يَعْنِي عُرُوقَ حَلْقِهِ ثُمَّ أَطْبَقَهُ ثُمَّ عَرَجَ بِهِ إِلَى السَّمَاءِ الدُّنْيَا فَضَرَبَ بَابًا مِنْ أَبْوَابِهَا فَنَادَاهُ أَهْلُ السَّمَاءِ مَنْ هَذَا فَقَالَ جِبْرِيلُ قَالُوا وَمَنْ مَعَكَ قَالَ مَعِيَ مُحَمَّدٌ قَالَ وَقَدْ بُعِثَ قَالَ نَعَمْ قَالُوا فَمَرْحَبًا بِهِ وَأَهْلًا فَيَسْتَبْشِرُ بِهِ أَهْلُ السَّمَاءِ لَا يَعْلَمُ أَهْلُ السَّمَاءِ بِمَا يُرِيدُ اللَّهُ بِهِ فِي الْأَرْضِ حَتَّى يُعْلِمَهُمْ فَوَجَدَ فِي السَّمَاءِ الدُّنْيَا آدَمَ فَقَالَ لَهُ جِبْرِيلُ هَذَا أَبُوكَ آدَمُ فَسَلِّمْ عَلَيْهِ فَسَلَّمَ عَلَيْهِ وَرَدَّ عَلَيْهِ آدَمُ وَقَالَ مَرْحَبًا وَأَهْلًا بِابْنِي نِعْمَ الِابْنُ أَنْتَ فَإِذَا هُوَ فِي السَّمَاءِ الدُّنْيَا بِنَهَرَيْنِ يَطَّرِدَانِ فَقَالَ مَا هَذَانِ النَّهَرَانِ يَا جِبْرِيلُ قَالَ هَذَا النِّيلُ وَالْفُرَاتُ عُنْصُرُهُمَا ثُمَّ مَضَى بِهِ فِي السَّمَاءِ فَإِذَا هُوَ بِنَهَرٍ آخَرَ عَلَيْهِ قَصْرٌ مِنْ لُؤْلُؤٍ وَزَبَرْجَدٍ فَضَرَبَ يَدَهُ فَإِذَا هُوَ مِسْكٌ أَذْفَرُ قَالَ مَا هَذَا يَا جِبْرِيلُ قَالَ هَذَا الْكَوْثَرُ الَّذِي خَبَأَ لَكَ رَبُّكَ ثُمَّ عَرَجَ بِهِ إِلَى السَّمَاءِ الثَّانِيَةِ فَقَالَتْ الْمَلَائِكَةُ لَهُ مِثْلَ مَا قَالَتْ لَهُ الْأُولَى مَنْ هَذَا قَالَ جِبْرِيلُ قَالُوا وَمَنْ مَعَكَ قَالَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا وَقَدْ بُعِثَ إِلَيْهِ قَالَ نَعَمْ قَالُوا مَرْحَبًا بِهِ وَأَهْلًا ثُمَّ عَرَجَ بِهِ إِلَى السَّمَاءِ الثَّالِثَةِ وَقَالُوا لَهُ مِثْلَ مَا قَالَتْ الْأُولَى وَالثَّانِيَةُ ثُمَّ عَرَجَ بِهِ إِلَى الرَّابِعَةِ فَقَالُوا لَهُ مِثْلَ ذَلِكَ ثُمَّ عَرَجَ بِهِ إِلَى السَّمَاءِ الْخَامِسَةِ فَقَالُوا مِثْلَ ذَلِكَ ثُمَّ عَرَجَ بِهِ إِلَى السَّمَاءِ السَّادِسَةِ فَقَالُوا لَهُ مِثْلَ ذَلِكَ ثُمَّ عَرَجَ بِهِ إِلَى السَّمَاءِ السَّابِعَةِ فَقَالُوا لَهُ مِثْلَ ذَلِكَ كُلُّ سَمَاءٍ فِيهَا أَنْبِيَاءُ قَدْ سَمَّاهُمْ فَأَوْعَيْتُ مِنْهُمْ إِدْرِيسَ فِي الثَّانِيَةِ وَهَارُونَ فِي الرَّابِعَةِ وَآخَرَ فِي الْخَامِسَةِ لَمْ أَحْفَظْ اسْمَهُ وَإِبْرَاهِيمَ فِي السَّادِسَةِ وَمُوسَى فِي السَّابِعَةِ بِتَفْضِيلِ كَلَامِ اللَّهِ فَقَالَ مُوسَى رَبِّ لَمْ أَظُنَّ أَنْ يُرْفَعَ عَلَيَّ أَحَدٌ ثُمَّ عَلَا بِهِ فَوْقَ ذَلِكَ بِمَا لَا يَع��لَمُهُ إِلَّا اللَّهُ حَتَّى جَاءَ سِدْرَةَ الْمُنْتَهَى وَدَنَا لِلْجَبَّارِ رَبِّ الْعِزَّةِ فَتَدَلَّى حَتَّى كَانَ مِنْهُ قَابَ قَوْسَيْنِ أَوْ أَدْنَى فَأَوْحَى اللَّهُ فِيمَا أَوْحَى إِلَيْهِ خَمْسِينَ صَلَاةً عَلَى أُمَّتِكَ كُلَّ يَوْمٍ وَلَيْلَةٍ ثُمَّ هَبَطَ حَتَّى بَلَغَ مُوسَى فَاحْتَبَسَهُ مُوسَى فَقَالَ يَا مُحَمَّدُ مَاذَا عَهِدَ إِلَيْكَ رَبُّكَ قَالَ عَهِدَ إِلَيَّ خَمْسِينَ صَلَاةً كُلَّ يَوْمٍ وَلَيْلَةٍ قَالَ إِنَّ أُمَّتَكَ لَا تَسْتَطِيعُ ذَلِكَ فَارْجِعْ فَلْيُخَفِّفْ عَنْكَ رَبُّكَ وَعَنْهُمْ فَالْتَفَتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى جِبْرِيلَ كَأَنَّهُ يَسْتَشِيرُهُ فِي ذَلِكَ فَأَشَارَ إِلَيْهِ جِبْرِيلُ أَنْ نَعَمْ إِنْ شِئْتَ فَعَلَا بِهِ إِلَى الْجَبَّارِ فَقَالَ وَهُوَ مَكَانَهُ يَا رَبِّ خَفِّفْ عَنَّا فَإِنَّ أُمَّتِي لَا تَسْتَطِيعُ هَذَا فَوَضَعَ عَنْهُ عَشْرَ صَلَوَاتٍ ثُمَّ رَجَعَ إِلَى مُوسَى فَاحْتَبَسَهُ فَلَمْ يَزَلْ يُرَدِّدُهُ مُوسَى إِلَى رَبِّهِ حَتَّى صَارَتْ إِلَى خَمْسِ صَلَوَاتٍ ثُمَّ احْتَبَسَهُ مُوسَى عِنْدَ الْخَمْسِ فَقَالَ يَا مُحَمَّدُ وَاللَّهِ لَقَدْ رَاوَدْتُ بَنِي إِسْرَائِيلَ قَوْمِي عَلَى أَدْنَى مِنْ هَذَا فَضَعُفُوا فَتَرَكُوهُ فَأُمَّتُكَ أَضْعَفُ أَجْسَادًا وَقُلُوبًا وَأَبْدَانًا وَأَبْصَارًا وَأَسْمَاعًا فَارْجِعْ فَلْيُخَفِّفْ عَنْكَ رَبُّكَ كُلَّ ذَلِكَ يَلْتَفِتُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى جِبْرِيلَ لِيُشِيرَ عَلَيْهِ وَلَا يَكْرَهُ ذَلِكَ جِبْرِيلُ فَرَفَعَهُ عِنْدَ الْخَامِسَةِ فَقَالَ يَا رَبِّ إِنَّ أُمَّتِي ضُعَفَاءُ أَجْسَادُهُمْ وَقُلُوبُهُمْ وَأَسْمَاعُهُمْ وَأَبْصَارُهُمْ وَأَبْدَانُهُمْ فَخَفِّفْ عَنَّا فَقَالَ الْجَبَّارُ يَا مُحَمَّدُ قَالَ لَبَّيْكَ وَسَعْدَيْكَ قَالَ إِنَّهُ لَا يُبَدَّلُ الْقَوْلُ لَدَيَّ كَمَا فَرَضْتُهُ عَلَيْكَ فِي أُمِّ الْكِتَابِ قَالَ فَكُلُّ حَسَنَةٍ بِعَشْرِ أَمْثَالِهَا فَهِيَ خَمْسُونَ فِي أُمِّ الْكِتَابِ وَهِيَ خَمْسٌ عَلَيْكَ فَرَجَعَ إِلَى مُوسَى فَقَالَ كَيْفَ فَعَلْتَ فَقَالَ خَفَّفَ عَنَّا أَعْطَانَا بِكُلِّ حَسَنَةٍ عَشْرَ أَمْثَالِهَا قَالَ مُوسَى قَدْ وَاللَّهِ رَاوَدْتُ بَنِي إِسْرَائِيلَ عَلَى أَدْنَى مِنْ ذَلِكَ فَتَرَكُوهُ ارْجِعْ إِلَى رَبِّكَ فَلْيُخَفِّفْ عَنْكَ أَيْضًا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مُوسَى قَدْ وَاللَّهِ اسْتَحْيَيْتُ مِنْ رَبِّي مِمَّا اخْتَلَفْتُ إِلَيْهِ قَالَ فَاهْبِطْ بِاسْمِ اللَّهِ قَالَ وَاسْتَيْقَظَ وَهُوَ فِي مَسْجِدِ الْحَرَامِ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] telah menceritakan kepadaku [Sulaiman] dari [Syarik bin Abdullah] berkata, \"Aku mendengar [Anas bin Malik] berkata, \"Tatkala Rasulullah shallallahu 'alaihi wasallam diisra'kan dari masjid Ka'bah, beliau didatangi oleh tiga orang -yang ketika itu beliau belum menerima wahyu- ketika di masjidil haram. Laki-laki pertama berkata, 'Mana orangnya? ' Laki-laki kedua berkata, 'Itu, orang terbaik di antara mereka! ' Lantas laki-laki ketiga berkata, 'Ambillah orang terbaik mereka', pada malam itu beliau tidak bisa melihat mereka bertiga. Hingga pada malam berikutnya mereka mendatangi beliau lagi, yang ketika itu hati (beliau) melihat, mata beliau tidur namun tidak untuk hatinya. Demikian pula para nabi, mata mereka tertidur namun hati mereka tidak tidur. Para malaikat itu tidak mengajak bicara beliau hingga mereka membawa dan meletakkan beliau di sisi sumur zamzam, Jibril lantas memimpin mereka untuk menyucikan nabi. Jibril kemudian membelah antara tenggorokan beliau hingga pangkal lehernya, sampai dadanya dan perutnya. Jibril kemudian memandikan beliau dengan air zamzam dengan tangannya hingga sampai pada bagian perut, setelah itu didatangkanlah bejana besar dari emas yang di dalamnya ada bejana yang terbuat dari tanah liat dari emas yang diisi dengan keimanan dan hikmah. Dengannya, Jibril mengisi dada dan urat-urat kerongkongannya lalu menjahitnya kembali. Kemudian Jibril membawanya ke langit dunia dan ia ketuk salah satu pintunya sehingga penghuni langit bertanya, 'Siapakah ini? ' Jibril berkata, 'Para malaikat bertanya, 'Siapa yang bersamamu? ' Jibril menjawab, 'Bersamaku Muhammad.' Penghuni langit bertanya, 'Dia telah diutus? ' Jibril menjawab, 'Benar.' Penghuni langit lalu berkata, 'Selamat datang, selamat atas kunjungannya.' Maka penghuni langit sedemikian bergembira, mereka tidak tahu apa yang Allah inginkan terhadap diri Muhammad di muka bumi, hingga Allah memberitahu mereka. Lantas di langit dunia nabi bertemu Adam, Jibril memperkenalkan kepada beliau, 'Ini adalah ayahmu, Adam. Ucapkanlah salam kepadanya. Dia (Muhammad) lalu mengucapkan salam yang kemudian dijawab oleh Adam seraya, 'Selamat datang, selamat berkunjung wahai anakku, sungguh engkau anak yang terbaik.' Ternyata di langit dunia ada dua sungai yang mengalir, Nabi Muhammad bertanya, 'Dua sungai apa ini wahai Jibril? ' Jibril menjawab, 'Ini adalah Nil dan Eufrat.' Kemudian Jibril terus membawa Nabi ke langit, tiba-tiba ada sungai lain yang di atasnya ada istana dari mutiara dan intan, Nabi memukulnya dengan tangannya, tiba-tiba baunya seperti minyak wangi adlfar. Nabi bertanya, 'Ini apa wahai Jibril? ' Jibril menjawab, 'Ini adalah telaga al Kautsar yang sengaja disimpan oleh Tuhanmu untukmu.' Kemudian Jibril membawanya naik ke langit kedua, dan malaikat bertanya kepadanya seperti yang ditanyakan malaikat pada langit pertama. Mereka bertanya, 'Siapa ini? ' Jibril menjawab, 'Ini Jibril.' Mereka bertanya lagi, 'Dan siapa ini yang bersamamu? ' Jibril menjawab, 'Muhammad shallallahu 'alaihi wasallam.' Mereka bertanya, 'Apakah dia telah diutus? ' Jibril menjawab, 'Benar.' Malaikat (langit tersebut) lalu berkata, 'Selamat datang, selamat atas kunjungannya.' Jibril kemudian membawanya naik ke langit ketiga dan para malaikat bertanya kepadanya sebagaimana yang ditanyakan malaikat di langit pertama dan kedua, kemudian Jibril membawanya naik ke langit keempat, dan mereka bertanya seperti halnya pertanyaan malaikat sebelumnya, setiap langit berisikan para nabi yang Jibril sebutkan nama-namanya. Dan seingatku di antara mereka ada Idris di langit kedua, Harun di langit keempat, dan lain di langit ke lima yang aku tak hapal namanya, Ibrahim di langit keenam, dan Musa di langit ketujuh karena diberi kelebihan bisa berbicara langsung dengan Allah. Lantas Musa berkata, 'Wahai Rabb, setahuku tak ada orang yang lebih ditinggikan daripada aku, ' kemudian Jibril membawanya naik di atas kesemuanya yang tidak satupun yang tahu selain Allah hingga tiba di Sidratul Muntaha. Kemudian Jibril mendekati Allah, Al Jabbar, Rabb pemilik kemuliaan, Nabi terus mendekat hingga jarak antara keduanya sebatas dua busur panah atau lebih dekat lagi, dan Allah memberinya wahyu, yang di antara wahyunya, Allah mewajibkan lima puluh kali shalat untuk umatmu (Muhammad) siang-malam. Kemudian Nabi turun hingga bertemu Musa, Musa menahannya dan berkata, 'Hai Muhammad, apa yang diikrarkan Tuhanmu kepadamu? ' Nabi menjawab, 'Allah mewajibkan aku untuk mendirikan lima puluh kali shalat sehari semalam.' Musa berkata, 'Umatmu tak bakalan kuat melakukan sedemikian itu, kembalilah kamu agar Tuhanmu memberi keringanan untkmu dan umatmu.' Maka Nabi menoleh ke Jibril seolah-olah meminta saran tentang saran Musa, dan Jibril memberi isyarat, 'Silahkan, kalau kau berkenan.' Maka Jibril kembali menaikannya ke Allah Yang Maha Jabbar yang ketika itu masih berada di singgahsana-Nya, Nabi katakan, 'Wahai Rabb, berilah kami keringanan, sebab umatku tak bakalan mampu melakukan shalat lima puluh kali dalam sehari! ' Lantas Allah mengurangi sepuluh kali, dan Nabi kembali bertemu Musa dan Musa menahannya, Musa terus-menerus membujuknya agar Nabi menegoisasi ulang kepada Rabbnya, sehingga Allah hanya mewajibkan lima kali shalat sehari-semalam. Musa kemudian menahannya ketika kewajiban shalat tinggal lima, Musa mengatakan, 'Hai Muhammad, pernah aku membujuk Bani Israil, kaumku, untuk suatu yang lebih rendah daripada ini namun mereka meninggalkannya, padahal umatmu lebih lemah fisiknya, badannya, hatinya, pandangan dan pendengarannya, maka temuilah kembali Rabbmu agar Dia memberi keringanan.' Dan atas semua instruksi itu, Nabi menoleh kepada Jibril untuk memberi saran, namun Jibril tidak membenci atas itu semua. Lantas Jibril kembali membawanya naik untuk kali kelima, lalu Nabi berkata, 'Ya Rabb, umatku adalah orang-orang lemah fisiknya, hatinya, pendengarannya, pandangannya, dan badannya, maka berilah kami keringanan.' Allah Yang Maha Jabbar menjawab, 'Hai Muhammad! ' Nabi menjawab, 'Aku penuhi panggilan-Mu.' Allah meneruskan firman-Nya, 'Sesungguhnya tidak ada lagi pergantian titah-Ku sebagaimana Aku wajibkan atasmu dalam ummul kitab.' Allah meneruskan titah-Nya, setiap satu kebaikan dibalas sepuluh kali lipatnya, maka lima kali shalat itu tercatat lima puluh kali dalam ummul kitab, sekalipun hanya dilaksanakan lima kali olehmu.' Maka Nabi kembali menemui Musa dan Musa bertanya, 'Apa yang telah kamu lakukan? ' Nabi menjawab, 'Allah betul-betul telah memberi kami keringanan, karena setiap kebaikan dibalas sepuluh kali lipatnya.' Musa berkata, 'Demi Allah, aku pernah membujuk bani israil untuk yang lebih remeh daripada itu namun mereka meninggalkannya, maka kembalilah kau temui Tuhanmu agar Dia memberi keringanan terhadapmu.' Rasulullah shallallahu 'alaihi wasallam menjawab, 'Hai Musa, demi Allah, aku telah malu kepada Tuhanku terhadap protes yang kulakukan terhadap-Nya.' Musa pun berkata, 'Baik kalau begitu, silahkan engkau turun dengan nama Allah.' Maka Nabi bangun (tidur) yang ketika itu beliau di Masjidil Haram.\""},"6594":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ حَدَّثَنِي ابْنُ وَهْبٍ قَالَ حَدَّثَنِي مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يَقُولُ لِأَهْلِ الْجَنَّةِ يَا أَهْلَ الْجَنَّةِ فَيَقُولُونَ لَبَّيْكَ رَبَّنَا وَسَعْدَيْكَ وَالْخَيْرُ فِي يَدَيْكَ فَيَقُولُ هَلْ رَضِيتُمْ فَيَقُولُونَ وَمَا لَنَا لَا نَرْضَى يَا رَبِّ وَقَدْ أَعْطَيْتَنَا مَا لَمْ تُعْطِ أَحَدًا مِنْ خَلْقِكَ فَيَقُولُ أَلَا أُعْطِيكُمْ أَفْضَلَ مِنْ ذَلِكَ فَيَقُولُونَ يَا رَبِّ وَأَيُّ شَيْءٍ أَفْضَلُ مِنْ ذَلِكَ فَيَقُولُ أُحِلُّ عَلَيْكُمْ رِضْوَانِي فَلَا أَسْخَطُ عَلَيْكُمْ بَعْدَهُ أَبَدًا","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] telah menceritakan kepadaku [Ibn Wahb] berkata, telah menceritakan kepadaku [Malik] dari [Zaid bin Aslam] dari ['Atha' bin Yasar] dari [Abu Sa'id Al Khudzri] radliyallahu'anhu berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Allah memanggil penduduk surga, 'Hai penduduk surga! ' Mereka menjawab, 'Baik, kami penuhi panggilan-Mu, dan seluruh kebaikan berada di tangan-Mu! Allah meneruskan, 'Apakah kalian telah puas! ' Mereka menjawab, 'Bagaimanakah kami tidak puas wahai Rabb, sedang telah Engkau beri kami sesuatu yang belum pernah Engkau berikan kepada satu pun dari makhluk-Mu! Allah kembali berkata, 'Maukah Aku beri kalian suatu yang lebih utama daripada itu semua? ' Mereka balik bertanya, 'Ya Rabb, apalagi yang lebih utama daripada itu semua? ' Allah menjawab, 'Sekarang Aku halalkan untuk kalian keredlaan-Ku, sehingga Aku tidak marah terhadap kalian selama-lamanya! '"},"6595":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سِنَانٍ حَدَّثَنَا فُلَيْحٌ حَدَّثَنَا هِلَالٌ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَوْمًا يُحَدِّثُ وَعِنْدَهُ رَجُلٌ مِنْ أَهْلِ الْبَادِيَةِ أَنَّ رَجُلًا مِنْ أَهْلِ الْجَنَّةِ اسْتَأْذَنَ رَبَّهُ فِي الزَّرْعِ فَقَالَ لَهُ أَوَلَسْتَ فِيمَا شِئْتَ قَالَ بَلَى وَلَكِنِّي أُحِبُّ أَنْ أَزْرَعَ فَأَسْرَعَ وَبَذَرَ فَتَبَادَرَ الطَّرْفَ نَبَاتُهُ وَاسْتِوَاؤُهُ وَاسْتِحْصَادُهُ وَتَكْوِيرُهُ أَمْثَالَ الْجِبَالِ فَيَقُولُ اللَّهُ تَعَالَى دُونَكَ يَا ابْنَ آدَمَ فَإِنَّهُ لَا يُشْبِعُكَ شَيْءٌ فَقَالَ الْأَعْرَابِيُّ يَا رَسُولَ اللَّهِ لَا تَجِدُ هَذَا إِلَّا قُرَشِيًّا أَوْ أَنْصَارِيًّا فَإِنَّهُمْ أَصْحَابُ زَرْعٍ فَأَمَّا نَحْنُ فَلَسْنَا بِأَصْحَابِ زَرْعٍ فَضَحِكَ رَسُولُ اللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Sinan] telah menceritakan kepada kami [Fulaih] telah menceritakan kepada kami [Hilal] dari ['Atha' bin Yasar] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam suatu hari menyampaikan hadis sedang di sisinya ada seorang arab badui: \"Ada seorang penduduk surga meminta ijin Tuhannya untuk menanam. Allah berujar, 'Bukankah engkau diperkenankan sekehendakmu! ' Orang tersebut menjawab, 'Memang, namun aku ingin menanam! ' Orang itu kemudian bergegas menabur benih, dan ujung-ujung tanamannya sedemikian cepat tumbuh, juga perkembangbiakannya, sehingga ia juga cepat memanen, yang himpunan panenannya sebesar gunung. Kemudian Allah berfirman, 'Silahkan kau ambil hai Anak adam, sungguh tak ada sesuatu yang menjadikanmu puas! ' Maka si arab badui berkata, 'Wahai Rasulullah, (jika demikian) tidak akan engkau temukan seperti orang ini selain dari Quraisy atau orang anshar, sebab mereka hobi bercocok tanam, adapun kami, tidak suka bercocok tanam! Rasulullah pun menjadi tertawa.\""},"6596":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا ج��رِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ عَنْ عَبْدِ اللَّهِ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الذَّنْبِ أَعْظَمُ عِنْدَ اللَّهِ قَالَ أَنْ تَجْعَلَ لِلَّهِ نِدًّا وَهُوَ خَلَقَكَ قُلْتُ إِنَّ ذَلِكَ لَعَظِيمٌ قُلْتُ ثُمَّ أَيُّ قَالَ ثُمَّ أَنْ تَقْتُلَ وَلَدَكَ تَخَافُ أَنْ يَطْعَمَ مَعَكَ قُلْتُ ثُمَّ أَيُّ قَالَ ثُمَّ أَنْ تُزَانِيَ بِحَلِيلَةِ جَارِكَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Wail] dari ['Amru bin Syurahbil] dari ['Abdullah] berkata, \"Pernah aku bertanya Nabi Shallahu'alaijiwasallam, dosa apa yang paling besar di sisi Allah?\" Nabi menjawab, \"Engkau menjadikan tandingan untuk Allah, padahal Dialah yang menciptamu.\" Aku lalu berkata, \"Jika demikian berarti itu memang perkara besar!\" kemudian aku bertanya lagi, 'Lalu apa lagi? ' Nabi menjawab: \"Engkau membunuh anakmu karena kamu khawatir akan makan bersamamu.\" Kemudian saya bertanya, \"Lantas apa lagi?\" Nabi menjawab: \"Engkau berzina dengan isteri tetanggamu.\""},"6597":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا مَنْصُورٌ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَاجْتَمَعَ عِنْدَ الْبَيْتِ ثَقَفِيَّانِ وَقُرَشِيٌّ أَوْ قُرَشِيَّانِ وَثَقَفِيٌّ كَثِيرَةٌ شَحْمُ بُطُونِهِمْ قَلِيلَةٌ فِقْهُ قُلُوبِهِمْ فَقَالَ أَحَدُهُمْ أَتَرَوْنَ أَنَّ اللَّهَ يَسْمَعُ مَا نَقُولُ قَالَ الْآخَرُ يَسْمَعُ إِنْ جَهَرْنَا وَلَا يَسْمَعُ إِنْ أَخْفَيْنَا وَقَالَ الْآخَرُ إِنْ كَانَ يَسْمَعُ إِذَا جَهَرْنَا فَإِنَّهُ يَسْمَعُ إِذَا أَخْفَيْنَا فَأَنْزَلَ اللَّهُ تَعَالَى{ وَمَا كُنْتُمْ تَسْتَتِرُونَ أَنْ يَشْهَدَ عَلَيْكُمْ سَمْعُكُمْ وَلَا أَبْصَارُكُمْ وَلَا جُلُودُكُمْ }الْآيَةَ","id":"Telah menceritakan kepada kami [Humaidi] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Manshur] dari [Mujahid] dari [Abu Ma'mar] dari [Abdullah] radliyallahu'anhu berkata, \"Ada dua orang kabilah Tsaqif dan seorang qurays, atau dua orang qurasy. Salah seorang dari kabilah Tsaqif lemak perutnya terlihat banyak sekali, sementara kefakihan hati mereka sangat minim. Lalu salah seorang dari mereka berkata, 'Apa menurutmu Allah akan mendengar apa yang kita ucapkan? ' Sedang lainnya berkata, 'Allah mendengar jika kita mengucapkan dengan lantang, dan Dia tidak mendengar jika kita mengucapkan dengan lirih (rahasia).' Lantas lainnya berkata, 'Apabila Dia mendengar jika kita mengucapkan secara lantang, tentu Dia juga mendengar jika kita mengucapkan secara lirih! Lantas Allah menurunkan ayat: '(Dan apa saja yang kalian sembunyikan, akan bersaksi atas kalian, pendengaran kalian, tidak pula penglihatan kalian dan tidak pula kulit kalian) ', (Qs. Fushshilat: ayat 22)."},"6598":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا حَاتِمُ بْنُ وَرْدَانَ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَيْفَ تَسْأَلُونَ أَهْلَ الْكِتَابِ عَنْ كُتُبِهِمْ وَعِنْدَكُمْ كِتَابُ اللَّهِ أَقْرَبُ الْكُتُبِ عَهْدًا بِاللَّهِ تَقْرَءُونَهُ مَحْضًا لَمْ يُشَبْ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Hatim bin Wardan] telah menceritakan kepada kami [Ayyub] dari ['Ikrimah] dari [Ibn Abbas] radliyallahu'anhuma, ia berkata, \"Bagaimana kalian bertanya ahli kitab tentang kitab mereka padahal kalian mempunyai Kitabullah, kitab yang paling dekat janjinya kepada Allah, yang kalian membacanya dengan tidak dicampuri hal-hal lainnya.\""},"6599":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ قَالَيَا مَعْشَرَ الْمُسْلِمِينَ كَيْفَ تَسْأَلُونَ أَهْلَ الْكِتَابِ عَنْ شَيْءٍ وَكِتَابُكُمْ الَّذِي أَنْزَلَ اللَّهُ عَلَى نَبِيِّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْدَثُ الْأَخْبَارِ بِاللَّهِ مَحْضًا لَمْ يُشَبْ وَقَدْ حَدَّثَكُمْ اللَّهُ أَنَّ أَهْلَ الْكِتَابِ قَدْ بَدَّلُوا مِنْ كُتُبِ اللَّهِ وَغَيَّرُوا فَكَتَبُوا بِأَيْدِيهِمْ الْكُتُبَ قَالُوا هُوَ مِنْ عِنْدِ اللَّهِ لِيَشْتَرُوا بِذَلِكَ ثَمَنًا قَلِيلًا أَوَلَا يَنْهَاكُمْ مَا جَاءَكُمْ مِنْ الْعِلْمِ عَنْ مَسْأَلَتِهِمْ فَلَا وَاللَّهِ مَا رَأَيْنَا رَجُلًا مِنْهُمْ يَسْأَلُكُمْ عَنْ الَّذِي أُنْزِلَ عَلَيْكُمْ","id":"Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Azzuhri] telah mengabarkan kepadaku ['Ubaidullah bin Abdullah] bahwa [Abdullah bin Abbas] berkata, \"Wahai segenap muslimin, bagaimana kalian bertanya ahli kitab tentang sesuatu, sedang kitab kalian yang Allah turunkan kepada nabi kalian shallallahu 'alaihi wasallam adalah berita paling baru tentang Allah yang tidak dicampuri oleh sesutu apapun, dan Allah telah menceritakan kepada kalian bahwa ahli kitab mengubah-ubah kitab Allah dan merubah-rubahnya. Setelah itu mereka tulis kitab-kitab Allah dengan tangannya, dan mereka katakan, 'Ini dari Allah', yang demikian untuk mereka beli dengan harga yang sedikit, tidakkah ilmu yang datang kepada kalian melarang kalian bertanya kepada mereka? Tidak, demi Allah, tidak akan kami lihat salah seorang di antara mereka bertanya kalian tentang yang diturunkan kepada kalian.\""},"6600":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مُوسَى بْنِ أَبِي عَائِشَةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ تَعَالَى{ لَا تُحَرِّكْ بِهِ لِسَانَكَ }قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَالِجُ مِنْ التَّنْزِيلِ شِدَّةً وَكَانَ يُحَرِّكُ شَفَتَيْهِ فَقَالَ لِي ابْنُ عَبَّاسٍ فَأَنَا أُحَرِّكُهُمَا لَكَ كَمَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحَرِّكُهُمَا فَقَالَ سَعِيدٌ أَنَا أُحَرِّكُهُمَا كَمَا كَانَ ابْنُ عَبَّاسٍ يُحَرِّكُهُمَا فَحَرَّكَ شَفَتَيْهِ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ لَا تُحَرِّكْ بِهِ لِسَانَكَ لِتَعْجَلَ بِهِ إِنَّ عَلَيْنَا جَمْعَهُ وَقُرْآنَهُ }قَالَ جَمْعُهُ فِي صَدْرِكَ ثُمَّ تَقْرَؤُهُ{ فَإِذَا قَرَأْنَاهُ فَاتَّبِعْ قُرْآنَهُ }قَالَ فَاسْتَمِعْ لَهُ وَأَنْصِتْ ثُمَّ إِنَّ عَلَيْنَا أَنْ تَقْرَأَهُ قَالَ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَاهُ جِبْرِيلُ عَلَيْهِ السَّلَام اسْتَمَعَ فَإِذَا انْطَلَقَ جِبْرِيلُ قَرَأَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا أَقْرَأَهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abu 'Awanah] dari [Musa bin Abu 'Aisyah] dari [Sa'id bin Jubair] dari [Ibn Abbas] tentang firman Allah: '(Jangan kamu gerakkan lisanmu) ' (Qs. Al Qiyamah: 16), Ibnu Abbas katakan, \"Nabi shallallahu 'alaihi wasallam merasa sangat kepayahan mengikuti wahyu yang diturunkan sehingga beliau gerak-gerakkan kedua bibirnya.\" Ibnu Abbas lantas berkata kepadaku, \"Maka aku gerakkan keduanya bagimu sebagaimana Rasulullah shallallahu 'alaihi wasallam menggerakkan keduanya.\" Sa'id berkata, \"Dan aku menggerakkan keduanya sebagaimana Ibnu Abbas menggerakkan keduanya, \" maka ia gerakkan kedua bibirnya sehingga Allah menurunkan ayat: '(Jangan engkau gerakkan lisanmu untuk membacanya agar kamu tergesa-gesa, sebab Kewajiban Kamilah yang mengumpulkannya dan membacakannya) ' (Qs. Al Qiyamah: 16-17). Ibn Abbas berkata, 'Mengumpulkan yang dimaksud adalah, mengumpulkan di dadamu, lantas kamu membacanya: '(Maka jika kami telah membacanya, maka ikutilah bacaannya) ' (Qs. Al Qiyamah: 18). Ibn 'Abbas berkata, 'Maka dengar dia baik-baik dan diamlah, kemudian Kami berkewajiban agar kamu mampu membacanya.\" Ibn Abbas berkata, \"Jika Jibril menemui Rasulullah shallallahu 'alaihi wasallam, maka beliau mendengarnya baik-baik, dan jika Jibril telah pulang, maka beliau membacanya sebagaimana Jibril membacakannya.\""},"6601":{"ar":"حَدَّثَنِي عَمْرُو بْنُ زُرَارَةَ عَنْ هُشَيْمٍ أَخْبَرَنَا أَبُو بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَافِي قَوْلِهِ تَعَالَى{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }قَالَ نَزَلَتْ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُخْتَفٍ بِمَكَّةَ فَكَانَ إِذَا صَلَّى بِأَصْحَابِهِ رَفَعَ صَوْتَهُ بِالْقُرْآنِ فَإِذَا سَمِعَهُ الْمُشْرِكُونَ سَبُّوا الْقُرْآنَ وَمَنْ أَنْزَلَهُ وَمَنْ جَاءَ بِهِ فَقَالَ اللَّهُ لِنَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَلَا تَجْهَرْ بِصَلَاتِكَ }أَيْ بِقِرَاءَتِكَ فَيَسْمَعَ الْمُشْرِكُونَ فَيَسُبُّوا الْقُرْآنَ{ وَلَا تُخَافِتْ بِهَا }عَنْ أَصْحَابِكَ فَلَا تُسْمِعُهُمْ{ وَابْتَغِ بَيْنَ ذَلِكَ سَبِيلًا }","id":"Telah menceritakan kepadaku ['Amru bin Zurarah] dari [Husyaim] telah mengabarkan kepada kami [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibn Abbas] radliyallahu'anhuma tentang firman Allah Ta'ala: '(Jangan kamu membacanya secara lantang dalam shalatmu, dan jangan pula secara lirih) ' (Qs. Al Isra': ayat 110), Ibn Abbas berkata, \"Ayat ini diturunkan saat Rasulullah shallallahu 'alaihi wasallam masih sembunyi-sembunyi di Makkah, jika shalat bersama sahabat-sahabatnya, beliau mengeraskan bacaan Al Qur'annya, sehingga jika kaum musyrikin mendengarnya, mereka mencaci Al Qur'an, Dzat yang menurunkannya dan malaikat yang membawanya. Maka Allah menegur nabi-Nya shallallahu 'alaihi wasallam shallallahu 'alaihi wasallam dengan ayat: '(Jangan kamu membacanya secara lantang dalam shalatmu) ' (Qs. Al Isra': ayat 110), yakni dengan bacaanmu, sehingga saat orang-orang Musyrik mendengar mereka akan mencela Al Qur'an, '(dan jangan pula secara lirih), yaitu kepada para sahabatmu, sehingga engkau tidak bisa menjadikan mereka mendengar, (Carilah jalan tengah antara keduanya) ', (Qs. Al Isra: ayat 110)."},"6602":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْنَزَلَتْ هَذِهِ الْآيَةُ{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }فِي الدُّعَاءِ","id":"Telah menceritakan kepada kami [Ubaid bin Ismail] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [Ayahnya] dari [Aisyah] radliyallahu'anha, ia berkata, \"Ayat ini: '(Janganlah kamu menyaringkan bacaanmu ketika shalatmu dan jangan pula membacanya terlalu lirih) ', (Qs. Al Isra`: Ayat 110), diturunkan berkenaan dengan doa.\""},"6603":{"ar":"حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا أَبُو عَاصِمٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنَا ابْنُ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنَّا مَنْ لَمْ يَتَغَنَّ بِالْقُرْآنِوَزَادَ غَيْرُهُ يَجْهَرُ بِهِ","id":"Telah menceritakan kepada kami [Ishaq] telah menceritakan kepada kami [Abu 'Ashim] telah mengabarkan kepada kami [Ibn Juraij] Telah mengabarkan kepada kami [Ibn Syihab] dari [Abu Salamah] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukan termasuk golongan kami orang yang tidak melagukan Al Qur'an, \" sementara yang lain menambahkan, 'dan mengeraskannya'.\""},"6604":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَحَاسُدَ إِلَّا فِي اثْنَتَيْنِ رَجُلٌ آتَاهُ اللَّهُ الْقُرْآنَ فَهُوَ يَتْلُوهُ آنَاءَ اللَّيْلِ وَآنَاءَ النَّهَارِ فَهُوَ يَقُولُ لَوْ أُوتِيتُ مِثْلَ مَا أُوتِيَ هَذَا لَفَعَلْتُ كَمَا يَفْعَلُ وَرَجُلٌ آتَاهُ اللَّهُ مَالًا فَهُوَ يُنْفِقُهُ فِي حَقِّهِ فَيَقُولُ لَوْ أُوتِيتُ مِثْلَ مَا أُوتِيَ عَمِلْتُ فِيهِ مِثْلَ مَا يَعْمَلُ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh iri kecuali dalam dua hal; seseorang yang Allah beri Al Qur'an, kemudian ia membacanya sepanjang siang dan malam. Lalu orang yang iri itu berkata 'Kalaulah aku diberi kepandaian seperti orang itu, niscaya kulakukan sepertinya.' Dan seseorang yang diberi harta, lantas dia membelanjakannya dalam haknya. Lalu orang yang iri itu berkata, 'Kalulah aku diberi harta si fulan, niscaya kulakukan seperti yang dilakukannya'.\""},"6605":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ الزُّهْرِيُّ عَنْ سَالِمٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا حَسَدَ إِلَّا فِي اثْنَتَيْنِ رَجُلٌ آتَاهُ اللَّهُ الْقُرْآنَ فَهُوَ يَتْلُوهُ آنَاءَ اللَّيْلِ وَآنَاءَ النَّهَارِ وَرَجُلٌ آتَاهُ اللَّهُ مَالًا فَهُوَ يُنْفِقُهُ آنَاءَ اللَّيْلِ وَآنَاءَ النَّهَارِسَمِعْتُ سُفْيَانَ مِرَارًا لَمْ أَسْمَعْهُ يَذْكُرُ الْخَبَرَ وَهُوَ مِنْ صَحِيحِ حَدِيثِهِ","id":"Telah menceritakan kepada kami ['Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] [Azzuhri] berkata dari [Salim] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak boleh iri kecuali dalam dua hal; seorang laki-laki yang Allah beri Al Qur'an, lantas ia membacanya di sepanjang malam dan sepanjang siang. Dan seorang laki-laki yang Allah beri harta, lantas ia membelanjakannya sepanjang malam dan sepanjang siang.\" Ali bin Abdullah berkata, \"Aku mendengar Sufyan berkali-kali, namun aku tidak mendengar ia menyebutkan hadits (dengan lafad akhbartu (aku mengabarkan), tetapi dengan lafad 'An (dari). Dan ini adalah hadits yang paling shahih dari yang ia punya.\""},"6606":{"ar":"حَدَّثَنَا الْفَضْلُ بْنُ يَعْقُوبَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الرَّقِّيُّ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ حَدَّثَنَا سَعِيدُ بْنُ عُبَيْدِ اللَّهِ الثَّقَفِيُّ حَدَّثَنَا بَكْرُ بْنُ عَبْدِ اللَّهِ الْمُزَنِيُّ وَزِيَادُ بْنُ جُبَيْرِ بْنِ حَيَّةَ عَنْ جُبَيْرِ بْنِ حَيَّةَ قَالَ الْمُغِيرَةُأَخْبَرَنَا نَبِيُّنَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ رِسَالَةِ رَبِّنَا أَنَّهُ مَنْ قُتِلَ مِنَّا صَارَ إِلَى الْجَنَّةِ","id":"Telah menceritakan kepada kami [Al Fadll bin Ya'qub] telah menceritakan kepada kami ['Abdullah bin Ja'far Ar Raqqi] telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] telah menceritakan kepada kami [Sa'id bin Ubaidullah Ats Tsaqafi] telah menceritakan kepada kami [Bakar bin Abdullah Al Muzani], dan [Ziyad bin Jubair bin Hayyah] dari [Jubair bin Hayyah], [Mughirah] berkata, \"Nabi shallallahu 'alaihi wasallam telah mengabarkan kepada kami dari risalah Rabb kami, bahwa siapa saja dari kami yang terbunuh, maka ia akan menuju surga.\""},"6607":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَاعِيلَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ مَنْ حَدَّثَكَ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَمَ شَيْئًا وَقَالَ مُحَمَّدٌ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ حَدَّثَنَا شُعْبَةُ عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْمَنْ حَدَّثَكَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَمَ شَيْئًا مِنْ الْوَحْيِ فَلَا تُصَدِّقْهُ إِنَّ اللَّهَ تَعَالَى يَقُولُ{ يَا أَيُّهَا الرَّسُولُ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ وَإِنْ لَمْ تَفْعَلْ فَمَا بَلَّغْتَ رِسَالَتَهُ }","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Ismail] dari [Asy Sya'bi] dari [Masruq] dari [Aisyah] radliyallahu'anhuma, ia berkata, \"Siapa saja yang menceritakan kepadamu bahwa Muhammad shallallahu 'alaihi wasallam menyembunyikan sesuatu…sedang [Muhammad] berkata, telah menceritakan kepada kami [Abu Amir Al 'Aqadi] telah menceritakan kepada kami [Syu'bah] dari [Ismail bin Abu Khalid] dari [Asy Sya'bi] dari [Masruq] dari ['Aisyah] berkata, \"Siapa saja yang menceritakan kepadamu bahwa Nabi shallallahu 'alaihi wasallam menyembunyikan sesuatu dari wahyu, maka janganlah kamu mempercayainya, sebab Allah Ta'ala berfirman: '(Wahai rasul, sampaikan yang diturunkan kepadamu dari Tuhanmu, jika kamu tidak mengerjakan lantas tidak kau sampaikan risalah….) ' (Qs. Al Maidah: 67)."},"6608":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ قَالَ قَالَ عَبْدُ اللَّهِقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَيُّ الذَّنْبِ أَكْبَرُ عِنْدَ اللَّهِ قَالَ أَنْ تَدْعُوَ لِلَّهِ نِدًّا وَهُوَ خَلَقَكَ قَالَ ثُمَّ أَيْ قَالَ ثُمَّ أَنْ تَقْتُلَ وَلَدَكَ مَخَافَةَ أَنْ يَطْعَمَ مَعَكَ قَالَ ثُمَّ أَيْ قَالَ أَنْ تُزَانِيَ حَلِيلَةَ جَارِكَ فَأَنْزَلَ اللَّهُ تَصْدِيقَهَا{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَلَا يَزْنُونَ وَمَنْ يَفْعَلْ ذَلِكَ يَلْقَ أَثَامًا يُضَاعَفْ لَهُ الْعَذَابُ }الْآيَةَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Wail] dari ['Amru bin Syurahbil] berkata, [Abdullah] berkata, \"Seorang laki-laki berkata, 'Wahai Rasulullah, dosa apakah yang terbesar di sisi Allah? ' Nabi menjawab: 'Engkau menjadikan tandingan bagi Allah, padahal Dialah yang menciptamu.' Laki-laki tersebut bertanya lagi, 'Lantas apa lagi? ' Nabi menjawab: 'Engkau bunuh anakmu karena khawatir makan bersamamu.' Laki-laki itu bertanya lagi, 'Lantas apa? ' Nabi menjawab: 'Engkau berzina dengan wanita tetanggamu.' Lantas Allah menurunkan ayat yang membenarkannya: '(Dan orang-orang yang tidak menyeru Tuhan lain disamping menyeru Allah, dan tidak membunuh jiwa yang Allah haramkan selain dengan alasan yang benar, dan tidak berzina, dan barangsiapa melakukan yang demikian ia akan memperoleh dosa dan akan dilipat gandakan siksa baginya) '. (Qs. Al Furqan: 68-69)."},"6609":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ أَخْبَرَنِي سَالِمٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا بَقَاؤُكُمْ فِيمَنْ سَلَفَ مِنْ الْأُمَمِ كَمَا بَيْنَ صَلَاةِ الْعَصْرِ إِلَى غُرُوبِ الشَّمْسِ أُوتِيَ أَهْلُ التَّوْرَاةِ التَّوْرَاةَ فَعَمِلُوا بِهَا حَتَّى انْتَصَفَ النَّهَارُ ثُمَّ عَجَزُوا فَأُعْطُوا قِيرَاطًا قِيرَاطًا ثُمَّ أُوتِيَ أَهْلُ الْإِنْجِيلِ الْإِنْجِيلَ فَعَمِلُوا بِهِ حَتَّى صُلِّيَتْ الْعَصْرُ ثُمَّ عَجَزُوا فَأُعْطُوا قِيرَاطًا قِيرَاطًا ثُمَّ أُوتِيتُمْ الْقُرْآنَ فَعَمِلْتُمْ بِهِ حَتَّى غَرَبَتْ الشَّمْسُ فَأُعْطِيتُمْ قِيرَاطَيْنِ قِيرَاطَيْنِ فَقَالَ أَهْلُ الْكِتَابِ هَؤُلَاءِ أَقَلُّ مِنَّا عَمَلًا وَأَكْثَرُ أَجْرًا قَالَ اللَّهُ هَلْ ظَلَمْتُكُمْ مِنْ حَقِّكُمْ شَيْئًا قَالُوا لَا قَالَ فَهُوَ فَضْلِي أُوتِيهِ مَنْ أَشَاءُ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Yunus] dari [Azzuhri] telah mengabarkan kepadaku [Salim] dari [Ibn Umar] radliyallahu'anhuma, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Keberadaan kalian di antara umat-umat terdahulu seperti permisalan antara antara shalat 'ashar hingga matahari terbenam. Pemeluk taurat diberi taurat dan mereka mengamalkannya hingga pertengahan siang, kemudian mereka tidak bisa lagi mengamalknnya sehingga diberi satu qirath. Kemudian pemeluk injil diberi injil dan mereka mengamalkannya hingga shalat 'ashar didirikan lantas mereka tidak bisa lagi mengamalkannya, dan mereka diberi satu qirath. Kemudian kalian diberi Al Qur'an dan kalian mengamalkannya hingga matahari terbenam, lantas kalian diberi dua qirath dua qirath. Orang-orang ahli kitab pun protes, 'Mereka (kaum muslimin) lebih sedikit bekerja daripada kami namun mengapa mereka lebih banyak pahalanya? ' Allah menjawab, 'Namun apakah berarti Aku menzhalimi hak kalian? ' Mereka menjawab, 'Tidak.' Allah kemudian firman-Nya: \"Itulah keutamaan-Ku yang Aku berikan kepada siapa yang Aku kehendaki.\" "},"6610":{"ar":"حَدَّثَنِي سُلَيْمَانُ حَدَّثَنَا شُعْبَةُ عَنْ الْوَلِيدِ ح و حَدَّثَنِي عَبَّادُ بْنُ يَعْقُوبَ الْأَسَدِيُّ أَخْبَرَنَا عَبَّادُ بْنُ الْعَوَّامِ عَنْ الشَّيْبَانِيِّ عَنْ الْوَلِيدِ بْنِ الْعَيْزَارِ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ عَنْ ابْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الْأَعْمَالِ أَفْضَلُ قَالَ الصَّلَاةُ لِوَقْتِهَا وَبِرُّ الْوَالِدَيْنِ ثُمَّ الْجِهَادُ فِي سَبِيلِ اللَّهِ","id":"Telah menceritakan kepadaku [Sulaiman] telah menceritakan kepada kami [Syu'bah] dari [Al Walid] (dalam jalur lain disebutkan) telah menceritakan kepadaku [Abbad bin Ya'qub Al Asadi] telah mengabarkan kepada kami [Abbad bin Al 'Awwam] dari [Asy Syaibani] dari [Al Walid bin 'Aizar] dari [Abu 'Amru dan Asy Syaibani] dari [Ibn Mas'ud] radliallahu 'anhu, bahwa seorang laki-laki pernah bertanya Nabi shallallahu 'alaihi wasallam, amalan apa yang paling utama? ' Nabi menjawab: \"Shalat tepat pada waktunya, berbakti kepada kedua orang tua, dan jihad fi sabilillah.\""},"6611":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ الْحَسَنِ حَدَّثَنَا عَمْرُو بْنُ تَغْلِبَ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَالٌ فَأَعْطَى قَوْمًا وَمَنَعَ آخَرِينَ فَبَلَغَهُ أَنَّهُمْ عَتَبُوا فَقَالَ إِنِّي أُعْطِي الرَّجُلَ وَأَدَعُ الرَّجُلَ وَالَّذِي أَدَعُ أَحَبُّ إِلَيَّ مِنْ الَّذِي أُعْطِي أُعْطِي أَقْوَامًا لِمَا فِي قُلُوبِهِمْ مِنْ الْجَزَعِ وَالْهَلَعِ وَأَكِلُ أَقْوَامًا إِلَى مَا جَعَلَ اللَّهُ فِي قُلُوبِهِمْ مِنْ الْغِنَى وَالْخَيْرِ مِنْهُمْ عَمْرُو بْنُ تَغْلِبَ فَقَالَ عَمْرٌو مَا أُحِبُّ أَنَّ لِي بِكَلِمَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُمْرَ النَّعَمِ","id":"Telah menceritakan kepada kami [Abu Nu'man] telah menceritakan kepada kami [Jarir bin Hazim] dari [Al Hasan] telah menceritakan kepada kami ['Amru bin Taghlib] berkata, \"Nabi shallallahu 'alaihi wasallam diberi sebuah harta, lantas beliau berikan kepada sebagian sahabatnya dan tidak beliau berikan kepada sahabat yang lain. Kemudian sampailah berita kepada beliau bahwa orang-orang mencela sikap beliau, maka antas beliau pun bersabda: \"Sungguh, ada orang yang kuberi dan ada yang tidak kuberi, namun yang tidak aku beri lebih aku sukai daripada yang aku beri, beberapa orang aku beri karena hati mereka masih ada keluh kesah dan ketakutan, dan beberapa orang aku percayakan kepada kecukupan dan kebaikan yang telah Allah jadikan pada hati mereka, diantara mereka ialah Amru bin Taghlib.\" Lantas 'Amru berkata, 'Aku tak ingin lagi unta-unta merah setelah mengetahui kalimat Rasulullah shallallahu 'alaihi wasallam itu.'"},"6612":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ حَدَّثَنَا أَبُو زَيْدٍ سَعِيدُ بْنُ الرَّبِيعِ الْهَرَوِيُّ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْوِيهِ عَنْ رَبِّهِ قَالَ إِذَا تَقَرَّبَ الْعَبْدُ إِلَيَّ شِبْرًا تَقَرَّبْتُ إِلَيْهِ ذِرَاعًا وَإِذَا تَقَرَّبَ مِنِّي ذِرَاعًا تَقَرَّبْتُ مِنْهُ بَاعًا وَإِذَا أَتَانِي مَشْيًا أَتَيْتُهُ هَرْوَلَةً","id":"Telah menceritakan kepadaku [Muhammad bin Abdurrahim] telah menceritakan kepada kami [Abu Zaid Said bin Rabi' Al Harawi] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] radliyallahu'anhu, dari Nabi shallallahu 'alaihi wasallam yang beliau riwayatkan dari Rabbnya (hadis qudsi), Allah berfirman: \"Jika seorang hamba mendekatkan diri kepada-Ku sejengkal, maka Aku akan mendekat kepadanya sehasta, jika ia mendekatkan diri kepada-Ku sehasta maka Aku mendekat kepadanya sedepa, dan jika ia mendekatkan diri kepada-Ku dengan berjalan maka Aku akan mendatanginya dengan berlari.\""},"6613":{"ar":"حَدَّثَنَا مُسَدَّدٌ عَنْ يَحْيَى عَنْ التَّيْمِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أَبِي هُرَيْرَةَ قَالَرُبَّمَا ذَكَرَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا تَقَرَّبَ الْعَبْدُ مِنِّي شِبْرًا تَقَرَّبْتُ مِنْهُ ذِرَاعًا وَإِذَا تَقَرَّبَ مِنِّي ذِرَاعًا تَقَرَّبْتُ مِنْهُ بَاعًا أَوْ بُوعًاوَقَالَ مُعْتَمِرٌ سَمِعْتُ أَبِي سَمِعْتُ أَنَسًا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْوِيهِ عَنْ رَبِّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Musaddad] dari [Yahya] dari [At Taimi] dari [Anas bin Malik] dari [Abu Hurairah] mengatakan, \"Adakalanya Nabi shallallahu 'alaihi wasallam bersabda mengingatkan hadis qudsi: \"Jika seorang hamba mendekatkan diri kepada-Ku sejengkal maka Aku akan mendekatkan kepadanya sehasta, jika ia mendekatkan diri kepada-Ku sehasta maka Aku akan mendekatkan diri kepadanya sedepa.\" [Mu'tamir] berkata, \"Aku mendengar [Ayahku] aku mendengar [Anas] dari Nabi shallallahu 'alaihi wasallam, yang beliau meriwayatkannya dari Tuhannya Azza wa Jalla.\""},"6614":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مُحَمَّدُ بْنُ زِيَادٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْوِيهِ عَنْ رَبِّكُمْ قَالَ لِكُلِّ عَمَلٍ كَفَّارَةٌ وَالصَّوْمُ لِي وَأَنَا أَجْزِي بِهِ وَلَخُلُوفُ فَمِ الصَّائِمِ أَطْيَبُ عِنْدَ اللَّهِ مِنْ رِيحِ الْمِسْكِ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Muhammad bin Ziyad] berkata, aku mendengar [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, yang beliau riwayatkan dari Rabb kalian: \"Setiap amalan adalah kaffarat dosa, sedang puasa adalah bagi-Ku dan Aku lah yang akan memberinya pahala. Sungguh, bau mulut orang yang berpuasa jauh lebih wangi di sisi Allah daripada minyak kesturi.\""},"6615":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ ح و قَالَ لِي خَلِيفَةُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ سَعِيدٍ عَن�� قَتَادَةَ عَنْ أَبِي الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا يَرْوِيهِ عَنْ رَبِّهِ قَالَ لَا يَنْبَغِي لِعَبْدٍ أَنْ يَقُولَ إِنَّهُ خَيْرٌ مِنْ يُونُسَ بْنِ مَتَّى وَنَسَبَهُ إِلَى أَبِيهِ","id":"Telah menceritakan kepada kami [Hafs bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Qatadah]. (dalam jalur lain disebutkan) [Khalifah] berkata kepada kami; telah menceritakan kepada kami [Yazid bin Zurai'] dari [Sa'id] dari [Qatadah] dari [Abu 'Aliyah] dari [Ibn 'Abbas] radliyallahu'anhuma, dari Nabi shallallahu 'alaihi wasallam yang beliau riwayatkan dari Rabbnya, Allah berfirman: \"Tak pantas seorang hamba berkata bahwa dirinya lebih baik daripada Yunus bin Mata dan ia nisbatkan dirinya kepada ayahnya.\""},"6616":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي سُرَيْجٍ أَخْبَرَنَا شَبَابَةُ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ الْمُزَنِيِّ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفَتْحِ عَلَى نَاقَةٍ لَهُ يَقْرَأُ سُورَةَ الْفَتْحِ أَوْ مِنْ سُورَةِ الْفَتْحِ قَالَ فَرَجَّعَ فِيهَا قَالَ ثُمَّ قَرَأَ مُعَاوِيَةُ يَحْكِي قِرَاءَةَ ابْنِ مُغَفَّلٍ وَقَالَ لَوْلَا أَنْ يَجْتَمِعَ النَّاسُ عَلَيْكُمْ لَرَجَّعْتُ كَمَا رَجَّعَ ابْنُ مُغَفَّلٍ يَحْكِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لِمُعَاوِيَةَ كَيْفَ كَانَ تَرْجِيعُهُ قَالَ آ آ آ ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Ahmad bin Abu Suraij] telah mengabarkan kepada kami [Syababah] telah menceritakan kepada kami [Syu'bah] dari [Mu'awiyah bin Qurrah] dari ['Abdullah bin Mughaffal Al Muzanni] berkata, \"Pernah aku melihat Rasulullah shallallahu 'alaihi wasallam pada hari pembebasan Makkah di atas untanya membaca surat al Fath, atau sebagian dari surat al Fath.\" Abdullah bin Mughaffal berkata, \"Lantas beliau mengulang-ulang suaranya dan mengeraskannya.\" Kemudian Mu'awiyah membaca dengan menirukan bacaan Abdullah bin Mughaffal seraya berkata, \"Kalaulah manusia tidak berkumpul kepada kalian, niscaya aku mengulang-ulang bacaan dan mengeraskannya sebagaimana Ibnu Mughaffal mengulang-ulang dan mengeraskan bacaan ketika menirukan nabi shallallahu 'alaihi wasallam.\" Maka aku katakana kepada Mu'awiyah, \"Bagaimana beliau mengulang-ulang dan mengeraskan bacaannya?\" Mu'awiyah menjawab, \"Dengan mengucapkan AAA (dengan bacaan panjang enam harakat), AAA (dengan bacaan panjang enam harakat), AAA (dengan bacaan panjang enam harakat), beliau ucapkan tiga kali.\""},"6617":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ أَهْلُ الْكِتَابِ يَقْرَءُونَ التَّوْرَاةَ بِالْعِبْرَانِيَّةِ وَيُفَسِّرُونَهَا بِالْعَرَبِيَّةِ لِأَهْلِ الْإِسْلَامِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُصَدِّقُوا أَهْلَ الْكِتَابِ وَلَا تُكَذِّبُوهُمْ وَقُولُوا{ آمَنَّا بِاللَّهِ وَمَا أُنْزِلَ }الْآيَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Ali bin Mubarak] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah] berkata, \"Ahli kitab membaca Taurat dengan bahasa Ibrani, dan mereka menafsirkannya dengan bahasa arab untuk pemeluk Islam.\" Spontan Rasulullah Sallallahu'alaihiwasallam bersabda: \"Jangan kalian membenarkan ahli kitab dan jangan pula mendustakan mereka, katakan saja: 'Kami beriman kepada Allah dan apa yang diturunkan'.\""},"6618":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَاعِيلُ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَجُلٍ وَامْرَأَةٍ مِنْ الْيَهُودِ قَدْ زَنَيَا فَقَالَ لِلْيَهُودِ مَا تَصْنَعُونَ بِهِمَا قَالُوا نُسَخِّمُ وُجُوهَهُمَا وَنُخْزِيهِمَا قَالَ{ فَأْتُوا بِالتَّوْرَاةِ فَاتْلُوهَا إِنْ كُنْتُمْ صَادِقِينَ }فَجَاءُوا فَقَالُوا لِرَجُلٍ مِمَّنْ يَرْضَوْنَ يَا أَعْوَرُ اقْرَأْ فَقَرَأَ حَتَّى انْتَهَى إِلَى مَوْضِعٍ مِنْهَا فَوَضَعَ يَدَهُ عَلَيْهِ قَالَ ارْفَعْ يَدَكَ فَرَفَعَ يَدَهُ فَإِذَا فِيهِ آيَةُ الرَّجْمِ تَلُوحُ فَقَالَ يَا مُحَمَّدُ إِنَّ عَلَيْهِمَا الرَّجْمَ وَلَكِنَّا نُكَاتِمُهُ بَيْنَنَا فَأَمَرَ بِهِمَا فَرُجِمَا فَرَأَيْتُهُ يُجَانِئُ عَلَيْهَا الْحِجَارَةَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Ismail] dari [Ayyub] dari [Nafi'] dari [Ibn Umar] radliyallahu'anhuma berkata, \"Seorang laki-laki dan wanita Yahudi yang berzina didatangkan kepada nabi shallallahu 'alaihi wasallam, Nabi lalu bertanya kepada si Yahudi: 'Hukuman apa biasa kalian lakukan terhadap keduanya? ' Mereka menjawab, 'Kami biasanya menghukum mereka dengan menghitami wajah keduanya dan menghinakannya.' Lantas nabi bersabda (dengan mengutip ayat): '(Maka datangkanlah Taurat dan bacalah, jika kalian orang-orang yang benar) ', (Qs. Ali 'Imran: 93), lantas mereka datang dan mereka katakan kepada seseorang yang mereka percayai, 'Hai A'war bacalah! Lantas A'war membaca hingga sampai ayat (yang berkenaan hukum perzinaan), dengan terburu-buru ia menutupi dengan tangannya, maka Nabi menegur: 'Hai, angkatlah tanganmu! ' Maka ia angkat tangannya. Dan ternyata yang ia tutupi adalah ayat rajam, lantas A'war berkata, 'Hai Muhammad, kedua orang itu wajib dirajam, hanya kami merahasiakannya di antara kami.' Maka Nabi perintahkan agar keduanya dirajam, dan kemudian keduanya pun dirajam. Sungguh, aku lihat yang laki-laki membungkukkan badannya ke arah wanita untuk mencegahnya agar tidak terkena batu.\""},"6619":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ حَمْزَةَ حَدَّثَنِي ابْنُ أَبِي حَازِمٍ عَنْ يَزِيدَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا أَذِنَ اللَّهُ لِشَيْءٍ مَا أَذِنَ لِنَبِيٍّ حَسَنِ الصَّوْتِ بِالْقُرْآنِ يَجْهَرُ بِهِ","id":"Telah menceritakan kepadaku [Ibrahim bin Hamzah] telah menceritakan kepadaku [Ibn Abu Hazim] dari [Yazid] dari [Muhammad bin Ibrahim] dari [Abu Salamah] dari [Abu Hurairah], bahwa ia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Allah tidak pernah mengijinkan sesuatu sebagaimana ijin-Nya terhadap nabi-Nya untuk memperindah suara Al Qur'an dan menyaringkannya.\""},"6620":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ وَسَعِيدُ بْنُ الْمُسَيَّبِ وَعَلْقَمَةُ بْنُ وَقَّاصٍ وَعُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ عَنْ حَدِيثِ عَائِشَةَحِينَ قَالَ لَهَا أَهْلُ الْإِفْكِ مَا قَالُوا وَكُلٌّ حَدَّثَنِي طَائِفَةً مِنْ الْحَدِيثِ قَالَتْ فَاضْطَجَعْتُ عَلَى فِرَاشِي وَأَنَا حِينَئِذٍ أَعْلَمُ أَنِّي بَرِيئَةٌ وَأَنَّ اللَّهَ يُبَرِّئُنِي وَلَكِنِّي وَاللَّهِ مَا كُنْتُ أَظُنُّ أَنَّ اللَّهَ يُنْزِلُ فِي شَأْنِي وَحْيًا يُتْلَى وَلَشَأْنِي فِي نَفْسِي كَانَ أَحْقَرَ مِنْ أَنْ يَتَكَلَّمَ اللَّهُ فِيَّ بِأَمْرٍ يُتْلَى وَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ إِنَّ الَّذِينَ جَاءُوا بِالْإِفْكِ عُصْبَةٌ مِنْكُمْ }الْعَشْرَ الْآيَاتِ كُلَّهَا","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Yunus] dari [Ibn Syihab] telah mengabarkan kepadaku ['Urwah bin Zubair] dan [Sa'id bin Musayyab] dan [Alqamah bin waqqash] dan ['Ubaidullah bin Abdullah] dari hadis ['Aisyah] ketika penyebar berita bohong mengisukan ia selingkuh, dan masing-masing menceritakan kepadaku sejumlah hadis. 'Aisyah berkata, \"Aku berbaring di atas kasurku, dan ketika itu aku tahu bahwa aku bersih (dari tuduhan selingkuh), Allah telah membersihkan tuduhan tersebut. Namun demi Allah, aku tak punya prasangka jika Allah hingga menurunkan wahyu yang selalu dibaca tentang masalahku, padahal masalahku terhadap diriku lebih remeh daripada Allah berfirman tentangku dengan ayat yang selalu dibaca. Allah lalu menurunkan ayat: '(Sesungguhnya orang-orang yang membawa berita bohong adalah dari kalian sendiri) ', (Qs. An Nuur: 11-21)."},"6621":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا مِسْعَرٌ عَنْ عَدِيِّ بْنِ ثَابِتٍ أُرَاهُ قَالَ سَمِعْتُ الْبَرَاءَ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْعِشَاءِ{ وَالتِّينِ وَالزَّيْتُونِ }فَمَا سَمِعْتُ أَحَدًا أَحْسَنَ صَوْتًا أَوْ قِرَاءَةً مِنْهُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Mis'ar] dari ['Adi bin Tsabit] seingatku Ia berkata, \"Pernah aku mendengar [Al Bara'] berkata; saya pernah mendengar Nabi shallallahu 'alaihi wasallam saat shalat Isya membaca 'WATTIINI WAZZAITUUNA (surat At Tiin) '. Dan belum pernah kudengar seorang pun yang lebih indah suaranya, atau bacaannya daripada beliau.\""},"6622":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هُشَيْمٌ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَوَارِيًا بِمَكَّةَ وَكَانَ يَرْفَعُ صَوْتَهُ فَإِذَا سَمِعَ الْمُشْرِكُونَ سَبُّوا الْقُرْآنَ وَمَنْ جَاءَ بِهِ فَقَالَ اللَّهُ عَزَّ وَجَلَّ لِنَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Husyaim] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibn 'Abbas] radliyallahu'anhuma, ia berkata, \"Nabi Shallalahu'alaihiwasllam sembunyi-sembunyi di Makkah, namun beliau mengeraskan suara bacaan, saat orang-orang musyrik mendengar (suara bacaan beliau), mereka mencaci Al Qur'an dan orang yang membawanya. Maka Allah Azza wa Jalla pun menurunkan ayat kepada nabi-Nya: '(Dan janganlah engkau menyaringkan bacaan shalatmu dan jangan pula melirihkannya) ', (Qs. Al Isra': 110)."},"6623":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ عَنْ أَبِيهِ أَنَّهُ أَخْبَرَهُ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ رَضِيَ اللَّهُ عَنْهُ قَالَ لَهُإِنِّي أَرَاكَ تُحِبُّ الْغَنَمَ وَالْبَادِيَةَ فَإِذَا كُنْتَ فِي غَنَمِكَ أَوْ بَادِيَتِكَ فَأَذَّنْتَ لِلصَّلَاةِ فَارْفَعْ صَوْتَكَ بِالنِّدَاءِ فَإِنَّهُ لَا يَسْمَعُ مَدَى صَوْتِ الْمُؤَذِّنِ جِنٌّ وَلَا إِنْسٌ وَلَا شَيْءٌ إِلَّا شَهِدَ لَهُ يَوْمَ الْقِيَامَةِ قَالَ أَبُو سَعِيدٍ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ismail] telah menceritakan kepadaku [Malik] dari ['Abdurrahman bin Abdullah bin Abdurrahman bin Abu Sha'sha'ah] dari [ayahnya] bahwa ia mengabarkan kepadanya, bahwa [Abu Sa'id Al Khudzri] radliyallahu'anhu berkata kepadanya, \"Aku lihat kamu hobi menggembala kambing dan alam pedusunan, jika engkau berada di tengah-tengah kambing gembalaanmu, lalu engkau mengumandangkan adzan (shalat), maka keraskanlah suaramu. Sebab tidaklah jin, manusia, atau sesuatu yang mendengar suara mu`adzin kecuali mereka akan menjadi saksi baginya pada hari kiamat.\" Abu Sa'id berkata, \"Aku mendengarnya dari Rasulullah shallallahu 'alaihi wasallam.\""},"6624":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ أُمِّهِ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ الْقُرْآنَ وَرَأْسُهُ فِي حَجْرِي وَأَنَا حَائِضٌ","id":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Ibunya] dari ['Aisyah] berkata, \"Pernah Nabi shallallahu 'alaihi wasallam membaca Al Qur'an sedang kepalanya di pahaku, padahal aku sedang dalam keadaan haid.\""},"6625":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي عُرْوَةُ أَنَّ الْمِسْوَرَ بْنَ مَخْرَمَةَ وَعَبْدَ الرَّحْمَنِ بْنَ عَبْدٍ الْقَارِيَّ حَدَّثَاهُ أَنَّهُمَا سَمِعَا عُمَرَ بْنَ الْخَطَّابِ يَقُولُسَمِعْتُ هِشَامَ بْنَ حَكِيمٍ يَقْرَأُ سُورَةَ الْفُرْقَانِ فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَمَعْتُ لِقِرَاءَتِهِ فَإِذَا هُوَ يَقْرَأُ عَلَى حُرُوفٍ كَثِيرَةٍ لَمْ يُقْرِئْنِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكِدْتُ أُسَاوِرُهُ فِي الصَّلَاةِ فَتَصَبَّرْتُ حَتَّى سَلَّمَ فَلَبَبْتُهُ بِرِدَائِهِ فَقُلْتُ مَنْ أَقْرَأَكَ هَذِهِ السُّورَةَ الَّتِي سَمِعْتُكَ تَقْرَأُ قَالَ أَقْرَأَنِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ كَذَبْتَ أَقْرَأَنِيهَا عَلَى غَيْرِ مَا قَرَأْتَ فَانْطَلَقْتُ بِهِ أَقُودُهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنِّي سَمِعْتُ هَذَا يَقْرَأُ سُورَةَ الْفُرْقَانِ عَلَى حُرُوفٍ لَمْ تُقْرِئْنِيهَا فَقَالَ أَرْسِلْهُ اقْرَأْ يَا هِشَامُ فَقَرَأَ الْقِرَاءَةَ الَّتِي سَمِعْتُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَذَلِكَ أُنْزِلَتْ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ يَا عُمَرُ فَقَرَأْتُ الَّتِي أَقْرَأَنِي فَقَالَ كَذَلِكَ أُنْزِلَتْ إِنَّ هَذَا الْقُرْآنَ أُنْزِلَ عَلَى سَبْعَةِ أَحْرُفٍ فَاقْرَءُوا مَا تَيَسَّرَ مِنْهُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibn Syihab] telah menceritakan kepadaku ['Urwah] bahwa [Miswar bin Makhramah] dan [Abdurrahman bin Abdul Qari] keduanya menceritakan kepadanya, bahwa ia mendengar [Umar bin Khattab] berkata, \"Aku mendengar Hisyam bin Hakim membaca surat al Furqaan semasa Rasulullah shallallahu 'alaihi wasallam masih hidup, dan aku menikmati bacaannya. Ternyata dia membaca dengan dialek yang berbeda-beda yang Rasulullah shallallahu 'alaihi wasallam belum pernah membacakannya kepadaku sehingga hampir saja aku menarik kepalanya ketika shalat. Namun aku berusaha menahan kesabaranku hingga ia mengucapkan salam, lantas aku mengikatnya dengan pakaiannya dan aku tanyakan, 'Siapa yang mula-mula membacakan surat Al Qur'an kepadamu yang aku dengar engkau membacanya? ' Ia menjawab, 'Rasulullah shallallahu 'alaihi wasallam yang membacakannya kepadaku! Aku lalu berkata, 'Engkau dusta, sebab rasul membacakan kepadaku tidak seperti yang engkau baca.' Maka aku bawa Hisyam bin hakim kepada Rasulullah shallallahu 'alaihi wasallam dan aku laporkan, 'Aku telah mendengar orang ini membaca surat Al Qur'an tidak dengan dialek seperti yang engkau bacakan kepadaku.' Kemudian Rasulullah berkata: 'Lepaskan dia, bacalah ya Hisyam! ' Lantas Hisyam membaca bacaan yang sebelumnya aku mendengarnya, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: 'Begitulah surat itu diturunkan! ' Lantas Rasulullah shallallahu 'alaihi wasallam bersabda: 'Bacalah wahai Umar! ' Aku pun membaca sebagaimana yang beliau bacakan kepadaku, dan beliau juga berkomentar 'Begitulah surat Al Qur'an diturunkan, sesungguhnya surat Al Qur'an ini diturunkan dengan tujuh dialek, maka bacalah apa yang mudah bagimu'.\""},"6626":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ يَزِيدُ حَدَّثَنِي مُطَرِّفُ بْنُ عَبْدِ اللَّهِ عَنْ عِمْرَانَ قَالَقُلْتُ يَا رَسُولَ اللَّهِ فِيمَا يَعْمَلُ الْعَامِلُونَ قَالَ كُلٌّ مُيَسَّرٌ لِمَا خُلِقَ لَهُ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami [Abdul Warits], [Yazid] berkata; telah menceritakan kepadaku [Mutharrif bin Abdullah] dari [Imran] ia berkata, \"Aku bertanya, 'Lalu untuk apa orang-orang beramal? ' Beliau menjawab: 'Setiap orang akan dimudahkan (menuju jalan) penciptaannya'.\""},"6627":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ وَالْأَعْمَشِ سَمِعَا سَعْدَ بْنَ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ فِي جَنَازَةٍ فَأَخَذَ عُودًا فَجَعَلَ يَنْكُتُ فِي الْأَرْضِ فَقَالَ مَا مِنْكُمْ مِنْ أَحَدٍ إِلَّا كُتِبَ مَقْعَدُهُ مِنْ النَّارِ أَوْ مِنْ الْجَنَّةِ قَالُوا أَلَا نَتَّكِلُ قَالَ اعْمَلُوا فَكُلٌّ مُيَسَّرٌ{ فَأَمَّا مَنْ أَعْطَى وَاتَّقَى }الْآيَةَ","id":"Telah menceritakan kepadaku [Muhammad bin Basyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Manshur] dan [Al A'masy] keduanya mendengar [Sa'd bin Ubaidah] dari [Abu Abdurrahman] dari [Ali] radliyallahu'anhu, dari Nabi shallallahu 'alaihi wasallam, bahwa suatu kali beliau menghadiri jenazah, kemudian beliau ambil dahan dan beliau pukulkan ke tanah secara ringan sambil beliau sabdakan: 'Tidaklah salah seorang di antara kalian melainkan telah ditetapkan tempat tinggalnya di neraka atau di surga.' Para sahabat bertanya, 'Kalau begitu, tidak sebaiknyakah kita bertawakkal saja? ' Nabi menjawab: 'Beramallah kalian, sebab masing-masing telah dimudahkan, dan beliau mengutip ayat: '(Adapun orang yang memberi hartanya dan bertakwa) ', (Qs. Al Lail: 5)."},"6628":{"ar":"و قَالَ لِي خَلِيفَةُ بْنُ خَيَّاطٍ حَدَّثَنَا مُعْتَمِرٌ سَمِعْتُ أَبِي عَنْ قَتَادَةَ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَمَّا قَضَى اللَّهُ الْخَلْقَ كَتَبَ كِتَابًا عِنْدَهُ غَلَبَتْ أَوْ قَالَ سَبَقَتْ رَحْمَتِي غَضَبِي فَهُوَ عِنْدَهُ فَوْقَ الْعَرْشِ","id":"[Khalifah bin Khayyath] berkata kepadaku, telah menceritakan kepada kami [Mu'tamir] aku mendengar [Ayahku] dari [Qatadah] dari [Abu Rafi'] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Dikala Allah menetapkan penciptaan, Dia menulis catatan di sisi-Nya 'Rahmat-Ku lebih mendominasi, atau beliau mengatakan, 'lebih mendahului kemurkaan-Ku, dan itu terjadi di atas 'arsy.\""},"6629":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي غَالِبٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا مُعْتَمِرٌ سَمِعْتُ أَبِي يَقُولُ حَدَّثَنَا قَتَادَةُ أَنَّ أَبَا رَافِعٍ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ كَتَبَ كِتَابًا قَبْلَ أَنْ يَخْلُقَ الْخَلْقَ إِنَّ رَحْمَتِي سَبَقَتْ غَضَبِي فَهُوَ مَكْتُوبٌ عِنْدَهُ فَوْقَ الْعَرْشِ","id":"Telah menceritakan kepadaku [Muhammad bin Abu Ghalib] telah menceritakan kepada kami [Muhammad bin Ismail] telah menceritakan kepada kami [Mu'tamir] aku mendengar [ayahku] berkata, telah menceritakan kepada kami [Qatadah] bahwa [Abu Rafi'] menceritakan kepadanya, ia mendengar [Abu Hurairah] radliyallahu'anhu berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah menetapkan satu ketetapan sebelum mencipta penciptaan 'rahmat-Ku lebih mendahului kemurkaan-Ku, dan itu tercatat di sisi-Nya di atas 'arsy.\""},"6630":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ وَالْقَاسِمِ التَّمِيمِيِّ عَنْ زَهْدَمٍ قَالَكَانَ بَيْنَ هَذَا الْحَيِّ مِنْ جُرْمٍ وَبَيْنَ الْأَشْعَرِيِّينَ وُدٌّ وَإِخَاءٌ فَكُنَّا عِنْدَ أَبِي مُوسَى الْأَشْعَرِيِّ فَقُرِّبَ إِلَيْهِ الطَّعَامُ فِيهِ لَحْمُ دَجَاجٍ وَعِنْدَهُ رَجُلٌ مِنْ بَنِي تَيْمِ اللَّهِ كَأَنَّهُ مِنْ الْمَوَالِي فَدَعَاهُ إِلَيْهِ فَقَالَ إِنِّي رَأَيْتُهُ يَأْكُلُ شَيْئًا فَقَذِرْتُهُ فَحَلَفْتُ لَا آكُلُهُ فَقَالَ هَلُمَّ فَلْأُحَدِّثْكَ عَنْ ذَاكَ إِنِّي أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَفَرٍ مِنْ الْأَشْعَرِيِّينَ نَسْتَحْمِلُهُ قَالَ وَاللَّهِ لَا أَحْمِلُكُمْ وَمَا عِنْدِي مَا أَحْمِلُكُمْ فَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَهْبِ إِبِلٍ فَسَأَلَ عَنَّا فَقَالَ أَيْنَ النَّفَرُ الْأَشْعَرِيُّونَ فَأَمَرَ لَنَا بِخَمْسِ ذَوْدٍ غُرِّ الذُّرَى ثُمَّ انْط��لَقْنَا قُلْنَا مَا صَنَعْنَا حَلَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا يَحْمِلَنَا وَمَا عِنْدَهُ مَا يَحْمِلُنَا ثُمَّ حَمَلَنَا تَغَفَّلْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمِينَهُ وَاللَّهِ لَا نُفْلِحُ أَبَدًا فَرَجَعْنَا إِلَيْهِ فَقُلْنَا لَهُ فَقَالَ لَسْتُ أَنَا أَحْمِلُكُمْ وَلَكِنَّ اللَّهَ حَمَلَكُمْ وَإِنِّي وَاللَّهِ لَا أَحْلِفُ عَلَى يَمِينٍ فَأَرَى غَيْرَهَا خَيْرًا مِنْهَا إِلَّا أَتَيْتُ الَّذِي هُوَ خَيْرٌ مِنْهُ وَتَحَلَّلْتُهَا","id":"Telah menceritakan kepada kami [Abdullah bin Abdul Wahhab] telah menceritakan kepada kami ['Abdul Wahhab] telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah], dan [Al Qasim At Tamimi] dari [Zahdam] ia berkata, \"Antara penduduk Jurum dan orang-orang Asy'ari terdapat kecintaan dan persaudaraan. Ketika itu kami berada bersama [Abu Musa] Al Asy'ari, lantas seporsi hidangan didekatkan kepadanya yang di antaranya ada daging ayam. Sementara di sisi Abu Musa ada seorang laki-laki dari bani Taimullah - seorang mawali (bangsa non arab) -. Abu Musa pun mengundangnya.\" Zahdam berkata, \"Kulihat laki-laki dari bani Taimullah itu menyantap makanan yang kuanggap jijik sehingga saya bersumpah untuk tidak memakannya. Maka Abu Musa berkata, 'Hei, datanglah kemari, saya akan sampaikan kepada kalian sebuah hadits kepadamu! Sungguh akan saya ceritakan kepadamu tentang sumpahmu itu. Dahulu aku menemui nabi shallallahu 'alaihi wasallam bersama beberapa orang Asy'ari dengan harapan beliau bisa mengangkut kami dengan kendaraan, namun beliau bersumpah: 'Demi Allah, saya tidak akan mengangkut kalian, dan memang saya tidak punya kendaraan untuk mengangkut kalian.' Ternyata nabi kemudian memperoleh rampasan unta dan menanyakan kami dengan berujar: 'Mana orang-orang Asy'ari tadi? ' Beliau perintahkan agar kami diberi sekitar lima dzaud (satu dzaud antara tiga hingga sepuluh) unta yang putih punggungnya, kemudian kami pun berangkat. Dalam keberangkatan, kami berkata, 'Heih…apa yang kita perbuat ini? Kita telah tahu bahwa Rasulullah shallallahu 'alaihi wasallam telah bersumpah untuk tidak mengangkut kita yang ketika itu beliau tidak mempunyai kendaraan untuk mengangkut kita, namun sekarang beliau menyediakan kendaraan untuk kita. Rupanya Rasulullah shallallahu 'alaihi wasallam lalai terhadap sumpahnya atas kita, demi Allah, kalau demikian, kita tak bakalan aman! Kami pun pulang dan kami temui beliau dan kami utarakan uneg-uneg kami. Beliau lalu bersabda: 'Bukan saya yang menyediakan kendaraan untuk kalian, namun Allah sematalah yang menyediakan kendaraan untuk mengangkut kalian. Demi Allah, tidaklah saya bersumpah kemudian aku melihat yang lebih baik dari sumpah tersebut, kecuali aku akan melakukan yang lebih baik dan kubayar kaffarat sumpahku'.\""},"6631":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ حَدَّثَنَا أَبُو جَمْرَةَ الضُّبَعِيُّ قُلْتُ لِابْنِ عَبَّاسٍ فَقَالَقَدِمَ وَفْدُ عَبْدِ الْقَيْسِ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا إِنَّ بَيْنَنَا وَبَيْنَكَ الْمُشْرِكِينَ مِنْ مُضَرَ وَإِنَّا لَا نَصِلُ إِلَيْكَ إِلَّا فِي أَشْهُرٍ حُرُمٍ فَمُرْنَا بِجُمَلٍ مِنْ الْأَمْرِ إِنْ عَمِلْنَا بِهِ دَخَلْنَا الْجَنَّةَ وَنَدْعُو إِلَيْهَا مَنْ وَرَاءَنَا قَالَ آمُرُكُمْ بِأَرْبَعٍ وَأَنْهَاكُمْ عَنْ أَرْبَعٍ آمُرُكُمْ بِالْإِيمَانِ بِاللَّهِ وَهَلْ تَدْرُونَ مَا الْإِيمَانُ بِاللَّهِ شَهَادَةُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَإِقَامُ الصَّلَاةِ وَإِيتَاءُ الزَّكَاةِ وَتُعْطُوا مِنْ الْمَغْنَمِ الْخُمُسَ وَأَنْهَاكُمْ عَنْ أَرْبَعٍ لَا تَشْرَبُوا فِي الدُّبَّاءِ وَالنَّقِيرِ وَالظُّرُوفِ الْمُزَفَّتَةِ وَالْحَنْتَمَةِ","id":"Telah menceritakan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Abu 'Ashim] telah menceritakan kepada kami [Qurrah bin Khalid] telah menceritakan kepada kami [Abu Jamrah Adl Dluba'i] saya mengajukan suatu pertanyaan kepada [Ibn Abbas] lalu ia berkata, \"Pernah serombongan utusan Abdul Qais menemui Rasulullah shallallahu 'alaihi wasallam dan berujar, 'Antara kami dan engkau ada orang-orang musyrik dari Mudlar, dan kami tidak bisa menjalin hubungan denganmu selain di bulan-bulan haram, maka perintahkanlah kami dengan hal-hal yang penting saja yang sekiranya kami lakukan maka kami masuk surga, dan kami bisa mengajak generasi kami kepadanya.\" Nabi menjawab: \"Aku perintahkan kalian empat hal dan aku larang kalian empat hal. Aku perintahkan kalian untuk beriman kepada Allah, tahukah kalian keimanan kepada Allah? Yaitu persaksian bahwa tiada sesembahan yang hak selain Allah, mendirikan shalat, membayar zakat, dan kalian berikan seperlima bagian ghanimah. Dan aku larang kalian empat hal, agar kalian tidak meminum dalam ad-Dubba', an-Naqir, azh-Zhuruf al-Muzaffat, dan al-Hantamah.\" "},"6632":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَصْحَابَ هَذِهِ الصُّوَرِ يُعَذَّبُونَ يَوْمَ الْقِيَامَةِ وَيُقَالُ لَهُمْ أَحْيُوا مَا خَلَقْتُمْ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Al Qasim bin Muhammad] dari ['Aisyah] radliyallahu'anhuma, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Para pembuat gambar disiksa dihari kiamat dan dikatakan, 'Cobalah hidupkan semua yang kalian cipta'.\""},"6633":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَصْحَابَ هَذِهِ الصُّوَرِ يُعَذَّبُونَ يَوْمَ الْقِيَامَةِ وَيُقَالُ لَهُمْ أَحْيُوا مَا خَلَقْتُمْ","id":"Telah menceritakan kepada kami [Abu Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Ibn Umar] radliyallahu'anhuma, ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Para pembuat gambar ini disiksa pada hari kiamat, lalu dikatakan, 'Cobalah hidupkan semua yang kalian cipta'.\""},"6634":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ عُمَارَةَ عَنْ أَبِي زُرْعَةَ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُقَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَالَ اللَّهُ عَزَّ وَجَلَّ وَمَنْ أَظْلَمُ مِمَّنْ ذَهَبَ يَخْلُقُ كَخَلْقِي فَلْيَخْلُقُوا ذَرَّةً أَوْ لِيَخْلُقُوا حَبَّةً أَوْ شَعِيرَةً","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala'] telah menceritakan kepada kami [Ibn Fudlail] dari ['Umarah] dari [Abu Zur'ah] ia mendengar [Abu Hurairah] radliyallahu'anhu berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Allah 'azza wajalla berfirman, 'Siapa yang lebih zhalim daripada orang yang mencipta seperti ciptaan-Ku, hendaklah ia cipta biji sawi, atau biji tepung, atau biji gandum!\""},"6635":{"ar":"حَدَّثَنَا هُدْبَةُ بْنُ خَالِدٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا أَنَسٌ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلُ الْمُؤْمِنِ الَّذِي يَقْرَأُ الْقُرْآنَ كَالْأُتْرُجَّةِ طَعْمُهَا طَيِّبٌ وَرِيحُهَا طَيِّبٌ وَمَثَلُ الَّذِي لَا يَقْرَأُ كَالتَّمْرَةِ طَعْمُهَا طَيِّبٌ وَلَا رِيحَ لَهَا وَمَثَلُ الْفَاجِرِ الَّذِي يَقْرَأُ الْقُرْآنَ كَمَثَلِ الرَّيْحَانَةِ رِيحُهَا طَيِّبٌ وَطَعْمُهَا مُرٌّ وَمَثَلُ الْفَاجِرِ الَّذِي لَا يَقْرَأُ الْقُرْآنَ كَمَثَلِ الْحَنْظَلَةِ طَعْمُهَا مُرٌّ وَلَا رِيحَ لَهَا","id":"Telah menceritakan kepada kami [Hudbah bin Khalid] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] telah menceritakan kepada kami [Anas] dari [Abu Musa] radliyallahu'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Perumpamaan orang mukmin yang membaca Al Qur'an seperti utrujah, rasanya enak dan baunya wangi, dan perumpamaan orang mukmin yang tidak membaca Al Qur'an seperti kurma, rasanya enak namun tidak berbau, dan perumpaman orang durhaka yang membaca Al Qur'an seperti buah raihana, baunya wangi namun rasanya pahit, dan perumpamaan orang durhaka yang tidak membaca Al Qur'an seperti buah hanzhalah, rasanya pahit dan tidak berbau.\""},"6636":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا هِشَامٌ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ ح و حَدَّثَنِي أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَنْبَسَةُ حَدَّثَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي يَحْيَى بْنُ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّهُ سَمِعَ عُرْوَةَ بْنَ الزُّبَيْرِ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهُمَاسَأَلَ أُنَاسٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْكُهَّانِ فَقَالَ إِنَّهُمْ لَيْسُوا بِشَيْءٍ فَقَالُوا يَا رَسُولَ اللَّهِ فَإِنَّهُمْ يُحَدِّثُونَ بِالشَّيْءِ يَكُونُ حَقًّا قَالَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِلْكَ الْكَلِمَةُ مِنْ الْحَقِّ يَخْطَفُهَا الْجِنِّيُّ فَيُقَرْقِرُهَا فِي أُذُنِ وَلِيِّهِ كَقَرْقَرَةِ الدَّجَاجَةِ فَيَخْلِطُونَ فِيهِ أَكْثَرَ مِنْ مِائَةِ كَذْبَةٍ","id":"Telah menceritakan kepada kami [Ali] telah menceritakan kepada kami [Hisyam] Telah mengabarkan kepada kami [Ma'mar] dari [Azzuhri]. (dalam jalur lain disebutkan) telah menceritakan kepadaku [Ahmad bin Shalih] telah menceritakan kepada kami ['Anbasah] telah menceritakan kepada kami [Yunus] dari [Ibn Syihab] telah mengabarkan kepadaku [Yahya bin Urwah bin Zubair] bahwa dia mendengar [Urwah bin Az Zubair], [Aisyah] radliyallahu'anhuma berkata, \"Beberapa orang bertanya Nabi shallallahu 'alaihi wasallam tentang dukun, beliau menjawab: \"Mereka tidak ada apa-apanya.\" Para sahabat berkata lagi, \"Wahai Rasulullah, namun terkadang mereka berbicara sesuatu dan menjadi benar.\" Nabi shallallahu 'alaihi wasallam kemudian berkata: \"Ucapan yang benar itu adalah hasil curian jin, lalu oleh jin diperdengarkan ke telinga wali-walinya sebagaimana ayam betina bersuara, lantas mereka tambahai dengan seratus kebohongan.\""},"6637":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا مَهْدِيُّ بْنُ مَيْمُونٍ سَمِعْتُ مُحَمَّدَ بْنَ سِيرِينَ يُحَدِّثُ عَنْ مَعْبَدِ بْنِ سِيرِينَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَخْرُجُ نَاسٌ مِنْ قِبَلِ الْمَشْرِقِ وَيَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ تَرَاقِيَهُمْ يَمْرُقُونَ مِنْ الدِّينِ كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِ ثُمَّ لَا يَعُودُونَ فِيهِ حَتَّى يَعُودَ السَّهْمُ إِلَى فُوقِهِ قِيلَ مَا سِيمَاهُمْ قَالَ سِيمَاهُمْ التَّحْلِيقُ أَوْ قَالَ التَّسْبِيدُ","id":"Telah menceritakan kepada kami [Abu Nu'man] telah menceritakan kepada kami [Mahdi bin maimun] aku mendengar [Muhammad bin Sirin] menceritakan dari [Ma'bad bin Sirin] dari [Abu Sa'id Al Khudzri] radliyallahu'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Akan muncul beberapa orang dari arah timur, mereka membaca Al Qur'an namun tidak lebih dari kerongkongan mereka (tidak meresap dalam hati), mereka keluar dari agama sebagaimana anak panah keluar dari busur, dan mereka tidak akan kembali hingga anak panah kembali ke tali busur.\" Lalu ditanya, \"Apa tanda mereka?\" Beliau menjawab: \"Ciri mereka adalah gundul.\" Atau, beliau mengatakan: \"Rambutnya dipangkas habis.\""},"6638":{"ar":"حَدَّثَنِي أَحْمَدُ بْنُ إِشْكَابٍ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلِمَتَانِ حَبِيبَتَانِ إِلَى الرَّحْمَنِ خَفِيفَتَانِ عَلَى اللِّسَانِ ثَقِيلَتَانِ فِي الْمِيزَانِ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ سُبْحَانَ اللَّهِ الْعَظِيمِ","id":"Telah menceritakan kepadaku [Ahmad bin Isykab] telah menceritakan kepada kami [Muhammad bin Fudlail] dari ['Umarah bin Alqa'qa'] dari [Abu Zur'ah] dari [Abu Hurairah] radliyallahu'anhu, ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Ada dua kalimat yang disukai Ar Rahman, ringan di lisan dan berat di timbangan, yaitu SUBHANALLAH WABIHAMDIHI dan SUBHAANALLAAHIL'AZHIIM.\""}};
